    def _material_source_rows_from_extended_payload(
        self,
        payload: dict[str, Any],
    ) -> list[dict[str, Any]]:
        original_material_keys: set[tuple[int, str]] = {
            (int(row[1]), str(row[2]))
            for row in payload.get("video_flag_rows") or []
            if int(row[3] or 0) == 1
        }
        anchor_name_by_ad_id = {
            int(row[3]): str(row[7] or "").strip()
            for row in payload.get("detail_rows") or []
            if len(row) > 7 and int(row[3] or 0)
        }
        material_source_rows: list[dict[str, Any]] = []
        for row in payload.get("material_rows") or []:
            advertiser_id = int(row[3])
            ad_id = int(row[5])
            material_id = str(row[9] or "")
            material_source_rows.append(
                {
                    "snapshot_time": row[0],
                    "window_start": row[1],
                    "window_end": row[2],
                    "advertiser_id": advertiser_id,
                    "advertiser_name": row[4],
                    "ad_id": ad_id,
                    "ad_name": row[6],
                    "material_type": row[7],
                    "material_key": row[8],
                    "material_id": material_id,
                    "material_name": row[10],
                    "create_time": row[11],
                    "video_id": row[12],
                    "cover_url": row[13],
                    "aweme_item_id": row[14],
                    "video_url": row[15],
                    "product_show_count": row[16],
                    "product_click_count": row[17],
                    "stat_cost": row[18],
                    "pay_amount": row[19],
                    "total_pay_amount": row[20],
                    "settled_pay_amount": row[21],
                    "order_count": row[22],
                    "settled_order_count": row[23],
                    "top_anchor_name": anchor_name_by_ad_id.get(int(row[5]), ""),
                    "raw_json": row[25],
                    "is_original": (advertiser_id, material_id) in original_material_keys,
                }
            )
        return material_source_rows

    def _normalized_material_source_rows_from_extended_payload(
        self,
        conn: Any,
        customer_center_id: str,
        payload: dict[str, Any],
        *,
        use_current: bool = False,
    ) -> list[dict[str, Any]]:
        material_source_rows = self._material_source_rows_from_extended_payload(payload)
        if not material_source_rows:
            return []
        return self._normalize_material_source_rows_to_plan_metrics(
            conn,
            customer_center_id,
            material_source_rows,
            snapshot_time=str(payload.get("snapshot_time") or ""),
            use_current=use_current,
        )

    def _material_rollup_rows_from_extended_payload(
        self,
        payload: dict[str, Any],
        *,
        material_source_rows: list[dict[str, Any]] | None = None,
    ) -> list[tuple[Any, ...]]:
        if material_source_rows is None:
            material_source_rows = self._material_source_rows_from_extended_payload(payload)
        if not material_source_rows:
            return []
        material_groups = self._group_material_rows(material_source_rows)
        self._apply_material_report_metrics(
            material_groups,
            material_source_rows,
            list(payload.get("material_report_rows") or []),
        )
        return self._build_material_rollup_rows(
            str(payload.get("snapshot_time") or ""),
            str(payload.get("window_start") or ""),
            str(payload.get("window_end") or ""),
            groups=material_groups,
        )

    def _upsert_extended_sync_run_record(
        self,
        conn: Any,
        *,
        customer_center_id: str,
        snapshot_time: str,
        window_start: str,
        window_end: str,
        plan_count: int,
        material_row_count: int,
        original_video_row_count: int = 0,
        error_items: list[dict[str, Any]] | None = None,
    ) -> None:
        errors = list(error_items or [])
        conn.execute(
            """
            INSERT INTO extended_sync_runs (
                snapshot_time, customer_center_id, window_start, window_end, status, plan_count, detail_count,
                product_row_count, material_row_count, original_video_row_count,
                error_count, error_json, created_at, finished_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT (customer_center_id, snapshot_time) DO UPDATE SET
                window_start = excluded.window_start,
                window_end = excluded.window_end,
                status = excluded.status,
                plan_count = excluded.plan_count,
                detail_count = excluded.detail_count,
                product_row_count = excluded.product_row_count,
                material_row_count = excluded.material_row_count,
                original_video_row_count = excluded.original_video_row_count,
                error_count = excluded.error_count,
                error_json = excluded.error_json,
                created_at = excluded.created_at,
                finished_at = excluded.finished_at
            """,
            (
                snapshot_time,
                customer_center_id,
                window_start,
                window_end,
                "ok" if not errors else "partial",
                int(plan_count or 0),
                0,
                0,
                int(material_row_count or 0),
                int(original_video_row_count or 0),
                len(errors),
                self._json_text(errors),
                now_text(),
                now_text(),
            ),
        )

    def cleanup_history(self) -> None:
        now_dt = datetime.now(ZoneInfo(TIMEZONE))
        base_cutoff_dt = now_dt - timedelta(days=RETENTION_DAYS)
        base_cutoff = base_cutoff_dt.strftime("%Y-%m-%d %H:%M:%S")
        base_cutoff_date = base_cutoff_dt.strftime("%Y-%m-%d")
        material_cutoff_date = MATERIAL_HISTORY_START_DATE
        extended_cutoff = f"{material_cutoff_date} 00:00:00"
        with self.db() as conn:
            conn.execute("DELETE FROM summary_snapshots WHERE snapshot_time < ?", (base_cutoff,))
            conn.execute("DELETE FROM account_snapshots WHERE snapshot_time < ?", (base_cutoff,))
            conn.execute("DELETE FROM plan_snapshots WHERE snapshot_time < ?", (base_cutoff,))
            conn.execute("DELETE FROM summary_daily WHERE biz_date < ?", (base_cutoff_date,))
            conn.execute("DELETE FROM account_daily WHERE biz_date < ?", (base_cutoff_date,))
            conn.execute("DELETE FROM plan_daily WHERE biz_date < ?", (base_cutoff_date,))
            conn.execute("DELETE FROM material_daily WHERE biz_date < ?", (material_cutoff_date,))
            conn.execute("DELETE FROM material_relation_daily WHERE biz_date < ?", (material_cutoff_date,))
            conn.execute("DELETE FROM account_balances WHERE snapshot_time < ?", (base_cutoff,))
            conn.execute("DELETE FROM shared_wallets WHERE snapshot_time < ?", (base_cutoff,))
            conn.execute("DELETE FROM shared_wallet_account_relations WHERE snapshot_time < ?", (base_cutoff,))
            conn.execute("DELETE FROM comment_records WHERE comment_date < ?", (base_cutoff_date,))
            conn.execute("DELETE FROM comment_sync_states WHERE sync_date < ?", (base_cutoff_date,))
            conn.execute("DELETE FROM plan_detail_snapshots WHERE snapshot_time < ?", (extended_cutoff,))
            conn.execute("DELETE FROM product_snapshots WHERE snapshot_time < ?", (extended_cutoff,))
            conn.execute("DELETE FROM material_snapshots WHERE snapshot_time < ?", (extended_cutoff,))
            conn.execute("DELETE FROM material_rollups WHERE snapshot_time < ?", (extended_cutoff,))
            conn.execute("DELETE FROM material_report_snapshots WHERE snapshot_time < ?", (extended_cutoff,))
            conn.execute("DELETE FROM video_origin_flags WHERE snapshot_time < ?", (extended_cutoff,))
            conn.execute("DELETE FROM extended_sync_runs WHERE snapshot_time < ?", (extended_cutoff,))
        self._cleanup_material_upload_storage(now_dt - timedelta(days=MATERIAL_UPLOAD_RETENTION_DAYS))

    def evaluate_alerts(self, payload: dict[str, Any]) -> None:
        with self.db() as conn:
            rules = conn.execute(
                """
                SELECT * FROM alert_rules
                WHERE enabled = 1
                ORDER BY id ASC
                """
            ).fetchall()
            if not rules:
                return

            latest_accounts = [item for item in payload["accounts"] if item["ok"]]
            latest_plans = payload["plans"]
            latest_account_balances = payload.get("accountBalances", [])
            latest_wallets = payload.get("sharedWallets", [])
            now_text = payload["snapshot_time"]
            burst_rows = self._build_burst_rows(latest_plans, self._previous_plan_order_map(conn, now_text))

            for rule in rules:
                entity_type = str(rule["entity_type"] or "")
                metric = str(rule["metric"] or "")
                if entity_type == "account":
                    rows = latest_accounts
                    entity_id_field = "advertiser_id"
                    entity_name_field = "advertiser_name"
                elif entity_type in {"plan", "burst_plan"}:
                    rows = burst_rows if entity_type == "burst_plan" else latest_plans
                    entity_id_field = "ad_id"
                    entity_name_field = "ad_name"
                elif entity_type == "account_balance":
                    rows = latest_account_balances
                    entity_id_field = "advertiser_id"
                    entity_name_field = "advertiser_name"
                elif entity_type == "shared_wallet":
                    rows = latest_wallets
                    entity_id_field = "main_wallet_id"
                    entity_name_field = "wallet_name"
                else:
                    continue
                for row in rows:
                    if metric not in row:
                        continue
                    entity_id = str(row[entity_id_field])
                    if rule["target_id"] and rule["target_id"] != entity_id:
                        continue
                    if entity_type in {"account", "plan", "burst_plan"} and float(row["stat_cost"]) < float(rule["min_spend"]):
                        continue
                    current_value = float(row[metric])
                    if not self._compare(current_value, str(rule["operator"]), float(rule["threshold"])):
                        continue
                    recent = conn.execute(
                        """
                        SELECT id FROM alert_events
                        WHERE rule_id = ? AND entity_id = ? AND created_at >= ?
                        ORDER BY created_at DESC LIMIT 1
                        """,
                        (
                            rule["id"],
                            entity_id,
                            (
                                datetime.fromisoformat(now_text)
                                - timedelta(minutes=int(rule["cooldown_minutes"] or ALERT_COOLDOWN_DEFAULT))
                            ).strftime("%Y-%m-%d %H:%M:%S"),
                        ),
                    ).fetchone()
                    if recent:
                        continue
                    entity_name = row[entity_name_field]
                    message = self._build_alert_message(rule, row, now_text)
                    conn.execute(
                        """
                        INSERT INTO alert_events (
                            rule_id, snapshot_time, entity_type, entity_id, entity_name,
                            metric, operator, threshold, current_value, stat_cost, pay_amount,
                            order_count, roi, message, status, created_at
                        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?)
                        """,
                        (
                            rule["id"],
                            payload["snapshot_time"],
                            rule["entity_type"],
                            entity_id,
                            entity_name,
                            rule["metric"],
                            rule["operator"],
                            rule["threshold"],
                            current_value,
                            row.get("stat_cost", 0),
                            row.get("pay_amount", 0),
                            row.get("order_count", 0),
                            row.get("roi", 0),
                            message,
                            now_text,
                        ),
                    )

    @staticmethod
    def _material_curve_metric_value(row: dict[str, Any], field: str) -> float:
        candidates: list[dict[str, Any]] = [row]
        for key in ("fields", "metrics", "stats", "values", "data"):
            nested = row.get(key)
            if isinstance(nested, dict):
                candidates.append(nested)
        for candidate in candidates:
            if field not in candidate:
                continue
            value = candidate.get(field)
            if isinstance(value, dict):
                value = (
                    value.get("Value")
                    or value.get("value")
                    or value.get("ValueStr")
                    or value.get("value_str")
                    or value.get("val")
                )
            try:
                return float(value or 0.0)
            except (TypeError, ValueError):
                continue
        return 0.0

    @staticmethod
    def _material_curve_second_value(row: dict[str, Any]) -> int:
        candidates: list[Any] = [
            row.get("h_sec"),
            row.get("second"),
            row.get("sec"),
            row.get("progress_second"),
            row.get("play_second"),
        ]
        dimensions = row.get("dimensions")
        if isinstance(dimensions, dict):
            candidates.extend(
                [
                    dimensions.get("h_sec"),
                    dimensions.get("second"),
                    dimensions.get("sec"),
                ]
            )
        for value in candidates:
            try:
                second = int(float(value or 0))
            except (TypeError, ValueError):
                continue
            if second >= 0:
                return second
        return -1

    def _normalize_video_user_lose_rows(self, response: dict[str, Any]) -> list[dict[str, float]]:
        data = response.get("data") or {}
        raw_rows: list[Any] = []
        if isinstance(data, list):
            raw_rows = data
        elif isinstance(data, dict):
            for key in ("list", "rows", "items", "stats_list", "series", "result"):
                value = data.get(key)
                if isinstance(value, list):
                    raw_rows = value
                    break
        metric_fields = ("click_cnt", "dy_like", "dy_comment", "dy_follow", "user_lose_cnt")
        grouped: dict[int, dict[str, float]] = {}
        for raw_row in raw_rows:
            if not isinstance(raw_row, dict):
                continue
            second = self._material_curve_second_value(raw_row)
            if second < 0:
                continue
            point = grouped.setdefault(
                second,
                {
                    "second": float(second),
                    **{field: 0.0 for field in metric_fields},
                },
            )
            for field in metric_fields:
                point[field] += self._material_curve_metric_value(raw_row, field)
        return [grouped[key] for key in sorted(grouped)]

    def _material_preview_requested_window(
        self,
        range_key: str,
        start_date: str,
        end_date: str,
        snapshot_time: str,
    ) -> tuple[datetime, datetime, str]:
        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        target_snapshot = str(snapshot_time or "").strip()
        if target_snapshot:
            snapshot_day = _parse_date_input(target_snapshot[:10], "snapshot_time")
            tz = ZoneInfo(tz_name)
            start_dt = datetime(snapshot_day.year, snapshot_day.month, snapshot_day.day, 0, 0, 0, tzinfo=tz)
            end_dt = datetime(snapshot_day.year, snapshot_day.month, snapshot_day.day, 23, 59, 59, tzinfo=tz)
            return start_dt, end_dt, "指定快照"
        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")
        if normalized == "custom":
            return build_material_custom_window(start_date, end_date, tz_name)
        if normalized == "all":
            return build_all_material_window(tz_name)
        return build_performance_window(normalized, tz_name)

    @staticmethod
    def _numeric_material_id_text(*values: Any) -> str:
        for value in values:
            text = str(value or "").strip()
            if text.isdigit():
                return text
        return ""

    def _material_snapshot_rows_for_curve(
        self,
        material_key: str,
        start_date: str,
        end_date: str,
        snapshot_time: str,
        allowed_advertiser_ids: set[int] | None = None,
        *,
        search_all_customer_centers: bool = False,
    ) -> list[dict[str, Any]]:
        material_key_text = str(material_key or "").strip()
        if not material_key_text:
            return []
        clauses = ["material_key = ?"]
        params: list[Any] = [material_key_text]
        if not search_all_customer_centers:
            clauses.append("customer_center_id = ?")
            params.append(self._current_customer_center_id())
        target_snapshot = str(snapshot_time or "").strip()
        if target_snapshot:
            clauses.append("snapshot_time = ?")
            params.append(target_snapshot)
        else:
            clauses.append("substr(snapshot_time, 1, 10) >= ?")
            params.append(str(start_date or "").strip())
            clauses.append("substr(snapshot_time, 1, 10) <= ?")
            params.append(str(end_date or "").strip())
        if allowed_advertiser_ids is not None:
            allowed = sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
            if not allowed:
                return []
            placeholders = ",".join("?" for _ in allowed)
            clauses.append(f"advertiser_id IN ({placeholders})")
            params.extend(allowed)
        with self.db() as conn:
            rows = conn.execute(
                f"""
                SELECT
                    snapshot_time,
                    customer_center_id,
                    advertiser_id,
                    advertiser_name,
                    ad_id,
                    ad_name,
                    material_type,
                    material_key,
                    material_id,
                    material_name,
                    video_id,
                    aweme_item_id,
                    cover_url,
                    video_url,
                    stat_cost,
                    pay_amount,
                    order_count,
                    raw_json
                FROM material_snapshots
                WHERE {" AND ".join(clauses)}
                ORDER BY snapshot_time DESC, order_count DESC, pay_amount DESC, stat_cost DESC
                LIMIT 200
                """,
                params,
            ).fetchall()
        return [dict(row) for row in rows]

    @classmethod
    def _material_curve_source_from_snapshot_row(cls, row: dict[str, Any]) -> dict[str, Any] | None:
        raw_payload = cls._json_object(row.get("raw_json"))
        material_type = str(row.get("material_type") or raw_payload.get("material_type") or "VIDEO").strip().upper()
        identity = cls._extract_material_identity(material_type, raw_payload) if raw_payload else {}
        preview = cls._extract_material_preview(material_type, raw_payload) if raw_payload else {}
        resolved_material_id = cls._numeric_material_id_text(
            identity.get("material_id"),
            row.get("material_id"),
        )
        if not resolved_material_id:
            return None
        resolved_video_id = cls._first_text(
            identity.get("video_id"),
            row.get("video_id"),
        )
        resolved_aweme_item_id = cls._first_text(
            preview.get("aweme_item_id"),
            row.get("aweme_item_id"),
        )
        return {
            "snapshot_time": str(row.get("snapshot_time") or ""),
            "customer_center_id": str(row.get("customer_center_id") or "").strip(),
            "advertiser_id": int(row.get("advertiser_id", 0) or 0),
            "advertiser_name": str(row.get("advertiser_name") or "").strip(),
            "ad_id": int(row.get("ad_id", 0) or 0),
            "ad_name": str(row.get("ad_name") or "").strip(),
            "material_type": material_type,
            "material_key": str(row.get("material_key") or "").strip(),
            "material_id": resolved_material_id,
            "video_id": resolved_video_id,
            "aweme_item_id": resolved_aweme_item_id,
            "order_count": int(float(row.get("order_count", 0) or 0)),
            "pay_amount": round(float(row.get("pay_amount", 0.0) or 0.0), 2),
            "stat_cost": round(float(row.get("stat_cost", 0.0) or 0.0), 2),
            "source": "material_snapshots.raw_json",
        }

    def _material_curve_source_candidates(
        self,
        row: dict[str, Any],
        start_date: str,
        end_date: str,
        snapshot_time: str,
        allowed_advertiser_ids: set[int] | None = None,
        *,
        search_all_customer_centers: bool = False,
    ) -> list[dict[str, Any]]:
        ranking_material_id = self._numeric_material_id_text(row.get("material_id"))
        ranking_video_id = str(row.get("video_id") or "").strip()
        ranking_aweme_item_id = str(row.get("aweme_item_id") or "").strip()
        top_account_name = str(row.get("top_account_name") or "").strip()
        top_plan_name = str(row.get("top_plan_name") or "").strip()

        candidates: list[tuple[tuple[Any, ...], dict[str, Any]]] = []
        seen: set[tuple[int, int, str]] = set()
        for snapshot_row in self._material_snapshot_rows_for_curve(
            str(row.get("material_key") or ""),
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            search_all_customer_centers=search_all_customer_centers,
        ):
            candidate = self._material_curve_source_from_snapshot_row(snapshot_row)
            if not candidate:
                continue
            dedupe_key = (
                int(candidate["advertiser_id"]),
                int(candidate["ad_id"]),
                str(candidate["material_id"]),
            )
            if dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            score = (
                0 if ranking_material_id and candidate["material_id"] == ranking_material_id else 1,
                0 if ranking_aweme_item_id and candidate["aweme_item_id"] == ranking_aweme_item_id else 1,
                0 if ranking_video_id and candidate["video_id"] == ranking_video_id else 1,
                0 if top_account_name and candidate["advertiser_name"] == top_account_name else 1,
                0 if top_plan_name and candidate["ad_name"] == top_plan_name else 1,
                -int(candidate["order_count"]),
                -float(candidate["pay_amount"]),
                -float(candidate["stat_cost"]),
            )
            candidates.append((score, candidate))

        if candidates:
            candidates.sort(key=lambda item: item[0])
            return [dict(item[1]) for item in candidates]

        advertiser_ids = [int(item) for item in row.get("advertiser_ids", []) if int(item or 0)]
        advertiser_id = advertiser_ids[0] if advertiser_ids else 0
        if ranking_material_id and advertiser_id:
            return [{
                "snapshot_time": "",
                "customer_center_id": self._current_customer_center_id(),
                "advertiser_id": advertiser_id,
                "advertiser_name": str(row.get("top_account_name") or "").strip(),
                "ad_id": 0,
                "ad_name": str(row.get("top_plan_name") or "").strip(),
                "material_type": str(row.get("material_type") or "VIDEO").strip().upper(),
                "material_key": str(row.get("material_key") or "").strip(),
                "material_id": ranking_material_id,
                "video_id": ranking_video_id,
                "aweme_item_id": ranking_aweme_item_id,
                "order_count": int(float(row.get("order_count", 0) or 0)),
                "pay_amount": round(float(row.get("pay_amount", 0.0) or 0.0), 2),
                "stat_cost": round(float(row.get("stat_cost", 0.0) or 0.0), 2),
                "source": "material_rankings.material_id",
            }]
        return []

    def _resolve_material_curve_source(
        self,
        row: dict[str, Any],
        start_date: str,
        end_date: str,
        snapshot_time: str,
        allowed_advertiser_ids: set[int] | None = None,
        *,
        search_all_customer_centers: bool = False,
    ) -> dict[str, Any] | None:
        candidates = self._material_curve_source_candidates(
            row,
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            search_all_customer_centers=search_all_customer_centers,
        )
        return dict(candidates[0]) if candidates else None

    def _material_preview_row_for_request(
        self,
        material_key: str,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        user: dict[str, Any] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
    ) -> tuple[dict[str, Any], bool]:
        material_key_text = str(material_key or "").strip()
        if not material_key_text:
            raise ValueError("material_key is required")

        role = str((user or {}).get("role") or "")
        search_all_customer_centers = self._display_scope_uses_all_customer_centers(display_scope)
        if role == ROLE_OPERATOR or search_all_customer_centers:
            rankings_payload = self._cross_customer_center_material_payload(
                range_key,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
            )
            search_all_customer_centers = True
            if role == ROLE_OPERATOR:
                scoped_payload = self._apply_material_scope(rankings_payload, user or {})
                row = next(
                    (
                        dict(item)
                        for item in scoped_payload.get("items", [])
                        if str(item.get("material_key") or "").strip() == material_key_text
                    ),
                    None,
                )
                if row is None:
                    row = next(
                        (
                            dict(item)
                            for item in rankings_payload.get("items", [])
                            if str(item.get("material_key") or "").strip() == material_key_text
                        ),
                        None,
                    )
            else:
                row = next(
                    (
                        dict(item)
                        for item in rankings_payload.get("items", [])
                        if str(item.get("material_key") or "").strip() == material_key_text
                    ),
                    None,
                )
        else:
            rankings_payload = self.material_rankings(range_key, start_date, end_date, snapshot_time, allowed_advertiser_ids)
            row = next(
                (
                    dict(item)
                    for item in rankings_payload.get("items", [])
                    if str(item.get("material_key") or "").strip() == material_key_text
                ),
                None,
            )
            if row is None:
                rankings_payload = self._cross_customer_center_material_payload(
                    range_key,
                    start_date,
                    end_date,
                    snapshot_time,
                    allowed_advertiser_ids,
                )
                search_all_customer_centers = True
                row = next(
                    (
                        dict(item)
                        for item in rankings_payload.get("items", [])
                        if str(item.get("material_key") or "").strip() == material_key_text
                    ),
                    None,
                )
        if row is None:
            raise ValueError("material not found in current material rankings")
        return row, search_all_customer_centers

    def material_preview_source(
        self,
        row: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        user: dict[str, Any] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
    ) -> dict[str, Any]:
        seed_row = dict(row or {})
        material_key_text = str(seed_row.get("material_key") or "").strip()
        resolved_row: dict[str, Any]
        search_all_customer_centers = self._display_scope_uses_all_customer_centers(display_scope) or str((user or {}).get("role") or "") == ROLE_OPERATOR
        if material_key_text:
            try:
                resolved_row, search_all_customer_centers = self._material_preview_row_for_request(
                    material_key_text,
                    range_key,
                    start_date,
                    end_date,
                    snapshot_time,
                    allowed_advertiser_ids,
                    user,
                    display_scope,
                )
            except ValueError:
                if not seed_row:
                    raise
                resolved_row = seed_row
        elif seed_row:
            resolved_row = seed_row
        else:
            raise ValueError("material_key is required")

        merged_row = self._merge_material_preview_seed_row(resolved_row, seed_row)

        current_video_url = self._normalize_media_url(merged_row.get("video_url"))
        resolved_current_video_url = self._resolve_preview_video_url(current_video_url)
        cover_url = self._normalize_media_url(merged_row.get("cover_url"))
        public_cover_url = self._coerce_public_preview_cover_url(cover_url)
        aweme_item_id = str(merged_row.get("aweme_item_id") or "").strip()
        video_id = str(merged_row.get("video_id") or "").strip()
        material_id = str(merged_row.get("material_id") or "").strip()
        public_video_url = resolved_current_video_url or current_video_url
        result = {
            "material_key": str(merged_row.get("material_key") or "").strip(),
            "material_id": material_id,
            "video_id": video_id,
            "cover_url": public_cover_url,
            "aweme_item_id": aweme_item_id,
            "video_url": (
                public_video_url
                if self._is_public_preview_video_url(public_video_url)
                else ""
            ),
            "public_video_url": public_video_url
            if self._is_public_preview_video_url(public_video_url)
            else "",
            "is_public_video_url": self._is_public_preview_video_url(public_video_url),
            "source": "current_material_payload",
            "reason": "",
        }
        if result["is_public_video_url"]:
            return result
        deferred_proxy_video_url = ""
        if self._should_defer_material_preview_proxy(current_video_url):
            deferred_proxy_video_url = self.build_material_preview_proxy_url(current_video_url)
        else:
            current_proxy_video_url = self.build_material_preview_proxy_url(public_video_url)
            if current_proxy_video_url:
                result["video_url"] = current_proxy_video_url
                result["public_video_url"] = current_proxy_video_url
                result["is_public_video_url"] = True
                result["source"] = "current_material_payload_proxy"
                return result

        start_text = str(start_date or "").strip()
        end_text = str(end_date or "").strip()
        if not snapshot_time and (not start_text or not end_text):
            if str(range_key or "").strip().lower() == "custom":
                start_text = start_text or str(merged_row.get("create_time") or "")[:10]
                end_text = end_text or str(merged_row.get("create_time") or "")[:10]
            else:
                requested_start_dt, requested_end_dt, _label = self._material_preview_requested_window(
                    range_key,
                    start_date,
                    end_date,
                    snapshot_time,
                )
                start_text = requested_start_dt.strftime("%Y-%m-%d")
                end_text = requested_end_dt.strftime("%Y-%m-%d")
        resolved_source = self._resolve_material_curve_source(
            merged_row,
            start_text,
            end_text,
            snapshot_time,
            allowed_advertiser_ids,
            search_all_customer_centers=search_all_customer_centers,
        )
        if not resolved_source:
            result["reason"] = "当前素材未定位到可解析的视频来源。"
            if current_video_url and self._is_internal_preview_video_url(current_video_url):
                result["reason"] = "当前素材只返回千川站内预览地址，无法在外部页面直连播放。"
                result["source"] = "internal_video_url"
            elif not current_video_url and cover_url:
                result["reason"] = "当前素材仅返回封面图，未返回可直连视频地址。"
                result["source"] = "cover_only"
            return result

        customer_center_id = str(resolved_source.get("customer_center_id") or "").strip()
        advertiser_id = int(resolved_source.get("advertiser_id", 0) or 0)
        source_video_id = str(resolved_source.get("video_id") or video_id).strip()
        source_material_id = str(resolved_source.get("material_id") or material_id).strip()
        if not customer_center_id or advertiser_id <= 0:
            result["reason"] = "当前素材缺少可解析的视频来源配置。"
            return result

        client = self._build_scoped_customer_center_client(customer_center_id)
        if source_video_id:
            try:
                uploaded_video = client.get_uploaded_video(advertiser_id, source_video_id)
                public_video_url = self._preferred_video_url_from_values(
                    uploaded_video.get("url"),
                    uploaded_video.get("video_url"),
                    uploaded_video.get("videoUrl"),
                    uploaded_video.get("play_url"),
                    uploaded_video.get("playUrl"),
                    uploaded_video.get("download_url"),
                    uploaded_video.get("downloadUrl"),
                    uploaded_video.get("download_url_https"),
                    uploaded_video.get("downloadUrlHttps"),
                    uploaded_video.get("material_url"),
                    uploaded_video.get("materialUrl"),
                    current_video_url,
                )
                resolved_public_video_url = self._resolve_preview_video_url(public_video_url)
                if self._is_public_preview_video_url(resolved_public_video_url):
                    result["video_url"] = resolved_public_video_url
                    result["public_video_url"] = resolved_public_video_url
                    result["is_public_video_url"] = True
                    result["source"] = "file_video_ad_get"
                    poster_url = self._normalize_media_url(uploaded_video.get("poster_url") or uploaded_video.get("posterUrl"))
                    if poster_url:
                        result["cover_url"] = poster_url
                    return result
            except Exception as exc:  # noqa: BLE001
                if "permission" in str(exc).lower():
                    result["reason"] = "当前账号未授权公开视频文件接口，无法优先返回公网直链。"
                    result["source"] = "file_video_ad_get_permission_denied"

        if deferred_proxy_video_url:
            result["video_url"] = deferred_proxy_video_url
            result["public_video_url"] = deferred_proxy_video_url
            result["is_public_video_url"] = True
            result["source"] = "current_material_payload_proxy_fallback"
            return result

        if current_video_url and self._is_internal_preview_video_url(current_video_url):
            result["reason"] = result["reason"] or "当前素材只返回千川站内预览地址，无法在外部页面直连播放。"
            result["source"] = "internal_video_url"
        elif not current_video_url and cover_url:
            result["reason"] = result["reason"] or "当前素材仅返回封面图，未返回可直连视频地址。"
            result["source"] = "cover_only"
        elif source_material_id:
            result["reason"] = result["reason"] or "已尝试解析公网直链，但当前接口未返回可外部直连的视频文件地址。"
        return result

    def material_preview_source_v2(
        self,
        row: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        user: dict[str, Any] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
    ) -> dict[str, Any]:
        seed_row = dict(row or {})
        material_key_text = str(seed_row.get("material_key") or "").strip()
        search_all_customer_centers = (
            self._display_scope_uses_all_customer_centers(display_scope)
            or str((user or {}).get("role") or "") == ROLE_OPERATOR
        )
        if material_key_text:
            try:
                resolved_row, search_all_customer_centers = self._material_preview_row_for_request(
                    material_key_text,
                    range_key,
                    start_date,
                    end_date,
                    snapshot_time,
                    allowed_advertiser_ids,
                    user,
                    display_scope,
                )
            except ValueError:
                if not seed_row:
                    raise
                resolved_row = seed_row
        elif seed_row:
            resolved_row = seed_row
        else:
            raise ValueError("material_key is required")

        merged_row = self._merge_material_preview_seed_row(resolved_row, seed_row)

        current_video_url = self._normalize_media_url(merged_row.get("video_url"))
        resolved_current_video_url = self._resolve_preview_video_url(
            current_video_url,
            timeout=MATERIAL_PREVIEW_SOURCE_RESOLVE_TIMEOUT_SECONDS,
        )
        cover_url = self._normalize_media_url(merged_row.get("cover_url"))
        aweme_item_id = str(merged_row.get("aweme_item_id") or "").strip()
        video_id = str(merged_row.get("video_id") or "").strip()
        material_id = str(merged_row.get("material_id") or "").strip()
        public_video_url = resolved_current_video_url or current_video_url

        def finalize_result(payload: dict[str, Any]) -> dict[str, Any]:
            source_text = str(payload.get("source") or "").strip()
            normalized_cover_url = self._normalize_media_url(payload.get("cover_url"))
            normalized_video_url = self._normalize_media_url(payload.get("video_url"))
            normalized_public_video_url = self._normalize_media_url(payload.get("public_video_url"))
            normalized_browser_video_url = self._normalize_media_url(payload.get("browser_video_url"))
            payload["cover_url"] = (
                normalized_cover_url if self._is_public_preview_cover_url(normalized_cover_url) else ""
            )
            payload["video_url"] = (
                normalized_video_url if self._is_public_preview_video_url(normalized_video_url) else ""
            )
            payload["public_video_url"] = (
                normalized_public_video_url
                if self._is_public_preview_video_url(normalized_public_video_url)
                else payload["video_url"]
            )
            payload["browser_video_url"] = (
                normalized_browser_video_url
                if self._is_browser_preview_video_candidate_url(normalized_browser_video_url)
                else ""
            )
            payload["browser_video_source"] = str(
                payload.get("browser_video_source") or (source_text if payload["browser_video_url"] else "")
            ).strip()
            payload["is_public_video_url"] = bool(payload["video_url"])
            payload["cover_source"] = str(
                payload.get("cover_source") or (source_text if payload["cover_url"] else "")
            ).strip()
            payload["video_source"] = str(
                payload.get("video_source") or (source_text if payload["video_url"] else "")
            ).strip()
            payload["preview_available"] = bool(
                payload["cover_url"]
                or payload["video_url"]
                or payload["public_video_url"]
                or payload["browser_video_url"]
                or aweme_item_id
            )
            return payload

        def finish(payload: dict[str, Any], *, cacheable: bool = True) -> dict[str, Any]:
            finalized = finalize_result(payload)
            if cacheable and cache_key and isinstance(finalized, dict):
                self._store_material_preview_source_cache(cache_key, cache_version, finalized)
            return finalized

        result = {
            "material_key": str(merged_row.get("material_key") or "").strip(),
            "material_id": material_id,
            "video_id": video_id,
            "cover_url": cover_url if self._is_public_preview_cover_url(cover_url) else "",
            "aweme_item_id": aweme_item_id,
            "video_url": public_video_url if self._is_public_preview_video_url(public_video_url) else "",
            "public_video_url": public_video_url if self._is_public_preview_video_url(public_video_url) else "",
            "browser_video_url": current_video_url
            if self._is_browser_preview_video_candidate_url(current_video_url)
            else "",
            "browser_video_source": "current_material_payload"
            if self._is_browser_preview_video_candidate_url(current_video_url)
            else "",
            "is_public_video_url": self._is_public_preview_video_url(public_video_url),
            "source": "current_material_payload",
            "reason": "",
        }
        deferred_proxy_video_url = ""
        if self._should_defer_material_preview_proxy(current_video_url):
            deferred_proxy_video_url = self.build_material_preview_proxy_url(current_video_url)
        else:
            current_proxy_video_url = self.build_material_preview_proxy_url(public_video_url)
            if current_proxy_video_url:
                result["video_url"] = current_proxy_video_url
                result["public_video_url"] = current_proxy_video_url
                result["is_public_video_url"] = True
                result["source"] = "current_material_payload_proxy"

        start_text = str(start_date or "").strip()
        end_text = str(end_date or "").strip()
        if not snapshot_time and (not start_text or not end_text):
            if str(range_key or "").strip().lower() == "custom":
                start_text = start_text or str(merged_row.get("create_time") or "")[:10]
                end_text = end_text or str(merged_row.get("create_time") or "")[:10]
            else:
                requested_start_dt, requested_end_dt, _label = self._material_preview_requested_window(
                    range_key,
                    start_date,
                    end_date,
                    snapshot_time,
                )
                start_text = requested_start_dt.strftime("%Y-%m-%d")
                end_text = requested_end_dt.strftime("%Y-%m-%d")

        cache_key = build_material_preview_source_cache_key(
            merged_row,
            range_key,
            start_text,
            end_text,
            snapshot_time,
            allowed_advertiser_ids,
            self._material_preview_cache_customer_center_id(display_scope),
        )
        cache_version = self._shared_cache_version("material-preview-source") if cache_key else "1"
        if cache_key:
            cached_payload = self._material_preview_source_cached_payload(cache_key, cache_version)
            if cached_payload is not None:
                return cached_payload

        if result["is_public_video_url"]:
            return finish(result)

        resolved_sources = self._material_curve_source_candidates(
            merged_row,
            start_text,
            end_text,
            snapshot_time,
            allowed_advertiser_ids,
            search_all_customer_centers=search_all_customer_centers,
        )[:MATERIAL_PREVIEW_SOURCE_MAX_CANDIDATES]
        if not resolved_sources:
            result["reason"] = "当前素材未定位到可解析的预览来源。"
            if current_video_url and self._needs_preview_video_redirect_resolution(current_video_url):
                result["reason"] = "当前素材返回的是千川中转预览地址，无法直接在浏览器中播放。"
                result["source"] = "redirect_preview_video_url"
            elif current_video_url and self._is_internal_preview_video_url(current_video_url):
                result["reason"] = "当前素材只返回站内预览地址，无法在外部页面直接播放。"
                result["source"] = "internal_video_url"
            elif cover_url and not self._is_public_preview_cover_url(cover_url):
                result["reason"] = "当前素材仅返回受限封面图地址，浏览器无法直接加载。"
                result["source"] = "restricted_cover_url"
            elif not current_video_url and cover_url:
                result["reason"] = "当前素材仅返回封面图，未返回可直接播放的视频地址。"
                result["source"] = "cover_only"
            return finish(result)

        attempted_sources = []
        any_source_material_id = False
        for resolved_source in resolved_sources:
            customer_center_id = str(resolved_source.get("customer_center_id") or "").strip()
            advertiser_id = int(resolved_source.get("advertiser_id", 0) or 0)
            source_video_id = str(resolved_source.get("video_id") or video_id).strip()
            source_material_id = str(resolved_source.get("material_id") or material_id).strip()
            if source_material_id:
                any_source_material_id = True
            if not customer_center_id or advertiser_id <= 0:
                continue
            attempted_sources.append(f"{customer_center_id}:{advertiser_id}:{source_video_id}")
            client = self._build_scoped_customer_center_client(customer_center_id)
            if source_video_id:
                try:
                    video_rows = client.list_qianchuan_videos(
                        advertiser_id=advertiser_id,
                        filtering={"video_ids": [source_video_id]},
                        page_size=10,
                        max_pages=1,
                        attempts=MATERIAL_PREVIEW_SOURCE_LOOKUP_ATTEMPTS,
                    )
                    for item in video_rows:
                        resolved_library_video_id = str(item.get("id") or item.get("video_id") or item.get("videoId") or "").strip()
                        if resolved_library_video_id and resolved_library_video_id != source_video_id:
                            continue
                        candidate_video_url = self._preferred_video_url_from_values(
                            item.get("url"),
                            item.get("video_url"),
                            item.get("videoUrl"),
                            item.get("play_url"),
                            item.get("playUrl"),
                            current_video_url,
                        )
                        resolved_library_video_url = self._resolve_preview_video_url(
                            candidate_video_url,
                            timeout=MATERIAL_PREVIEW_SOURCE_RESOLVE_TIMEOUT_SECONDS,
                        )
                        if self._is_public_preview_video_url(resolved_library_video_url):
                            result["video_url"] = resolved_library_video_url
                            result["public_video_url"] = resolved_library_video_url
                            result["is_public_video_url"] = True
                            result["source"] = "qianchuan_video_get"
                            result["reason"] = ""
                            poster_url = self._coerce_public_preview_cover_url(
                                item.get("poster_url") or item.get("posterUrl") or cover_url
                            )
                            if poster_url:
                                result["cover_url"] = poster_url
                            return finish(result)
                        proxy_video_url = self.build_material_preview_proxy_url(candidate_video_url)
                        if proxy_video_url:
                            result["video_url"] = proxy_video_url
                            result["public_video_url"] = proxy_video_url
                            result["is_public_video_url"] = True
                            result["source"] = "qianchuan_video_get_proxy"
                            result["reason"] = ""
                            poster_url = self._coerce_public_preview_cover_url(
                                item.get("poster_url") or item.get("posterUrl") or cover_url
                            )
                            if poster_url:
                                result["cover_url"] = poster_url
                            return finish(result)
                        if self._is_browser_preview_video_candidate_url(candidate_video_url):
                            result["browser_video_url"] = candidate_video_url
                            result["browser_video_source"] = "qianchuan_video_get"
                            result["source"] = "qianchuan_video_get_browser_candidate"
                            result["reason"] = ""
                            poster_url = self._coerce_public_preview_cover_url(
                                item.get("poster_url") or item.get("posterUrl") or cover_url
                            )
                            if poster_url:
                                result["cover_url"] = poster_url
                            return finish(result)
                        poster_url = self._coerce_public_preview_cover_url(
                            item.get("poster_url") or item.get("posterUrl") or cover_url
                        )
                        if poster_url and not result["cover_url"]:
                            result["cover_url"] = poster_url
                except Exception:
                    pass
                try:
                    uploaded_video = client.get_uploaded_video(
                        advertiser_id,
                        source_video_id,
                        attempts=MATERIAL_PREVIEW_SOURCE_LOOKUP_ATTEMPTS,
                        base_delay=0.25,
                    )
                    candidate_video_url = self._preferred_video_url_from_values(
                        uploaded_video.get("url"),
                        uploaded_video.get("video_url"),
                        uploaded_video.get("videoUrl"),
                        uploaded_video.get("play_url"),
                        uploaded_video.get("playUrl"),
                        uploaded_video.get("download_url"),
                        uploaded_video.get("downloadUrl"),
                        uploaded_video.get("download_url_https"),
                        uploaded_video.get("downloadUrlHttps"),
                        uploaded_video.get("material_url"),
                        uploaded_video.get("materialUrl"),
                        current_video_url,
                    )
                    resolved_public_video_url = self._resolve_preview_video_url(
                        candidate_video_url,
                        timeout=MATERIAL_PREVIEW_SOURCE_RESOLVE_TIMEOUT_SECONDS,
                    )
                    if self._is_public_preview_video_url(resolved_public_video_url):
                        result["video_url"] = resolved_public_video_url
                        result["public_video_url"] = resolved_public_video_url
                        result["is_public_video_url"] = True
                        result["source"] = "file_video_ad_get"
                        result["reason"] = ""
                        poster_url = self._coerce_public_preview_cover_url(
                            uploaded_video.get("poster_url") or uploaded_video.get("posterUrl")
                        )
                        if poster_url:
                            result["cover_url"] = poster_url
                        return finish(result)
                    proxy_video_url = self.build_material_preview_proxy_url(candidate_video_url)
                    if proxy_video_url:
                        result["video_url"] = proxy_video_url
                        result["public_video_url"] = proxy_video_url
                        result["is_public_video_url"] = True
                        result["source"] = "file_video_ad_get_proxy"
                        result["reason"] = ""
                        poster_url = self._coerce_public_preview_cover_url(
                            uploaded_video.get("poster_url") or uploaded_video.get("posterUrl")
                        )
                        if poster_url:
                            result["cover_url"] = poster_url
                        return finish(result)
                    if self._is_browser_preview_video_candidate_url(candidate_video_url):
                        result["browser_video_url"] = candidate_video_url
                        result["browser_video_source"] = "file_video_ad_get"
                        result["source"] = "file_video_ad_get_browser_candidate"
                        result["reason"] = ""
                        poster_url = self._coerce_public_preview_cover_url(
                            uploaded_video.get("poster_url") or uploaded_video.get("posterUrl")
                        )
                        if poster_url:
                            result["cover_url"] = poster_url
                        return finish(result)
                except Exception as exc:  # noqa: BLE001
                    message = str(exc)
                    lowered = message.lower()
                    if "permission" in lowered and not result["reason"]:
                        result["reason"] = "当前账号未授权公开视频接口，无法优先返回公网直链。"
                        result["source"] = "file_video_ad_get_permission_denied"
                    elif ("refresh_token" in lowered or "40103" in message or "已过期" in message) and not result["reason"]:
                        result["reason"] = "素材所属客服中心授权已过期，当前无法解析可外部访问的预览地址。"
                        result["source"] = "file_video_ad_get_token_expired"

        if deferred_proxy_video_url:
            result["video_url"] = deferred_proxy_video_url
            result["public_video_url"] = deferred_proxy_video_url
            result["is_public_video_url"] = True
            result["source"] = "current_material_payload_proxy_fallback"
            return finish(result)

        if not attempted_sources:
            result["reason"] = "当前素材缺少可解析的预览来源配置。"
            return finish(result)

        if current_video_url and self._needs_preview_video_redirect_resolution(current_video_url):
            result["reason"] = result["reason"] or "当前素材返回的是千川中转预览地址，无法直接在浏览器中播放。"
            result["source"] = "redirect_preview_video_url"
        elif current_video_url and self._is_internal_preview_video_url(current_video_url):
            result["reason"] = result["reason"] or "当前素材只返回站内预览地址，无法在外部页面直接播放。"
            result["source"] = "internal_video_url"
        elif cover_url and not self._is_public_preview_cover_url(cover_url):
            result["reason"] = result["reason"] or "当前素材仅返回受限封面图地址，浏览器无法直接加载。"
            result["source"] = "restricted_cover_url"
        elif not current_video_url and cover_url:
            result["reason"] = result["reason"] or "当前素材仅返回封面图，未返回可直接播放的视频地址。"
            result["source"] = "cover_only"
        elif any_source_material_id:
            result["reason"] = result["reason"] or "已尝试解析公网直链，但当前接口未返回可外部访问的视频文件地址。"
        return finish(result)

    def material_preview_curve(
        self,
        material_key: str,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        user: dict[str, Any] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
    ) -> dict[str, Any]:
        material_key_text = str(material_key or "").strip()
        curve_metric_fields = ("click_cnt", "dy_like", "dy_comment", "dy_follow", "user_lose_cnt")
        requested_start_dt, requested_end_dt, requested_range_label = self._material_preview_requested_window(
            range_key,
            start_date,
            end_date,
            snapshot_time,
        )
        try:
            row, search_all_customer_centers = self._material_preview_row_for_request(
                material_key_text,
                range_key,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
                user,
                display_scope,
            )
        except ValueError as exc:
            if str(exc) != "material not found in current material rankings":
                raise
            return {
                "material_key": material_key_text,
                "material_id": "",
                "material_name": "",
                "material_type": "VIDEO",
                "advertiser_id": 0,
                "curve_material_id": "",
                "curve_advertiser_id": 0,
                "curve_ad_id": 0,
                "material_id_source": "",
                "advertiser_count": 0,
                "top_account_name": "",
                "supported": True,
                "t_plus_one_only": True,
                "range_key": str(range_key or "day"),
                "range_label": str(requested_range_label or ""),
                "requested_start_date": requested_start_dt.strftime("%Y-%m-%d"),
                "requested_end_date": requested_end_dt.strftime("%Y-%m-%d"),
                "query_start_date": requested_start_dt.strftime("%Y-%m-%d"),
                "query_end_date": requested_end_dt.strftime("%Y-%m-%d"),
                "is_clamped_to_yesterday": False,
                "notice": "",
                "message": "Selected material is no longer present in the current rankings. Refresh the material list and retry.",
                "series": [],
                "metrics": list(curve_metric_fields),
                "totals": {field: 0 for field in curve_metric_fields},
                "peak": {
                    "second": 0,
                    **{field: 0 for field in curve_metric_fields},
                },
                "peaks": {field: {"second": 0, "value": 0} for field in curve_metric_fields},
                "duration_seconds": 0,
                "point_count": 0,
            }

        material_type = str(row.get("material_type") or "").strip().upper()
        advertiser_ids = [int(item) for item in row.get("advertiser_ids", []) if int(item or 0)]
        advertiser_id = advertiser_ids[0] if advertiser_ids else 0
        config = self.read_config()
        tz = ZoneInfo(str(config.get("timezone") or TIMEZONE))
        latest_available_day = (datetime.now(tz) - timedelta(days=1)).date()
        latest_available_start = datetime(
            latest_available_day.year,
            latest_available_day.month,
            latest_available_day.day,
            0,
            0,
            0,
            tzinfo=tz,
        )
        latest_available_end = datetime(
            latest_available_day.year,
            latest_available_day.month,
            latest_available_day.day,
            23,
            59,
            59,
            tzinfo=tz,
        )

        response_payload: dict[str, Any] = {
            "material_key": material_key_text,
            "material_id": str(row.get("material_id") or ""),
            "material_name": str(row.get("material_name") or ""),
            "material_type": material_type,
            "advertiser_id": advertiser_id,
            "curve_material_id": "",
            "curve_advertiser_id": 0,
            "curve_ad_id": 0,
            "material_id_source": "",
            "advertiser_count": len(advertiser_ids),
            "top_account_name": str(row.get("top_account_name") or ""),
            "supported": material_type == "VIDEO",
            "t_plus_one_only": True,
            "range_key": str(range_key or "day"),
            "range_label": str(requested_range_label or ""),
            "requested_start_date": requested_start_dt.strftime("%Y-%m-%d"),
            "requested_end_date": requested_end_dt.strftime("%Y-%m-%d"),
            "query_start_date": "",
            "query_end_date": "",
            "is_clamped_to_yesterday": False,
            "notice": "",
            "message": "",
            "series": [],
            "metrics": list(curve_metric_fields),
            "totals": {field: 0 for field in curve_metric_fields},
            "peak": {
                "second": 0,
                **{field: 0 for field in curve_metric_fields},
            },
            "peaks": {field: {"second": 0, "value": 0} for field in curve_metric_fields},
            "duration_seconds": 0,
            "point_count": 0,
        }

        if material_type != "VIDEO":
            response_payload["message"] = "仅视频素材支持互动峰形图。"
            return response_payload

        query_start_dt = requested_start_dt
        query_end_dt = min(requested_end_dt, latest_available_end)
        clamped = query_end_dt < requested_end_dt
        target_snapshot = str(snapshot_time or "").strip()
        normalized_range = str(range_key or "day").strip().lower()
        if query_start_dt > query_end_dt:
            if not target_snapshot and normalized_range == "day":
                query_start_dt = latest_available_start
                query_end_dt = latest_available_end
                clamped = True
            else:
                response_payload["query_start_date"] = requested_start_dt.strftime("%Y-%m-%d")
                response_payload["query_end_date"] = requested_end_dt.strftime("%Y-%m-%d")
                response_payload["is_clamped_to_yesterday"] = clamped
                response_payload["message"] = "当前筛选范围内没有可查询的 T+1 数据。"
                if clamped:
                    response_payload["notice"] = f"该接口仅支持 T+1 数据，最近可查询日期为 {latest_available_day.isoformat()}。"
                return response_payload

        response_payload["query_start_date"] = query_start_dt.strftime("%Y-%m-%d")
        response_payload["query_end_date"] = query_end_dt.strftime("%Y-%m-%d")
        response_payload["is_clamped_to_yesterday"] = clamped

        resolved_sources = self._material_curve_source_candidates(
            row,
            response_payload["query_start_date"],
            response_payload["query_end_date"],
            snapshot_time,
            allowed_advertiser_ids,
            search_all_customer_centers=search_all_customer_centers,
        )
        resolved_source = dict(resolved_sources[0]) if resolved_sources else None
        if resolved_source:
            response_payload["curve_material_id"] = str(resolved_source.get("material_id") or "")
            response_payload["curve_advertiser_id"] = int(resolved_source.get("advertiser_id", 0) or 0)
            response_payload["curve_ad_id"] = int(resolved_source.get("ad_id", 0) or 0)
            response_payload["material_id_source"] = str(resolved_source.get("source") or "")
        if not response_payload["curve_material_id"]:
            response_payload["message"] = "未找到可用于峰形图查询的素材唯一 ID。"
            return response_payload
        if not response_payload["curve_advertiser_id"]:
            response_payload["message"] = "未找到可用于峰形图查询的投放账户 ID。"
            return response_payload

        notices: list[str] = []
        if clamped:
            notices.append(f"该接口仅支持 T+1 数据，当前展示截至 {latest_available_day.isoformat()} 的数据。")
        if len(advertiser_ids) > 1:
            account_name = str(row.get("top_account_name") or "").strip()
            if account_name:
                notices.append(f"该素材被多个账户复用，当前仅展示账户 {account_name} 的曲线。")
            else:
                notices.append("该素材被多个账户复用，当前仅展示其中一个账户的曲线。")

        source_limit = max(min(int(os.environ.get("MATERIAL_PREVIEW_CURVE_SOURCE_LIMIT") or "20"), 50), 1)
        points: list[dict[str, float]] = []
        tried_sources = 0
        last_error = ""
        for candidate_source in resolved_sources[:source_limit]:
            candidate_material_id = str(candidate_source.get("material_id") or "").strip()
            candidate_advertiser_id = int(candidate_source.get("advertiser_id", 0) or 0)
            if not candidate_material_id or candidate_advertiser_id <= 0:
                continue
            tried_sources += 1
            curve_customer_center_id = (
                str(candidate_source.get("customer_center_id") or "").strip()
                or self._current_customer_center_id()
            )
            client = self._build_scoped_customer_center_client(curve_customer_center_id)
            try:
                response = client.get_video_user_lose(
                    advertiser_id=candidate_advertiser_id,
                    material_id=candidate_material_id,
                    start_date=response_payload["query_start_date"],
                    end_date=response_payload["query_end_date"],
                )
                candidate_points = self._normalize_video_user_lose_rows(response)
            except Exception as exc:  # noqa: BLE001
                last_error = str(exc)
                continue
            if not candidate_points:
                continue
            points = candidate_points
            resolved_source = dict(candidate_source)
            response_payload["curve_material_id"] = candidate_material_id
            response_payload["curve_advertiser_id"] = candidate_advertiser_id
            response_payload["curve_ad_id"] = int(candidate_source.get("ad_id", 0) or 0)
            response_payload["material_id_source"] = str(candidate_source.get("source") or "")
            break
        response_payload["series"] = [
            {
                "second": int(point["second"]),
                **{field: int(round(point.get(field, 0.0) or 0.0)) for field in curve_metric_fields},
            }
            for point in points
        ]
        response_payload["duration_seconds"] = int(max((point["second"] for point in points), default=0))
        response_payload["point_count"] = len(points)
        response_payload["totals"] = {
            field: int(round(sum(float(point.get(field, 0.0) or 0.0) for point in points)))
            for field in curve_metric_fields
        }
        response_payload["peaks"] = {
            field: max(
                (
                    {
                        "second": int(item.get("second", 0) or 0),
                        "value": int(item.get(field, 0) or 0),
                    }
                    for item in response_payload["series"]
                ),
                key=lambda item: (int(item["value"]), -int(item["second"])),
                default={"second": 0, "value": 0},
            )
            for field in curve_metric_fields
        }
        peak_point = max(
            response_payload["series"],
            key=lambda item: (
                max(int(item.get(field, 0) or 0) for field in curve_metric_fields),
                int(item.get("click_cnt", 0) or 0),
                -int(item["second"]),
            ),
            default={"second": 0, **{field: 0 for field in curve_metric_fields}},
        )
        response_payload["peak"] = {
            "second": int(peak_point["second"]),
            **{field: int(peak_point.get(field, 0) or 0) for field in curve_metric_fields},
        }
        if not response_payload["series"]:
            response_payload["message"] = "接口未返回该素材的秒级互动分布数据。"
        if notices:
            response_payload["notice"] = " ".join(notices)
        return response_payload

    def _material_meta_from_rows(
        self,
        rows: list[dict[str, Any]],
        latest_snapshot_time: str,
        *,
        material_count: int | None = None,
    ) -> dict[str, Any]:
        snapshot_dates = sorted(
            {
                str(row.get("snapshot_time") or "")[:10]
                for row in rows
                if str(row.get("snapshot_time") or "").strip()
            }
        )
        return {
            "snapshot_time": latest_snapshot_time,
            "status": "ok",
            "plan_count": 0,
            "detail_count": 0,
            "product_count": 0,
            "material_count": int(material_count if material_count is not None else len(rows)),
            "video_count": 0,
            "error_count": 0,
            "snapshot_dates": snapshot_dates,
            "snapshot_fallback_used": False,
        }

    @staticmethod
    def _material_performance_row_has_metrics(row: dict[str, Any]) -> bool:
        metric_fields = (
            "stat_cost",
            "pay_amount",
            "total_pay_amount",
            "settled_pay_amount",
            "order_count",
            "settled_order_count",
            "overall_show_count",
            "overall_click_count",
            "refund_amount_1h",
        )
        for field in metric_fields:
            try:
                if float(row.get(field, 0) or 0) != 0.0:
                    return True
            except Exception:
                continue
        return False

    def _filter_material_current_or_daily_rows(
        self,
        rows: list[dict[str, Any]],
        start_dt: datetime,
        end_dt: datetime,
        tz_name: str,
        allowed_advertiser_ids: set[int] | None = None,
    ) -> list[dict[str, Any]]:
        # current/daily rows are already scoped by performance day; do not re-filter by material create_time.
        # Zero-metric materials remain in the result set and are naturally ordered by the requested sort field.
        scoped_rows: list[dict[str, Any]] = []
        for raw_row in rows:
            row = dict(raw_row)
            create_time = self._normalize_datetime_text(row.get("create_time"))
            if create_time:
                row["create_time"] = create_time
            scoped_rows.append(row)
        if allowed_advertiser_ids is None:
            return scoped_rows
        allowed = {int(item) for item in allowed_advertiser_ids}
        return [
            row
            for row in scoped_rows
            if any(int(item) in allowed for item in json.loads(str(row.get("advertiser_ids_json") or "[]")))
        ]

    def _material_row_matches_create_time_window(
        self,
        row: dict[str, Any],
        start_dt: datetime,
        end_dt: datetime,
        tz_name: str,
        *,
        include_missing: bool = False,
    ) -> bool:
        tz = ZoneInfo(str(tz_name or TIMEZONE))
        start_text = start_dt.astimezone(tz).strftime("%Y-%m-%d %H:%M:%S")
        end_text = end_dt.astimezone(tz).strftime("%Y-%m-%d %H:%M:%S")
        create_time = self._normalize_datetime_text(row.get("create_time"))
        if not create_time:
            return include_missing
        return start_text <= create_time <= end_text

    def _material_profile_first_seen_map(
        self,
        conn: Any,
        material_refs: list[tuple[str, str]],
    ) -> dict[tuple[str, str], str]:
        refs_by_customer_center: dict[str, set[str]] = {}
        for customer_center_id, material_key in material_refs:
            normalized_customer_center_id = str(customer_center_id or "").strip()
            normalized_material_key = str(material_key or "").strip()
            if not normalized_customer_center_id or not normalized_material_key:
                continue
            refs_by_customer_center.setdefault(normalized_customer_center_id, set()).add(normalized_material_key)
        if not refs_by_customer_center:
            return {}
        first_seen_by_key: dict[tuple[str, str], str] = {}
        for customer_center_id, material_keys in refs_by_customer_center.items():
            for chunk in self._chunked_material_keys(sorted(material_keys)):
                placeholders = ",".join("?" for _ in chunk)
                rows = conn.execute(
                    f"""
                    SELECT
                        material_key,
                        MIN(NULLIF(first_seen_at, '')) AS first_seen_at
                    FROM material_relation_edges
                    WHERE customer_center_id = ?
                      AND material_key IN ({placeholders})
                    GROUP BY material_key
                    """,
                    [customer_center_id, *chunk],
                ).fetchall()
                for raw_row in rows:
                    material_key = str(raw_row.get("material_key") or "").strip()
                    first_seen_at = self._normalize_datetime_text(raw_row.get("first_seen_at"))
                    if material_key and first_seen_at:
                        first_seen_by_key[(customer_center_id, material_key)] = first_seen_at
        return first_seen_by_key

    def _material_profile_rows_for_window(
        self,
        conn: Any,
        start_dt: datetime,
        end_dt: datetime,
        *,
        tz_name: str,
        range_key: str,
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
    ) -> list[dict[str, Any]]:
        where_prefix = "COALESCE(customer_center_id, '') <> ''" if all_customer_centers else "customer_center_id = ?"
        params_prefix: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        rows = [
            dict(row)
            for row in conn.execute(
                f"""
                SELECT
                    customer_center_id,
                    material_key,
                    material_id,
                    material_name,
                    create_time,
                    material_type,
                    video_id,
                    cover_url,
                    aweme_item_id,
                    video_url,
                    is_original,
                    top_plan_name,
                    top_account_name,
                    top_anchor_name,
                    product_info_text,
                    product_names_json,
                    plan_ids_json,
                    advertiser_ids_json,
                    plan_count,
                    advertiser_count,
                    updated_at
                FROM material_profile
                WHERE {where_prefix}
                ORDER BY updated_at DESC, material_key ASC
                """,
                params_prefix,
            ).fetchall()
        ]
        first_seen_by_key = self._material_profile_first_seen_map(
            conn,
            [
                (
                    str(row.get("customer_center_id") or "").strip(),
                    str(row.get("material_key") or "").strip(),
                )
                for row in rows
            ],
        )
        scoped_rows: list[dict[str, Any]] = []
        for raw_row in rows:
            row = dict(raw_row)
            customer_center_id = str(row.get("customer_center_id") or "").strip()
            material_key = str(row.get("material_key") or "").strip()
            stored_create_time = self._normalize_datetime_text(row.get("create_time"))
            first_seen_at = first_seen_by_key.get((customer_center_id, material_key), "")
            create_time = stored_create_time or first_seen_at
            updated_at = self._normalize_datetime_text(row.get("updated_at"))
            if create_time:
                row["create_time"] = create_time
            if first_seen_at:
                row["first_seen_at"] = first_seen_at
            if not stored_create_time and first_seen_at:
                row["_create_time_fallback"] = True
            if updated_at:
                row["updated_at"] = updated_at
            scoped_rows.append(row)
        if allowed_advertiser_ids is not None:
            allowed = {int(item) for item in allowed_advertiser_ids}
            scoped_rows = [
                row
                for row in scoped_rows
                if any(int(item) in allowed for item in json.loads(str(row.get("advertiser_ids_json") or "[]")))
            ]
        include_missing = str(range_key or "").strip().lower() == "all"
        matched_rows = [
            row
            for row in scoped_rows
            if self._material_row_matches_create_time_window(
                row,
                start_dt,
                end_dt,
                tz_name,
                include_missing=include_missing,
            )
        ]
        if matched_rows or include_missing or not scoped_rows:
            return matched_rows
        if any(self._normalize_datetime_text(row.get("create_time")) for row in scoped_rows):
            return matched_rows
        fallback_rows: list[dict[str, Any]] = []
        for row in scoped_rows:
            fallback_row = dict(row)
            fallback_row["_create_time_fallback"] = True
            fallback_rows.append(fallback_row)
        return fallback_rows

    @staticmethod
    def _material_profile_seed_row(
        row: dict[str, Any],
        *,
        snapshot_time: str,
        window_start: str,
        window_end: str,
    ) -> dict[str, Any]:
        return {
            "customer_center_id": str(row.get("customer_center_id") or "").strip(),
            "snapshot_time": str(snapshot_time or ""),
            "window_start": str(window_start or ""),
            "window_end": str(window_end or ""),
            "material_key": str(row.get("material_key") or "").strip(),
            "material_id": str(row.get("material_id") or "").strip(),
            "material_name": str(row.get("material_name") or "").strip(),
            "backend_material_name": str(row.get("backend_material_name") or "").strip(),
            "publish_title": str(row.get("publish_title") or "").strip(),
            "creative_title_material_ids_json": str(row.get("creative_title_material_ids_json") or "[]").strip() or "[]",
            "creative_source": str(row.get("creative_source") or "").strip(),
            "create_time": str(row.get("create_time") or "").strip(),
            "material_type": str(row.get("material_type") or "").strip(),
            "video_id": str(row.get("video_id") or "").strip(),
            "cover_url": str(row.get("cover_url") or "").strip(),
            "aweme_item_id": str(row.get("aweme_item_id") or "").strip(),
            "video_url": str(row.get("video_url") or "").strip(),
            "stat_cost": 0.0,
            "pay_amount": 0.0,
            "total_pay_amount": 0.0,
            "settled_pay_amount": 0.0,
            "order_count": 0,
            "settled_order_count": 0,
            "plan_count": int(row.get("plan_count", 0) or 0),
            "advertiser_count": int(row.get("advertiser_count", 0) or 0),
            "plan_ids_json": str(row.get("plan_ids_json") or "[]"),
            "advertiser_ids_json": str(row.get("advertiser_ids_json") or "[]"),
            "is_original": bool(row.get("is_original")),
            "top_plan_name": str(row.get("top_plan_name") or "").strip(),
            "top_account_name": str(row.get("top_account_name") or "").strip(),
            "top_anchor_name": str(row.get("top_anchor_name") or "").strip(),
            "product_info_text": str(row.get("product_info_text") or "").strip(),
            "product_names_json": str(row.get("product_names_json") or "[]"),
            "overall_show_count": 0,
            "overall_click_count": 0,
            "overall_ctr": 0.0,
            "roi": 0.0,
            "settled_roi": 0.0,
            "pay_order_cost": 0.0,
            "settled_amount_rate": 0.0,
            "refund_amount_1h": 0.0,
            "refund_rate_1h": None,
        }

    def _build_material_payload_from_rows(
        self,
        conn: Any,
        material_rows: list[dict[str, Any]],
        *,
        latest_snapshot_time: str,
        all_customer_centers: bool = False,
        meta_rows: list[dict[str, Any]] | None = None,
        enrich_snapshot_context: bool = False,
        query_context_ready: bool = False,
    ) -> dict[str, Any]:
        aggregated_items = self._aggregate_material_rollups(material_rows)
        effective_context_ready = bool(query_context_ready)
        if (
            enrich_snapshot_context
            and aggregated_items
            and material_rows
            and len(aggregated_items) <= MATERIAL_EAGER_CONTEXT_ROW_LIMIT
        ):
            selected_pairs = self._snapshot_pairs_from_rows(material_rows)
            if selected_pairs:
                aggregated_items = self._apply_material_snapshot_context_for_pairs(
                    conn,
                    aggregated_items,
                    selected_pairs,
                )
                aggregated_items = self._apply_material_top_anchor_names_for_pairs(
                    conn,
                    aggregated_items,
                    selected_pairs,
                )
                aggregated_items = self._apply_material_relation_context(
                    conn,
                    aggregated_items,
                )
                effective_context_ready = True
        elif enrich_snapshot_context and aggregated_items and material_rows:
            effective_context_ready = False
        payload = {
            "snapshot_time": latest_snapshot_time,
            "items": aggregated_items,
            "meta": self._material_meta_from_rows(
                meta_rows or material_rows,
                latest_snapshot_time,
                material_count=len(aggregated_items),
            ),
            "snapshot_count": len(
                {str(row.get("snapshot_time") or "") for row in material_rows if str(row.get("snapshot_time") or "").strip()}
            ),
            "_selected_pairs": [
                [customer_center_id, snapshot_time]
                for customer_center_id, snapshot_time in sorted(self._snapshot_pairs_from_rows(material_rows))
            ],
            "_material_context_ready": bool(effective_context_ready),
        }
        if all_customer_centers:
            payload["customer_center_count"] = len(
                {str(row.get("customer_center_id") or "").strip() for row in material_rows if str(row.get("customer_center_id") or "").strip()}
            )
        return payload

    def _material_rankings_from_profile_library(
        self,
        conn: Any,
        start_dt: datetime,
        end_dt: datetime,
        *,
        tz_name: str,
        range_key: str,
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
    ) -> dict[str, Any] | None:
        profile_rows = self._material_profile_rows_for_window(
            conn,
            start_dt,
            end_dt,
            tz_name=tz_name,
            range_key=range_key,
            allowed_advertiser_ids=allowed_advertiser_ids,
            all_customer_centers=all_customer_centers,
        )
        if not profile_rows:
            return None
        latest_snapshot_time = max(
            (str(row.get("updated_at") or "") for row in profile_rows if str(row.get("updated_at") or "").strip()),
            default="",
        )
        create_time_fallback = any(bool(row.get("_create_time_fallback")) for row in profile_rows)
        missing_create_time_count = sum(
            1
            for row in profile_rows
            if not self._normalize_datetime_text(row.get("create_time"))
        )
        seeded_rows = [
            self._material_profile_seed_row(
                row,
                snapshot_time=latest_snapshot_time,
                window_start=start_dt.strftime("%Y-%m-%d %H:%M:%S"),
                window_end=end_dt.strftime("%Y-%m-%d %H:%M:%S"),
            )
            for row in profile_rows
        ]
        payload = self._build_material_payload_from_rows(
            conn,
            seeded_rows,
            latest_snapshot_time=latest_snapshot_time,
            all_customer_centers=all_customer_centers,
            meta_rows=profile_rows,
            query_context_ready=False,
        )
        if create_time_fallback:
            meta = dict(payload.get("meta") or {})
            meta["create_time_fallback"] = True
            meta["create_time_missing_count"] = int(missing_create_time_count)
            payload["meta"] = meta
        return payload

    def _material_library_page_payload(
        self,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        *,
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
    ) -> dict[str, Any]:
        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")
        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if normalized == "custom":
            start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
        elif normalized == "all":
            start_dt, end_dt, range_label = build_all_material_window(tz_name)
        else:
            start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)
        tz = ZoneInfo(str(tz_name or TIMEZONE))
        start_text = start_dt.astimezone(tz).strftime("%Y-%m-%d %H:%M:%S")
        end_text = end_dt.astimezone(tz).strftime("%Y-%m-%d %H:%M:%S")
        include_missing = normalized == "all"
        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, 20)
        offset = max(normalized_page - 1, 0) * normalized_page_size
        normalized_sort_dir = self._query_sort_dir(sort_dir)
        normalized_sort_key = str(sort_key or "").strip() or "create_time"
        sort_expr_by_key = {
            "create_time": "effective_create_time",
            "material_name": "LOWER(COALESCE(material_name, ''))",
            "material_type": "LOWER(COALESCE(material_type, ''))",
            "top_account_name": "LOWER(COALESCE(top_account_name, ''))",
            "top_plan_name": "LOWER(COALESCE(top_plan_name, ''))",
            "top_anchor_name": "LOWER(COALESCE(top_anchor_name, ''))",
            "plan_count": "plan_count",
            "advertiser_count": "advertiser_count",
            "updated_at": "updated_at",
        }
        sort_expr = sort_expr_by_key.get(normalized_sort_key)
        if not sort_expr:
            normalized_sort_key = "create_time"
            sort_expr = sort_expr_by_key[normalized_sort_key]
        customer_filter = "COALESCE(mp.customer_center_id, '') <> ''" if all_customer_centers else "mp.customer_center_id = ?"
        params: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        allowed = None if allowed_advertiser_ids is None else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
        if allowed_advertiser_ids is not None and not allowed:
            return {
                "snapshot_time": "",
                "items": [],
                "meta": self._material_meta_from_rows([], "", material_count=0),
                "snapshot_count": 0,
                "range_key": normalized,
                "range_label": range_label,
                "material_mode": MATERIAL_VIEW_LIBRARY,
                "query_start_date": start_dt.strftime("%Y-%m-%d"),
                "query_end_date": end_dt.strftime("%Y-%m-%d"),
                "materials_aggregate": self._material_aggregate_row([], material_mode=MATERIAL_VIEW_LIBRARY),
                "pagination": {
                    "page": normalized_page,
                    "page_size": normalized_page_size,
                    "total": 0,
                    "total_pages": 1,
                    "sort_key": normalized_sort_key,
                    "sort_dir": normalized_sort_dir,
                    "search": str(search or "").strip(),
                },
                "freshness": self._build_freshness_payload(source="material_profile_library_page"),
            }
        filter_clauses = [customer_filter]
        if not include_missing:
            filter_clauses.append("effective_create_time >= ?")
            filter_clauses.append("effective_create_time <= ?")
            params.extend([start_text, end_text])
        if allowed:
            filter_clauses.append(
                f"""
                EXISTS (
                    SELECT 1
                    FROM jsonb_array_elements_text(COALESCE(NULLIF(advertiser_ids_json, ''), '[]')::jsonb) AS adv(value)
                    WHERE CAST(adv.value AS BIGINT) IN ({','.join('?' for _ in allowed)})
                )
                """
            )
            params.extend(allowed)
        search_text = self._query_text(search)
        if search_text:
            escaped = search_text.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
            like_value = f"%{escaped}%"
            filter_clauses.append(
                """
                LOWER(CONCAT_WS(
                    ' ',
                    COALESCE(material_key, ''),
                    COALESCE(material_id, ''),
                    COALESCE(backend_material_name, ''),
                    COALESCE(material_name, ''),
                    COALESCE(publish_title, ''),
                    COALESCE(video_id, ''),
                    COALESCE(product_info_text, ''),
                    COALESCE(top_anchor_name, ''),
                    COALESCE(top_plan_name, ''),
                    COALESCE(top_account_name, ''),
                    COALESCE(aweme_item_id, ''),
                    COALESCE(material_type, ''),
                    COALESCE(product_names_json, '')
                )) LIKE ? ESCAPE '\\'
                """
            )
            params.append(like_value)
        first_seen_scope = "COALESCE(customer_center_id, '') <> ''" if all_customer_centers else "customer_center_id = ?"
        first_seen_params: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        filtered_clauses = (
            filter_clauses[1:]
            if filter_clauses and filter_clauses[0] == customer_filter
            else filter_clauses
        )
        filtered_where_sql = " AND ".join(filtered_clauses) or "1=1"
        base_cte = f"""
            WITH first_seen AS (
                SELECT customer_center_id, material_key, MIN(NULLIF(first_seen_at, '')) AS first_seen_at
                FROM material_relation_edges
                WHERE {first_seen_scope}
                GROUP BY customer_center_id, material_key
            ),
            source AS (
                SELECT
                    mp.customer_center_id,
                    mp.material_key,
                    mp.material_id,
                    mp.material_name,
                    mp.backend_material_name,
                    mp.publish_title,
                    mp.creative_title_material_ids_json,
                    mp.creative_source,
                    COALESCE(NULLIF(mp.create_time, ''), first_seen.first_seen_at, '') AS effective_create_time,
                    mp.create_time AS stored_create_time,
                    first_seen.first_seen_at,
                    mp.material_type,
                    mp.video_id,
                    mp.cover_url,
                    mp.aweme_item_id,
                    mp.video_url,
                    mp.is_original,
                    mp.top_plan_name,
                    mp.top_account_name,
                    mp.top_anchor_name,
                    mp.product_info_text,
                    mp.product_names_json,
                    COALESCE(NULLIF(mp.plan_ids_json, ''), '[]') AS plan_ids_json,
                    COALESCE(NULLIF(mp.advertiser_ids_json, ''), '[]') AS advertiser_ids_json,
                    CAST(COALESCE(mp.plan_count, 0) AS INTEGER) AS plan_count,
                    CAST(COALESCE(mp.advertiser_count, 0) AS INTEGER) AS advertiser_count,
                    COALESCE(NULLIF(mp.updated_at, ''), '') AS updated_at,
                    CASE WHEN COALESCE(mp.create_time, '') = '' AND COALESCE(first_seen.first_seen_at, '') <> '' THEN 1 ELSE 0 END AS create_time_fallback
                FROM material_profile mp
                LEFT JOIN first_seen
                  ON first_seen.customer_center_id = mp.customer_center_id
                 AND first_seen.material_key = mp.material_key
                WHERE {customer_filter}
            ),
            filtered AS (
                SELECT *
                FROM source
                WHERE {filtered_where_sql}
            )
        """
        summary_params = [*first_seen_params, *params]
        page_params = [*first_seen_params, *params, normalized_page_size, offset]
        order_sql = f"{sort_expr} {normalized_sort_dir.upper()} NULLS LAST, material_key ASC"
        with self.db() as conn:
            summary_row = dict(
                conn.execute(
                    f"""
                    {base_cte},
                    material_plan_ids AS (
                        SELECT DISTINCT CAST(plan_item.value AS BIGINT) AS plan_id
                        FROM filtered
                        CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(NULLIF(plan_ids_json, ''), '[]')::jsonb) AS plan_item(value)
                    ),
                    material_advertiser_ids AS (
                        SELECT DISTINCT CAST(adv_item.value AS BIGINT) AS advertiser_id
                        FROM filtered
                        CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(NULLIF(advertiser_ids_json, ''), '[]')::jsonb) AS adv_item(value)
                    )
                    SELECT
                        COUNT(*) AS total_count,
                        COALESCE(MAX(updated_at), '') AS latest_snapshot_time,
                        COALESCE((SELECT COUNT(DISTINCT plan_id) FROM material_plan_ids), 0) AS aggregate_plan_count,
                        COALESCE((SELECT COUNT(DISTINCT advertiser_id) FROM material_advertiser_ids), 0) AS aggregate_advertiser_count,
                        COALESCE(SUM(CASE WHEN COALESCE(effective_create_time, '') = '' THEN 1 ELSE 0 END), 0) AS create_time_missing_count,
                        COALESCE(SUM(create_time_fallback), 0) AS create_time_fallback_count
                    FROM filtered
                    """,
                    summary_params,
                ).fetchone()
                or {}
            )
            total_count = int(summary_row.get("total_count", 0) or 0)
            page_rows = [
                dict(row)
                for row in conn.execute(
                    f"""
                    {base_cte}
                    SELECT *
                    FROM filtered
                    ORDER BY {order_sql}
                    LIMIT ? OFFSET ?
                    """,
                    page_params,
                ).fetchall()
            ]
            latest_snapshot_time = str(summary_row.get("latest_snapshot_time") or "")
            seeded_rows = [
                self._material_profile_seed_row(
                    {
                        **row,
                        "create_time": row.get("effective_create_time") or "",
                        "_create_time_fallback": bool(row.get("create_time_fallback")),
                    },
                    snapshot_time=latest_snapshot_time,
                    window_start=start_dt.strftime("%Y-%m-%d %H:%M:%S"),
                    window_end=end_dt.strftime("%Y-%m-%d %H:%M:%S"),
                )
                for row in page_rows
            ]
            page_items = self._aggregate_material_rollups(seeded_rows)
            if page_items:
                page_items = self._apply_material_relation_context(conn, page_items)
                page_items = self._apply_latest_material_previews(conn, page_items)
            page_items = self._sanitize_material_preview_fields_for_payload(page_items)
        total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
        pagination = {
            "page": min(normalized_page, total_pages),
            "page_size": normalized_page_size,
            "total": total_count,
            "total_pages": total_pages,
            "sort_key": normalized_sort_key,
            "sort_dir": normalized_sort_dir,
            "search": str(search or "").strip(),
        }
        materials_aggregate = {
            "material_mode": MATERIAL_VIEW_LIBRARY,
            "material_count": total_count,
            "stat_cost": 0.0,
            "pay_amount": 0.0,
            "total_pay_amount": 0.0,
            "settled_pay_amount": 0.0,
            "order_count": 0,
            "settled_order_count": 0,
            "overall_show_count": 0,
            "overall_click_count": 0,
            "overall_ctr": 0.0,
            "roi": 0.0,
            "settled_roi": 0.0,
            "plan_count": int(summary_row.get("aggregate_plan_count", 0) or 0),
            "advertiser_count": int(summary_row.get("aggregate_advertiser_count", 0) or 0),
            "summary_text": f"共 {total_count} 条素材资产",
        }
        meta = self._material_meta_from_rows(page_items, latest_snapshot_time, material_count=total_count)
        if int(summary_row.get("create_time_fallback_count", 0) or 0) > 0:
            meta["create_time_fallback"] = True
        meta["create_time_missing_count"] = int(summary_row.get("create_time_missing_count", 0) or 0)
        payload = {
            "snapshot_time": latest_snapshot_time,
            "items": page_items,
            "meta": meta,
            "snapshot_count": 1 if latest_snapshot_time else 0,
            "range_key": normalized,
            "range_label": range_label,
            "material_mode": MATERIAL_VIEW_LIBRARY,
            "query_start_date": start_dt.strftime("%Y-%m-%d"),
            "query_end_date": end_dt.strftime("%Y-%m-%d"),
            "metrics_semantics": {
                "money_scope": "material_profile_library",
                "reconcilable_to_account_summary": False,
                "notice": "资产库口径用于素材档案展示，不承诺与账户总表核平。",
            },
            "materialTodayStatus": self._material_today_hot_status(all_customer_centers=all_customer_centers),
            "materials_aggregate": materials_aggregate,
            "pagination": pagination,
        }
        return self._attach_freshness(
            payload,
            data_time=latest_snapshot_time,
            synced_at=latest_snapshot_time,
            source="material_profile_library_page",
        )

    def _material_relation_rows_for_exact_snapshot(
        self,
        conn: Any,
        snapshot_time: str,
        *,
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
    ) -> list[dict[str, Any]]:
        normalized_snapshot = str(snapshot_time or "").strip()
        if not normalized_snapshot:
            return []
        where_prefix = "ms.snapshot_time = ? AND COALESCE(ms.customer_center_id, '') <> ''" if all_customer_centers else "ms.snapshot_time = ? AND ms.customer_center_id = ?"
        params: list[Any] = [normalized_snapshot]
        if not all_customer_centers:
            params.append(self._current_customer_center_id())
        allowed = None if allowed_advertiser_ids is None else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
        if allowed_advertiser_ids is not None and not allowed:
            return []
        allowed_clause = ""
        if allowed:
            allowed_clause = f" AND ms.advertiser_id IN ({','.join('?' for _ in allowed)})"
            params.extend(allowed)
        read_model_current_params: list[Any] = [normalized_snapshot]
        read_model_current_where = ["mrc.snapshot_time = ?"]
        if all_customer_centers:
            read_model_current_where.append("COALESCE(mrc.customer_center_id, '') <> ''")
        else:
            read_model_current_where.append("mrc.customer_center_id = ?")
            read_model_current_params.append(self._current_customer_center_id())
        if allowed:
            read_model_current_where.append(f"mrc.advertiser_id IN ({','.join('?' for _ in allowed)})")
            read_model_current_params.extend(allowed)
        read_model_daily_params: list[Any] = [normalized_snapshot]
        read_model_daily_where = ["mrd.snapshot_time = ?"]
        read_model_daily_where.append(
            self._material_history_stable_day_sql(
                day_expr="substr(mrd.snapshot_time, 1, 10)",
                customer_center_expr="mrd.customer_center_id",
            )
        )
        if all_customer_centers:
            read_model_daily_where.append("COALESCE(mrd.customer_center_id, '') <> ''")
        else:
            read_model_daily_where.append("mrd.customer_center_id = ?")
            read_model_daily_params.append(self._current_customer_center_id())
        if allowed:
            read_model_daily_where.append(f"mrd.advertiser_id IN ({','.join('?' for _ in allowed)})")
            read_model_daily_params.extend(allowed)
        read_model_rows = conn.execute(
            f"""
            WITH exact_rows AS (
                SELECT
                    mrc.customer_center_id,
                    mrc.snapshot_time,
                    mrc.advertiser_id,
                    mrc.advertiser_name,
                    mrc.ad_id,
                    mrc.ad_name,
                    mrc.material_type,
                    mrc.material_key,
                    mrc.material_id,
                    mrc.material_name,
                    mrc.backend_material_name,
                    mrc.create_time,
                    mrc.video_id,
                    mrc.cover_url,
                    mrc.aweme_item_id,
                    mrc.video_url,
                    mrc.stat_cost,
                    mrc.pay_amount,
                    mrc.total_pay_amount,
                    mrc.settled_pay_amount,
                    mrc.order_count,
                    mrc.settled_order_count,
                    mrc.overall_show_count,
                    mrc.overall_click_count,
                    mrc.top_anchor_name,
                    mrc.product_info_text,
                    mrc.is_original
                FROM material_relation_current mrc
                WHERE {' AND '.join(read_model_current_where)}
                UNION ALL
                SELECT
                    mrd.customer_center_id,
                    mrd.snapshot_time,
                    mrd.advertiser_id,
                    mrd.advertiser_name,
                    mrd.ad_id,
                    mrd.ad_name,
                    mrd.material_type,
                    mrd.material_key,
                    mrd.material_id,
                    mrd.material_name,
                    mrd.backend_material_name,
                    mrd.create_time,
                    mrd.video_id,
                    mrd.cover_url,
                    mrd.aweme_item_id,
                    mrd.video_url,
                    mrd.stat_cost,
                    mrd.pay_amount,
                    mrd.total_pay_amount,
                    mrd.settled_pay_amount,
                    mrd.order_count,
                    mrd.settled_order_count,
                    mrd.overall_show_count,
                    mrd.overall_click_count,
                    mrd.top_anchor_name,
                    mrd.product_info_text,
                    mrd.is_original
                FROM material_relation_daily mrd
                WHERE {' AND '.join(read_model_daily_where)}
            )
            SELECT
                mr.customer_center_id,
                mr.snapshot_time,
                mr.advertiser_id,
                COALESCE(NULLIF(mr.advertiser_name, ''), '') AS advertiser_name,
                mr.ad_id,
                COALESCE(NULLIF(mr.ad_name, ''), '') AS ad_name,
                mr.material_type,
                mr.material_key,
                COALESCE(NULLIF(mr.material_id, ''), NULLIF(mp.material_id, ''), '') AS material_id,
                CASE
                    WHEN mr.material_type = 'UNATTRIBUTED_DELETED' THEN '未归因关闭/暂停计划消耗'
                    ELSE COALESCE(NULLIF(mr.backend_material_name, ''), NULLIF(mp.backend_material_name, ''), NULLIF(mr.material_name, ''), NULLIF(mp.material_name, ''), '未命名素材')
                END AS material_name,
                COALESCE(NULLIF(mp.create_time, ''), NULLIF(mr.create_time, ''), '') AS create_time,
                COALESCE(NULLIF(mp.video_id, ''), NULLIF(mr.video_id, ''), '') AS video_id,
                COALESCE(NULLIF(mp.cover_url, ''), NULLIF(mr.cover_url, ''), '') AS cover_url,
                COALESCE(NULLIF(mp.aweme_item_id, ''), NULLIF(mr.aweme_item_id, ''), '') AS aweme_item_id,
                COALESCE(NULLIF(mp.video_url, ''), NULLIF(mr.video_url, ''), '') AS video_url,
                CAST(ROUND(COALESCE(mr.stat_cost, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                CAST(ROUND(COALESCE(mr.pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                CAST(ROUND(COALESCE(mr.total_pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                CAST(ROUND(COALESCE(mr.settled_pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                CAST(COALESCE(mr.order_count, 0) AS INTEGER) AS order_count,
                CAST(COALESCE(mr.settled_order_count, 0) AS INTEGER) AS settled_order_count,
                CAST(COALESCE(mr.overall_show_count, 0) AS INTEGER) AS overall_show_count,
                CAST(COALESCE(mr.overall_click_count, 0) AS INTEGER) AS overall_click_count,
                COALESCE(NULLIF(mr.product_info_text, ''), NULLIF(mp.product_info_text, ''), '') AS product_info_text,
                COALESCE(NULLIF(mr.top_anchor_name, ''), NULLIF(mp.top_anchor_name, ''), '') AS top_anchor_name,
                COALESCE(mre.first_seen_at, '') AS first_seen_at,
                COALESCE(mre.last_seen_at, '') AS last_seen_at,
                COALESCE(mre.last_snapshot_time, '') AS last_snapshot_time,
                CAST(COALESCE(mre.seen_count, 0) AS INTEGER) AS seen_count,
                CAST(COALESCE(mp.is_original, mr.is_original, 0) AS INTEGER) AS is_original,
                1 AS active_day_count
            FROM exact_rows mr
            LEFT JOIN material_profile mp
              ON mp.customer_center_id = mr.customer_center_id
             AND mp.material_key = mr.material_key
            LEFT JOIN material_relation_edges mre
              ON mre.customer_center_id = mr.customer_center_id
             AND mre.material_key = mr.material_key
             AND mre.advertiser_id = mr.advertiser_id
             AND mre.ad_id = mr.ad_id
            ORDER BY mr.stat_cost DESC, mr.pay_amount DESC, mr.order_count DESC, mr.material_key ASC
            """,
            [*read_model_current_params, *read_model_daily_params],
        ).fetchall()
        if read_model_rows:
            return [dict(row) for row in read_model_rows]
        rows = conn.execute(
            f"""
            SELECT
                ms.customer_center_id,
                ms.snapshot_time,
                ms.advertiser_id,
                COALESCE(NULLIF(ms.advertiser_name, ''), '') AS advertiser_name,
                ms.ad_id,
                COALESCE(NULLIF(ms.ad_name, ''), '') AS ad_name,
                ms.material_type,
                ms.material_key,
                COALESCE(NULLIF(ms.material_id, ''), NULLIF(mp.material_id, ''), '') AS material_id,
                CASE
                    WHEN ms.material_type = 'UNATTRIBUTED_DELETED' THEN '未归因关闭/暂停计划消耗'
                    ELSE COALESCE(NULLIF(ms.backend_material_name, ''), NULLIF(mp.backend_material_name, ''), NULLIF(ms.material_name, ''), NULLIF(mp.material_name, ''), '未命名素材')
                END AS material_name,
                COALESCE(NULLIF(mp.create_time, ''), NULLIF(ms.create_time, ''), '') AS create_time,
                COALESCE(NULLIF(mp.video_id, ''), NULLIF(ms.video_id, ''), '') AS video_id,
                COALESCE(NULLIF(mp.cover_url, ''), NULLIF(ms.cover_url, ''), '') AS cover_url,
                COALESCE(NULLIF(mp.aweme_item_id, ''), NULLIF(ms.aweme_item_id, ''), '') AS aweme_item_id,
                COALESCE(NULLIF(mp.video_url, ''), NULLIF(ms.video_url, ''), '') AS video_url,
                CAST(ROUND(COALESCE(ms.stat_cost, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                CAST(ROUND(COALESCE(ms.pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                CAST(ROUND(COALESCE(ms.total_pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                CAST(ROUND(COALESCE(ms.settled_pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                CAST(COALESCE(ms.order_count, 0) AS INTEGER) AS order_count,
                CAST(COALESCE(ms.settled_order_count, 0) AS INTEGER) AS settled_order_count,
                CAST(COALESCE(ms.product_show_count, 0) AS INTEGER) AS overall_show_count,
                CAST(COALESCE(ms.product_click_count, 0) AS INTEGER) AS overall_click_count,
                COALESCE(NULLIF(mp.product_info_text, ''), '') AS product_info_text,
                COALESCE(NULLIF(mp.top_anchor_name, ''), '') AS top_anchor_name,
                COALESCE(mre.first_seen_at, '') AS first_seen_at,
                COALESCE(mre.last_seen_at, '') AS last_seen_at,
                COALESCE(mre.last_snapshot_time, '') AS last_snapshot_time,
                CAST(COALESCE(mre.seen_count, 0) AS INTEGER) AS seen_count,
                CAST(COALESCE(mp.is_original, 0) AS INTEGER) AS is_original,
                1 AS active_day_count
            FROM material_snapshots ms
            LEFT JOIN material_profile mp
              ON mp.customer_center_id = ms.customer_center_id
             AND mp.material_key = ms.material_key
            LEFT JOIN material_relation_edges mre
              ON mre.customer_center_id = ms.customer_center_id
             AND mre.material_key = ms.material_key
             AND mre.advertiser_id = ms.advertiser_id
             AND mre.ad_id = ms.ad_id
            WHERE {where_prefix}{allowed_clause}
            ORDER BY ms.stat_cost DESC, ms.pay_amount DESC, ms.order_count DESC, ms.material_key ASC
            """,
            params,
        ).fetchall()
        return [dict(row) for row in rows]

    def _material_relation_rows_for_window(
        self,
        conn: Any,
        start_dt: datetime,
        end_dt: datetime,
        *,
        tz_name: str,
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
    ) -> list[dict[str, Any]]:
        tz = ZoneInfo(str(tz_name or TIMEZONE))
        start_day = start_dt.astimezone(tz).strftime("%Y-%m-%d")
        end_day = end_dt.astimezone(tz).strftime("%Y-%m-%d")
        latest_where = "COALESCE(customer_center_id, '') <> ''" if all_customer_centers else "customer_center_id = ?"
        params: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        params.extend([start_day, end_day])
        allowed = None if allowed_advertiser_ids is None else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
        if allowed_advertiser_ids is not None and not allowed:
            return []
        allowed_clause = ""
        if allowed:
            allowed_clause = f" AND ms.advertiser_id IN ({','.join('?' for _ in allowed)})"
            params.extend(allowed)
        today_key = datetime.now(tz).strftime("%Y-%m-%d")
        read_model_queries: list[str] = []
        read_model_params: list[Any] = []
        daily_end_day = min(end_day, (datetime.strptime(today_key, "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d"))
        if start_day <= daily_end_day:
            daily_where = ["mrd.biz_date >= ?", "mrd.biz_date <= ?"]
            read_model_params.extend([start_day, daily_end_day])
            daily_where.append(
                self._material_history_stable_day_sql(
                    day_expr="mrd.biz_date",
                    customer_center_expr="mrd.customer_center_id",
                )
            )
            if all_customer_centers:
                daily_where.append("COALESCE(mrd.customer_center_id, '') <> ''")
            else:
                daily_where.append("mrd.customer_center_id = ?")
                read_model_params.append(self._current_customer_center_id())
            if allowed:
                daily_where.append(f"mrd.advertiser_id IN ({','.join('?' for _ in allowed)})")
                read_model_params.extend(allowed)
            read_model_queries.append(
                f"""
                SELECT
                    mrd.customer_center_id,
                    mrd.snapshot_time,
                    mrd.biz_date AS source_day,
                    mrd.advertiser_id,
                    mrd.advertiser_name,
                    mrd.ad_id,
                    mrd.ad_name,
                    mrd.material_type,
                    mrd.material_key,
                    mrd.material_id,
                    mrd.material_name,
                    mrd.backend_material_name,
                    mrd.create_time,
                    mrd.video_id,
                    mrd.cover_url,
                    mrd.aweme_item_id,
                    mrd.video_url,
                    mrd.stat_cost,
                    mrd.pay_amount,
                    mrd.total_pay_amount,
                    mrd.settled_pay_amount,
                    mrd.order_count,
                    mrd.settled_order_count,
                    mrd.overall_show_count,
                    mrd.overall_click_count,
                    mrd.top_anchor_name,
                    mrd.product_info_text,
                    mrd.is_original
                FROM material_relation_daily mrd
                WHERE {' AND '.join(daily_where)}
                """
            )
        if end_day >= today_key:
            current_where = []
            if all_customer_centers:
                current_where.append("COALESCE(mrc.customer_center_id, '') <> ''")
            else:
                current_where.append("mrc.customer_center_id = ?")
                read_model_params.append(self._current_customer_center_id())
            if allowed:
                current_where.append(f"mrc.advertiser_id IN ({','.join('?' for _ in allowed)})")
                read_model_params.extend(allowed)
            read_model_queries.append(
                f"""
                SELECT
                    mrc.customer_center_id,
                    mrc.snapshot_time,
                    substr(mrc.snapshot_time, 1, 10) AS source_day,
                    mrc.advertiser_id,
                    mrc.advertiser_name,
                    mrc.ad_id,
                    mrc.ad_name,
                    mrc.material_type,
                    mrc.material_key,
                    mrc.material_id,
                    mrc.material_name,
                    mrc.backend_material_name,
                    mrc.create_time,
                    mrc.video_id,
                    mrc.cover_url,
                    mrc.aweme_item_id,
                    mrc.video_url,
                    mrc.stat_cost,
                    mrc.pay_amount,
                    mrc.total_pay_amount,
                    mrc.settled_pay_amount,
                    mrc.order_count,
                    mrc.settled_order_count,
                    mrc.overall_show_count,
                    mrc.overall_click_count,
                    mrc.top_anchor_name,
                    mrc.product_info_text,
                    mrc.is_original
                FROM material_relation_current mrc
                WHERE {' AND '.join(current_where) if current_where else '1 = 1'}
                """
            )
        if read_model_queries:
            read_model_rows = conn.execute(
                f"""
                WITH source AS (
                    {' UNION ALL '.join(read_model_queries)}
                ),
                metrics AS (
                    SELECT
                        customer_center_id,
                        advertiser_id,
                        ad_id,
                        material_type,
                        material_key,
                        MAX(snapshot_time) AS snapshot_time,
                        CAST(ROUND(SUM(COALESCE(stat_cost, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                        CAST(ROUND(SUM(COALESCE(pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                        CAST(ROUND(SUM(COALESCE(total_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                        CAST(ROUND(SUM(COALESCE(settled_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                        CAST(SUM(COALESCE(order_count, 0)) AS INTEGER) AS order_count,
                        CAST(SUM(COALESCE(settled_order_count, 0)) AS INTEGER) AS settled_order_count,
                        CAST(SUM(COALESCE(overall_show_count, 0)) AS INTEGER) AS overall_show_count,
                        CAST(SUM(COALESCE(overall_click_count, 0)) AS INTEGER) AS overall_click_count,
                        COUNT(*) AS active_day_count
                    FROM source
                    GROUP BY customer_center_id, advertiser_id, ad_id, material_type, material_key
                )
                SELECT
                    metrics.customer_center_id,
                    metrics.snapshot_time,
                    latest_row.advertiser_id,
                    COALESCE(NULLIF(latest_row.advertiser_name, ''), '') AS advertiser_name,
                    latest_row.ad_id,
                    COALESCE(NULLIF(latest_row.ad_name, ''), '') AS ad_name,
                    latest_row.material_type,
                    latest_row.material_key,
                    COALESCE(NULLIF(latest_row.material_id, ''), NULLIF(mp.material_id, ''), '') AS material_id,
                    CASE
                        WHEN latest_row.material_type = 'UNATTRIBUTED_DELETED' THEN '未归因关闭/暂停计划消耗'
                        ELSE COALESCE(NULLIF(latest_row.backend_material_name, ''), NULLIF(mp.backend_material_name, ''), NULLIF(latest_row.material_name, ''), NULLIF(mp.material_name, ''), '未命名素材')
                    END AS material_name,
                    COALESCE(NULLIF(mp.create_time, ''), NULLIF(latest_row.create_time, ''), '') AS create_time,
                    COALESCE(NULLIF(mp.video_id, ''), NULLIF(latest_row.video_id, ''), '') AS video_id,
                    COALESCE(NULLIF(mp.cover_url, ''), NULLIF(latest_row.cover_url, ''), '') AS cover_url,
                    COALESCE(NULLIF(mp.aweme_item_id, ''), NULLIF(latest_row.aweme_item_id, ''), '') AS aweme_item_id,
                    COALESCE(NULLIF(mp.video_url, ''), NULLIF(latest_row.video_url, ''), '') AS video_url,
                    metrics.stat_cost,
                    metrics.pay_amount,
                    metrics.total_pay_amount,
                    metrics.settled_pay_amount,
                    metrics.order_count,
                    metrics.settled_order_count,
                    metrics.overall_show_count,
                    metrics.overall_click_count,
                    COALESCE(NULLIF(latest_row.product_info_text, ''), NULLIF(mp.product_info_text, ''), '') AS product_info_text,
                    COALESCE(NULLIF(latest_row.top_anchor_name, ''), NULLIF(mp.top_anchor_name, ''), '') AS top_anchor_name,
                    COALESCE(mre.first_seen_at, '') AS first_seen_at,
                    COALESCE(mre.last_seen_at, '') AS last_seen_at,
                    COALESCE(mre.last_snapshot_time, '') AS last_snapshot_time,
                    CAST(COALESCE(mre.seen_count, 0) AS INTEGER) AS seen_count,
                    CAST(COALESCE(mp.is_original, latest_row.is_original, 0) AS INTEGER) AS is_original,
                    CAST(metrics.active_day_count AS INTEGER) AS active_day_count
                FROM metrics
                INNER JOIN source AS latest_row
                  ON latest_row.customer_center_id = metrics.customer_center_id
                 AND latest_row.advertiser_id = metrics.advertiser_id
                 AND latest_row.ad_id = metrics.ad_id
                 AND latest_row.material_type = metrics.material_type
                 AND latest_row.material_key = metrics.material_key
                 AND latest_row.snapshot_time = metrics.snapshot_time
                LEFT JOIN material_profile mp
                  ON mp.customer_center_id = metrics.customer_center_id
                 AND mp.material_key = metrics.material_key
                LEFT JOIN material_relation_edges mre
                  ON mre.customer_center_id = metrics.customer_center_id
                 AND mre.material_key = metrics.material_key
                 AND mre.advertiser_id = metrics.advertiser_id
                 AND mre.ad_id = metrics.ad_id
                ORDER BY metrics.stat_cost DESC, metrics.pay_amount DESC, metrics.order_count DESC, latest_row.material_key ASC
                """,
                read_model_params,
            ).fetchall()
            if read_model_rows:
                return [dict(row) for row in read_model_rows]
        rows = conn.execute(
            f"""
            WITH latest_per_day AS (
                SELECT
                    customer_center_id,
                    substr(snapshot_time, 1, 10) AS biz_date,
                    MAX(snapshot_time) AS snapshot_time
                FROM material_snapshots
                WHERE {latest_where}
                  AND {self._material_history_stable_day_sql(
                      day_expr='substr(snapshot_time, 1, 10)',
                      customer_center_expr='customer_center_id',
                  )}
                  AND substr(snapshot_time, 1, 10) >= ?
                  AND substr(snapshot_time, 1, 10) <= ?
                GROUP BY customer_center_id, substr(snapshot_time, 1, 10)
            ),
            scoped AS (
                SELECT ms.*
                FROM material_snapshots ms
                INNER JOIN latest_per_day lp
                  ON lp.customer_center_id = ms.customer_center_id
                 AND lp.snapshot_time = ms.snapshot_time
                WHERE 1 = 1{allowed_clause}
            ),
            metrics AS (
                SELECT
                    customer_center_id,
                    advertiser_id,
                    ad_id,
                    material_type,
                    material_key,
                    MAX(snapshot_time) AS snapshot_time,
                    CAST(ROUND(SUM(COALESCE(stat_cost, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                    CAST(ROUND(SUM(COALESCE(pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                    CAST(ROUND(SUM(COALESCE(total_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                    CAST(ROUND(SUM(COALESCE(settled_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                    CAST(SUM(COALESCE(order_count, 0)) AS INTEGER) AS order_count,
                    CAST(SUM(COALESCE(settled_order_count, 0)) AS INTEGER) AS settled_order_count,
                    CAST(SUM(COALESCE(product_show_count, 0)) AS INTEGER) AS overall_show_count,
                    CAST(SUM(COALESCE(product_click_count, 0)) AS INTEGER) AS overall_click_count,
                    COUNT(*) AS active_day_count
                FROM scoped
                GROUP BY customer_center_id, advertiser_id, ad_id, material_type, material_key
            )
            SELECT
                metrics.customer_center_id,
                metrics.snapshot_time,
                latest_row.advertiser_id,
                COALESCE(NULLIF(latest_row.advertiser_name, ''), '') AS advertiser_name,
                latest_row.ad_id,
                COALESCE(NULLIF(latest_row.ad_name, ''), '') AS ad_name,
                latest_row.material_type,
                latest_row.material_key,
                COALESCE(NULLIF(latest_row.material_id, ''), NULLIF(mp.material_id, ''), '') AS material_id,
                CASE
                    WHEN latest_row.material_type = 'UNATTRIBUTED_DELETED' THEN '未归因关闭/暂停计划消耗'
                        ELSE COALESCE(NULLIF(latest_row.backend_material_name, ''), NULLIF(mp.backend_material_name, ''), NULLIF(latest_row.material_name, ''), NULLIF(mp.material_name, ''), '未命名素材')
                END AS material_name,
                COALESCE(NULLIF(mp.create_time, ''), NULLIF(latest_row.create_time, ''), '') AS create_time,
                COALESCE(NULLIF(mp.video_id, ''), NULLIF(latest_row.video_id, ''), '') AS video_id,
                COALESCE(NULLIF(mp.cover_url, ''), NULLIF(latest_row.cover_url, ''), '') AS cover_url,
                COALESCE(NULLIF(mp.aweme_item_id, ''), NULLIF(latest_row.aweme_item_id, ''), '') AS aweme_item_id,
                COALESCE(NULLIF(mp.video_url, ''), NULLIF(latest_row.video_url, ''), '') AS video_url,
                metrics.stat_cost,
                metrics.pay_amount,
                metrics.total_pay_amount,
                metrics.settled_pay_amount,
                metrics.order_count,
                metrics.settled_order_count,
                metrics.overall_show_count,
                metrics.overall_click_count,
                COALESCE(NULLIF(mp.product_info_text, ''), '') AS product_info_text,
                COALESCE(NULLIF(mp.top_anchor_name, ''), '') AS top_anchor_name,
                COALESCE(mre.first_seen_at, '') AS first_seen_at,
                COALESCE(mre.last_seen_at, '') AS last_seen_at,
                COALESCE(mre.last_snapshot_time, '') AS last_snapshot_time,
                CAST(COALESCE(mre.seen_count, 0) AS INTEGER) AS seen_count,
                CAST(COALESCE(mp.is_original, 0) AS INTEGER) AS is_original,
                CAST(metrics.active_day_count AS INTEGER) AS active_day_count
            FROM metrics
            INNER JOIN scoped AS latest_row
              ON latest_row.customer_center_id = metrics.customer_center_id
             AND latest_row.advertiser_id = metrics.advertiser_id
             AND latest_row.ad_id = metrics.ad_id
             AND latest_row.material_type = metrics.material_type
             AND latest_row.material_key = metrics.material_key
             AND latest_row.snapshot_time = metrics.snapshot_time
            LEFT JOIN material_profile mp
              ON mp.customer_center_id = metrics.customer_center_id
             AND mp.material_key = metrics.material_key
            LEFT JOIN material_relation_edges mre
              ON mre.customer_center_id = metrics.customer_center_id
             AND mre.material_key = metrics.material_key
             AND mre.advertiser_id = metrics.advertiser_id
             AND mre.ad_id = metrics.ad_id
            ORDER BY metrics.stat_cost DESC, metrics.pay_amount DESC, metrics.order_count DESC, latest_row.material_key ASC
            """,
            params,
        ).fetchall()
        return [dict(row) for row in rows]

    def _build_material_relation_payload_from_rows(
        self,
        conn: Any,
        relation_rows: list[dict[str, Any]],
        *,
        latest_snapshot_time: str,
        all_customer_centers: bool = False,
    ) -> dict[str, Any]:
        items: list[dict[str, Any]] = []
        snapshot_pairs: set[tuple[str, str]] = set()
        snapshot_dates: set[str] = set()
        customer_center_ids: set[str] = set()
        for raw_row in relation_rows:
            row = dict(raw_row)
            customer_center_id = str(row.get("customer_center_id") or "").strip()
            snapshot_time = str(row.get("snapshot_time") or "").strip()
            material_key = str(row.get("material_key") or "").strip()
            advertiser_id = int(row.get("advertiser_id", 0) or 0)
            ad_id = int(row.get("ad_id", 0) or 0)
            if not customer_center_id or not material_key or advertiser_id <= 0 or ad_id <= 0:
                continue
            stat_cost = round(float(row.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(row.get("pay_amount", 0.0) or 0.0), 2)
            total_pay_amount = round(float(row.get("total_pay_amount", 0.0) or 0.0), 2)
            settled_pay_amount = round(float(row.get("settled_pay_amount", 0.0) or 0.0), 2)
            order_count = int(row.get("order_count", 0) or 0)
            settled_order_count = int(row.get("settled_order_count", 0) or 0)
            overall_show_count = int(row.get("overall_show_count", 0) or 0)
            overall_click_count = int(row.get("overall_click_count", 0) or 0)
            item = {
                "customer_center_id": customer_center_id,
                "snapshot_time": snapshot_time,
                "material_row_key": f"{customer_center_id}:{advertiser_id}:{ad_id}:{str(row.get('material_type') or '').strip()}:{material_key}",
                "material_key": material_key,
                "material_id": str(row.get("material_id") or "").strip(),
                "material_name": self._material_display_name_value(row.get("material_type"), row.get("material_name")),
                "create_time": str(row.get("create_time") or "").strip(),
                "material_type": str(row.get("material_type") or "").strip() or "OTHER",
                "video_id": str(row.get("video_id") or "").strip(),
                "cover_url": str(row.get("cover_url") or "").strip(),
                "aweme_item_id": str(row.get("aweme_item_id") or "").strip(),
                "video_url": str(row.get("video_url") or "").strip(),
                "stat_cost": stat_cost,
                "pay_amount": pay_amount,
                "total_pay_amount": total_pay_amount,
                "settled_pay_amount": settled_pay_amount,
                "order_count": order_count,
                "settled_order_count": settled_order_count,
                "overall_show_count": overall_show_count,
                "overall_click_count": overall_click_count,
                "overall_ctr": round(overall_click_count / overall_show_count * 100.0, 2) if overall_show_count > 0 else 0.0,
                "roi": round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                "settled_roi": round(settled_pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                "pay_order_cost": round(stat_cost / order_count, 2) if order_count > 0 else 0.0,
                "settled_amount_rate": round(settled_pay_amount / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else 0.0,
                "refund_amount_1h": 0.0,
                "refund_rate_1h": None,
                "advertiser_id": advertiser_id,
                "advertiser_name": str(row.get("advertiser_name") or "").strip(),
                "ad_id": ad_id,
                "ad_name": str(row.get("ad_name") or "").strip(),
                "top_account_name": str(row.get("advertiser_name") or "").strip(),
                "top_plan_name": str(row.get("ad_name") or "").strip(),
                "top_anchor_name": str(row.get("top_anchor_name") or "").strip(),
                "product_info_text": str(row.get("product_info_text") or "").strip(),
                "plan_count": 1,
                "advertiser_count": 1,
                "plan_ids": [ad_id],
                "advertiser_ids": [advertiser_id],
                "plan_ids_json": self._json_text([ad_id]),
                "advertiser_ids_json": self._json_text([advertiser_id]),
                "first_seen_at": str(row.get("first_seen_at") or "").strip(),
                "last_seen_at": str(row.get("last_seen_at") or "").strip(),
                "last_snapshot_time": str(row.get("last_snapshot_time") or "").strip(),
                "seen_count": int(row.get("seen_count", 0) or 0),
                "active_day_count": int(row.get("active_day_count", 0) or 0),
                "is_original": bool(int(row.get("is_original", 0) or 0)),
            }
            items.append(item)
            if snapshot_time:
                snapshot_pairs.add((customer_center_id, snapshot_time))
                snapshot_dates.add(snapshot_time[:10])
            customer_center_ids.add(customer_center_id)
        payload = {
            "snapshot_time": latest_snapshot_time,
            "items": items,
            "meta": {
                "snapshot_time": latest_snapshot_time,
                "status": "ok",
                "plan_count": 0,
                "detail_count": 0,
                "product_count": 0,
                "material_count": len(items),
                "relation_count": len(items),
                "video_count": 0,
                "error_count": 0,
                "snapshot_dates": sorted(snapshot_dates),
                "snapshot_fallback_used": False,
            },
            "snapshot_count": len(snapshot_pairs),
            "_selected_pairs": [[customer_center_id, snapshot_time] for customer_center_id, snapshot_time in sorted(snapshot_pairs)],
        }
        if all_customer_centers:
            payload["customer_center_count"] = len(customer_center_ids)
        return payload

    def _material_rankings_from_current_daily(
        self,
        conn: Any,
        start_dt: datetime,
        end_dt: datetime,
        *,
        tz_name: str,
        range_key: str,
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
    ) -> dict[str, Any] | None:
        today_key = datetime.now(ZoneInfo(tz_name)).strftime("%Y-%m-%d")
        where_prefix = "COALESCE(customer_center_id, '') <> ''" if all_customer_centers else "customer_center_id = ?"
        params_prefix: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        stable_daily_sql = self._material_history_stable_day_sql(
            day_expr="material_daily.biz_date",
            customer_center_expr="material_daily.customer_center_id",
        )
        fact_rows: list[dict[str, Any]] = []

        if end_dt.strftime("%Y-%m-%d") < today_key:
            daily_rows = [
                dict(row)
                for row in conn.execute(
                    f"""
                        SELECT *
                        FROM material_daily
                        WHERE {where_prefix}
                          AND {stable_daily_sql}
                          AND biz_date >= ?
                          AND biz_date <= ?
                        ORDER BY biz_date DESC, stat_cost DESC, material_key ASC
                        """,
                    [*params_prefix, start_dt.strftime("%Y-%m-%d"), end_dt.strftime("%Y-%m-%d")],
                ).fetchall()
            ]
            fact_rows = self._filter_material_current_or_daily_rows(
                daily_rows,
                start_dt,
                end_dt,
                tz_name,
                allowed_advertiser_ids,
            )
        else:
            daily_rows: list[dict[str, Any]] = []
            if start_dt.strftime("%Y-%m-%d") < today_key:
                daily_rows = [
                    dict(row)
                    for row in conn.execute(
                        f"""
                        SELECT *
                        FROM material_daily
                        WHERE {where_prefix}
                          AND {stable_daily_sql}
                          AND biz_date >= ?
                          AND biz_date < ?
                        ORDER BY biz_date DESC, stat_cost DESC, material_key ASC
                        """,
                        [*params_prefix, start_dt.strftime("%Y-%m-%d"), today_key],
                    ).fetchall()
                ]
            current_rows = [
                dict(row)
                for row in conn.execute(
                    f"""
                    SELECT *
                    FROM material_current
                    WHERE {where_prefix}
                    ORDER BY snapshot_time DESC, stat_cost DESC, material_key ASC
                    """,
                    params_prefix,
                ).fetchall()
            ]
            fact_rows = self._filter_material_current_or_daily_rows(
                [*daily_rows, *current_rows],
                start_dt,
                end_dt,
                tz_name,
                allowed_advertiser_ids,
            )
        if not fact_rows:
            return None
        latest_snapshot_time = max(
            (str(row.get("snapshot_time") or "") for row in fact_rows if str(row.get("snapshot_time") or "").strip()),
            default="",
        )
        return self._build_material_payload_from_rows(
            conn,
            fact_rows,
            latest_snapshot_time=latest_snapshot_time,
            all_customer_centers=all_customer_centers,
            meta_rows=fact_rows,
            enrich_snapshot_context=True,
            query_context_ready=True,
        )

    def _material_rankings_read_model_payload(
        self,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        mode: str = MATERIAL_VIEW_PERFORMANCE,
        *,
        all_customer_centers: bool = False,
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        target_snapshot = str(snapshot_time or "").strip()
        normalized = str(range_key or "day").strip().lower()
        normalized_mode = normalize_material_view_mode(mode)
        freshness_source = (
            "material_current_daily"
            if normalized_mode == MATERIAL_VIEW_PERFORMANCE
            else ("material_profile_library" if normalized_mode == MATERIAL_VIEW_LIBRARY else "material_relation_current_daily")
        )
        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if target_snapshot:
            snapshot_day = _parse_date_input(target_snapshot[:10], "snapshot_time")
            tz = ZoneInfo(tz_name)
            start_dt = datetime(snapshot_day.year, snapshot_day.month, snapshot_day.day, 0, 0, 0, tzinfo=tz)
            end_dt = datetime(snapshot_day.year, snapshot_day.month, snapshot_day.day, 23, 59, 59, tzinfo=tz)
            range_label = "指定快照"
            normalized = "custom"
        else:
            if normalized not in MATERIAL_RANGES:
                raise ValueError("range must be one of day/yesterday/week/month/all/custom")
            if normalized == "custom":
                start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
            elif normalized == "all":
                start_dt, end_dt, range_label = build_all_material_window(tz_name)
            else:
                start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)

        cache_customer_center_id = "__all_customer_centers__" if all_customer_centers else self._current_customer_center_id()
        cache_key = build_material_cache_key(
            range_key,
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            cache_customer_center_id,
            normalized_mode,
        )
        cache_scope = material_cache_scope_for_range(normalized, snapshot_time=target_snapshot)
        cache_namespace = build_material_cache_namespace(normalized_mode, scope=cache_scope)
        cache_version = self._shared_cache_version(cache_namespace)
        versioned_cache_key = self._versioned_cache_key(cache_version, cache_key)
        base_fresh_ttl, base_stale_ttl = material_cache_ttls_for_scope(cache_scope)
        def build_payload() -> dict[str, Any]:
            with self.db() as conn:
                if target_snapshot:
                    if normalized_mode == MATERIAL_VIEW_PERFORMANCE:
                        where_prefix = "COALESCE(customer_center_id, '') <> ''" if all_customer_centers else "customer_center_id = ?"
                        params_prefix: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
                        stable_daily_sql = self._material_history_stable_day_sql(
                            day_expr="material_daily.biz_date",
                            customer_center_expr="material_daily.customer_center_id",
                        )
                        current_rows = [
                            dict(row)
                            for row in conn.execute(
                                f"""
                                SELECT *
                                FROM material_current
                                WHERE {where_prefix}
                                  AND snapshot_time = ?
                                ORDER BY snapshot_time DESC, stat_cost DESC, material_key ASC
                                """,
                                [*params_prefix, target_snapshot],
                            ).fetchall()
                        ]
                        source_rows = current_rows or [
                            dict(row)
                            for row in conn.execute(
                                f"""
                                SELECT *
                                FROM material_daily
                                WHERE {where_prefix}
                                  AND {stable_daily_sql}
                                  AND biz_date = ?
                                ORDER BY snapshot_time DESC, stat_cost DESC, material_key ASC
                                """,
                                [*params_prefix, target_snapshot[:10]],
                            ).fetchall()
                        ]
                        material_rows = self._filter_material_current_or_daily_rows(
                            source_rows,
                            start_dt,
                            end_dt,
                            tz_name,
                            allowed_advertiser_ids,
                        )
                        payload = (
                            self._build_material_payload_from_rows(
                                conn,
                                material_rows,
                                latest_snapshot_time=max(
                                    (str(row.get("snapshot_time") or "") for row in material_rows),
                                    default=target_snapshot,
                                ),
                                all_customer_centers=all_customer_centers,
                                enrich_snapshot_context=True,
                                query_context_ready=True,
                            )
                            if material_rows
                            else {
                                "snapshot_time": target_snapshot,
                                "items": [],
                                "meta": None,
                                "snapshot_count": 0,
                                **({"customer_center_count": 0} if all_customer_centers else {}),
                            }
                        )
                    else:
                        if normalized_mode == MATERIAL_VIEW_LIBRARY:
                            payload = self._material_rankings_from_profile_library(
                                conn,
                                start_dt,
                                end_dt,
                                range_key=normalized,
                                tz_name=tz_name,
                                allowed_advertiser_ids=allowed_advertiser_ids,
                                all_customer_centers=all_customer_centers,
                            ) or {
                                "snapshot_time": "",
                                "items": [],
                                "meta": None,
                                "snapshot_count": 0,
                                **({"customer_center_count": 0} if all_customer_centers else {}),
                            }
                        else:
                            relation_rows = self._material_relation_rows_for_exact_snapshot(
                                conn,
                                target_snapshot,
                                allowed_advertiser_ids=allowed_advertiser_ids,
                                all_customer_centers=all_customer_centers,
                            )
                            payload = (
                                self._build_material_relation_payload_from_rows(
                                    conn,
                                    relation_rows,
                                    latest_snapshot_time=max(
                                        (str(row.get("snapshot_time") or "") for row in relation_rows if str(row.get("snapshot_time") or "").strip()),
                                        default=target_snapshot,
                                    ),
                                    all_customer_centers=all_customer_centers,
                                )
                                if relation_rows
                                else {
                                    "snapshot_time": target_snapshot,
                                    "items": [],
                                    "meta": None,
                                    "snapshot_count": 0,
                                    **({"customer_center_count": 0} if all_customer_centers else {}),
                                }
                            )
                else:
                    if normalized_mode == MATERIAL_VIEW_PERFORMANCE:
                        payload = self._material_rankings_from_current_daily(
                            conn,
                            start_dt,
                            end_dt,
                            range_key=normalized,
                            tz_name=tz_name,
                            allowed_advertiser_ids=allowed_advertiser_ids,
                            all_customer_centers=all_customer_centers,
                        ) or {
                            "snapshot_time": "",
                            "items": [],
                            "meta": None,
                            "snapshot_count": 0,
                            **({"customer_center_count": 0} if all_customer_centers else {}),
                        }
                    elif normalized_mode == MATERIAL_VIEW_LIBRARY:
                        payload = self._material_rankings_from_profile_library(
                            conn,
                            start_dt,
                            end_dt,
                            range_key=normalized,
                            tz_name=tz_name,
                            allowed_advertiser_ids=allowed_advertiser_ids,
                            all_customer_centers=all_customer_centers,
                        ) or {
                            "snapshot_time": "",
                            "items": [],
                            "meta": None,
                            "snapshot_count": 0,
                            **({"customer_center_count": 0} if all_customer_centers else {}),
                        }
                    else:
                        relation_rows = self._material_relation_rows_for_window(
                            conn,
                            start_dt,
                            end_dt,
                            tz_name=tz_name,
                            allowed_advertiser_ids=allowed_advertiser_ids,
                            all_customer_centers=all_customer_centers,
                        )
                        payload = (
                            self._build_material_relation_payload_from_rows(
                                conn,
                                relation_rows,
                                latest_snapshot_time=max(
                                    (str(row.get("snapshot_time") or "") for row in relation_rows if str(row.get("snapshot_time") or "").strip()),
                                    default="",
                                ),
                                all_customer_centers=all_customer_centers,
                            )
                            if relation_rows
                            else {
                                "snapshot_time": "",
                                "items": [],
                                "meta": None,
                                "snapshot_count": 0,
                                **({"customer_center_count": 0} if all_customer_centers else {}),
                            }
                        )

            payload["range_key"] = normalized
            payload["range_label"] = range_label
            payload["material_mode"] = normalized_mode
            payload["query_start_date"] = start_dt.strftime("%Y-%m-%d")
            payload["query_end_date"] = end_dt.strftime("%Y-%m-%d")
            payload["_query_cache_base_key"] = cache_key
            if normalized_mode == MATERIAL_VIEW_PERFORMANCE:
                payload["metrics_semantics"] = {
                    "money_scope": "material_reuse_aggregation",
                    "reconcilable_to_account_summary": False,
                    "notice": "当前素材表现金额为素材复用聚合口径，同一素材复用于多个计划或账户时会重复累计，不直接与账户总消耗核平。",
                }
            elif normalized_mode == MATERIAL_VIEW_LIBRARY:
                payload["metrics_semantics"] = {
                    "money_scope": "material_profile_library",
                    "reconcilable_to_account_summary": False,
                    "notice": "资产库口径用于素材档案展示，不承诺与账户总表核平。",
                }
            else:
                payload["metrics_semantics"] = {
                    "money_scope": "material_relation_grain",
                    "reconcilable_to_account_summary": True,
                    "reconcile_requires_relation_grain": True,
                    "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
                }
            payload["materialTodayStatus"] = self._material_today_hot_status(
                all_customer_centers=all_customer_centers,
            )
            if normalized_mode != MATERIAL_VIEW_LIBRARY:
                history_kind = "material_relation" if normalized_mode == MATERIAL_VIEW_RELATION else "material"
                payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind=history_kind,
                        all_customer_centers=all_customer_centers,
                    )
                )
                payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind=history_kind,
                        all_customer_centers=all_customer_centers,
                    )
                )
            else:
                payload["history_backfill_pending"] = False
                payload["missing_history_days"] = 0
                payload["history_backfill_queued"] = False
                payload["history_recent_missing_days"] = 0
                payload["history_correction_pending"] = False
                payload["missing_correction_days"] = 0
                payload["history_correction_queued"] = False
                payload["yesterday_finalized"] = True
            return self._attach_freshness(
                payload,
                data_time=payload.get("snapshot_time"),
                synced_at=payload.get("snapshot_time"),
                source=freshness_source,
                partial=str(((payload.get("meta") or {}).get("status") or "")).strip().lower() not in {"", "ok"},
            )

        return self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_cache,
            cache_key=versioned_cache_key,
            raw_cache_key=cache_key,
            cache_version=cache_version,
            force_refresh=force_refresh,
            builder=build_payload,
            fresh_ttl_seconds=base_fresh_ttl,
            stale_ttl_seconds=base_stale_ttl,
        )

