    def material_rankings_for_user(
        self,
        user: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
        mode: str = MATERIAL_VIEW_PERFORMANCE,
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        role = str((user or {}).get("role") or "")
        if role == ROLE_OPERATOR or self._display_scope_uses_all_customer_centers(display_scope):
            payload = self._cross_customer_center_material_payload(
                range_key,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
                mode,
                force_refresh=force_refresh,
            )
            return self._apply_material_scope(payload, user or {}) if role == ROLE_OPERATOR else payload
        return self.material_rankings(
            range_key,
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            mode,
            force_refresh=force_refresh,
        )

    def _operator_material_performance_page_payload(
        self,
        user: dict[str, Any] | None,
        *,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        user_id = int((user or {}).get("id", 0) or 0)
        keyword_texts, keyword_signature = self._operator_material_keywords(user_id)
        if not keyword_texts:
            normalized = str(range_key or "day").strip().lower()
            config = self.read_config()
            tz_name = str(config.get("timezone") or TIMEZONE)
            if normalized == "custom":
                start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
            elif normalized == "all":
                start_dt, end_dt, range_label = build_all_material_window(tz_name)
            else:
                if normalized not in MATERIAL_RANGES:
                    raise ValueError("range must be one of day/yesterday/week/month/all/custom")
                start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)
            return self._empty_material_performance_page_payload(
                range_key=normalized,
                range_label=range_label,
                start_dt=start_dt,
                end_dt=end_dt,
                page_size=self._query_page_size_value(page_size, 20),
                sort_key=self._material_performance_sort_sql(sort_key, sort_dir)[1],
                sort_dir=self._material_performance_sort_sql(sort_key, sort_dir)[2],
                search=search,
                tz_name=tz_name,
                all_customer_centers=True,
            )
        indexed_sort_key = self._material_performance_sort_sql(sort_key, sort_dir)[1]
        if indexed_sort_key in {
            "overall_ctr",
            "stat_cost",
            "pay_amount",
            "total_pay_amount",
            "settled_pay_amount",
            "roi",
            "settled_roi",
            "pay_order_cost",
            "settled_amount_rate",
            "refund_rate_1h",
            "order_count",
            "settled_order_count",
            "plan_count",
            "advertiser_count",
        }:
            indexed_payload = self._operator_material_index_page_payload(
                user_id,
                range_key=range_key,
                start_date=start_date,
                end_date=end_date,
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
                force_refresh=force_refresh,
            )
            if indexed_payload is not None:
                return indexed_payload
        return self._material_performance_page_payload(
            range_key=range_key,
            start_date=start_date,
            end_date=end_date,
            allowed_advertiser_ids=allowed_advertiser_ids,
            all_customer_centers=True,
            page=page,
            page_size=page_size,
            sort_key=sort_key,
            sort_dir=sort_dir,
            search=search,
            force_refresh=force_refresh,
            material_name_keywords=keyword_texts,
            cache_key_suffix=f"operator-material:{user_id}:{keyword_signature}:zero-tail",
            rank_zero_metrics_last=True,
        )

    def material_rankings_page_for_user(
        self,
        user: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
        mode: str = MATERIAL_VIEW_PERFORMANCE,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        normalized_mode = normalize_material_view_mode(mode)
        if normalized_mode == MATERIAL_VIEW_RELATION:
            return self.material_relations_page_for_user(
                user,
                range_key,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
                display_scope,
                page,
                page_size,
                sort_key,
                sort_dir,
                search,
                force_refresh,
            )

        role = str((user or {}).get("role") or "")
        search_text = self._query_text(search)
        normalized_snapshot = str(snapshot_time or "").strip()
        normalized_sort_key = str(sort_key or "").strip()
        indexed_sort_keys = {
            "",
            "stat_cost",
            "total_pay_amount",
            "settled_pay_amount",
            "pay_amount",
            "order_count",
        }
        if (
            normalized_mode == MATERIAL_VIEW_PERFORMANCE
            and role != ROLE_OPERATOR
            and not normalized_snapshot
            and not search_text
            and normalized_sort_key not in indexed_sort_keys
        ):
            sort_key = "stat_cost"
            normalized_sort_key = "stat_cost"
        if normalized_mode == MATERIAL_VIEW_PERFORMANCE and role == ROLE_OPERATOR and not normalized_snapshot:
            return self._operator_material_performance_page_payload(
                user,
                range_key=range_key,
                start_date=start_date,
                end_date=end_date,
                allowed_advertiser_ids=allowed_advertiser_ids,
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
                force_refresh=force_refresh,
            )
        use_sql_page = (
            normalized_mode == MATERIAL_VIEW_PERFORMANCE
            and role != ROLE_OPERATOR
            and not normalized_snapshot
            and normalized_sort_key in indexed_sort_keys
        )
        if use_sql_page:
            return self._material_performance_page_payload(
                range_key=range_key,
                start_date=start_date,
                end_date=end_date,
                allowed_advertiser_ids=allowed_advertiser_ids,
                all_customer_centers=self._display_scope_uses_all_customer_centers(display_scope),
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
                force_refresh=force_refresh,
                rank_zero_metrics_last=True,
            )

        if normalized_mode == MATERIAL_VIEW_LIBRARY and not normalized_snapshot:
            return self._material_library_page_payload(
                range_key=range_key,
                start_date=start_date,
                end_date=end_date,
                allowed_advertiser_ids=allowed_advertiser_ids,
                all_customer_centers=self._display_scope_uses_all_customer_centers(display_scope),
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
            )

        payload = self.material_rankings_for_user(
            user,
            range_key,
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            display_scope,
            normalized_mode,
            force_refresh,
        )
        return self.paginate_material_payload(
            payload,
            page=page,
            page_size=page_size,
            sort_key=sort_key,
            sort_dir=sort_dir,
            search=search,
            allowed_advertiser_ids=allowed_advertiser_ids,
            force_refresh=force_refresh,
        )

