    @staticmethod
    def _material_performance_nonzero_sql(alias: str = "") -> str:
        prefix = str(alias or "").strip()
        if prefix and not prefix.endswith("."):
            prefix = f"{prefix}."
        metric_fields = (
            "stat_cost",
            "pay_amount",
            "total_pay_amount",
            "settled_pay_amount",
            "order_count",
            "settled_order_count",
            "overall_show_count",
            "overall_click_count",
            "refund_amount_1h",
        )
        return "(" + " OR ".join(f"COALESCE({prefix}{field}, 0) <> 0" for field in metric_fields) + ")"

    @staticmethod
    def _material_performance_zero_bucket_sql(alias: str = "") -> str:
        return material_ranking_index.zero_bucket_sql(alias)

    def _empty_material_performance_page_payload(
        self,
        *,
        range_key: str,
        range_label: str,
        start_dt: datetime,
        end_dt: datetime,
        page_size: int,
        sort_key: str,
        sort_dir: str,
        search: str,
        tz_name: str,
        all_customer_centers: bool,
        source: str = "material_current_daily",
    ) -> dict[str, Any]:
        payload = {
            "snapshot_time": "",
            "snapshot_count": 0,
            "items": [],
            "meta": {
                "snapshot_time": "",
                "status": "ok",
                "plan_count": 0,
                "detail_count": 0,
                "product_count": 0,
                "material_count": 0,
                "video_count": 0,
                "error_count": 0,
                "snapshot_dates": [],
                "snapshot_fallback_used": False,
            },
            "range_key": range_key,
            "range_label": range_label,
            "material_mode": MATERIAL_VIEW_PERFORMANCE,
            "query_start_date": start_dt.strftime("%Y-%m-%d"),
            "query_end_date": end_dt.strftime("%Y-%m-%d"),
            "pagination": {
                "page": 1,
                "page_size": page_size,
                "total_count": 0,
                "total_pages": 1,
                "start_index": 0,
                "end_index": 0,
                "sort_key": sort_key,
                "sort_dir": sort_dir,
                "search": str(search or "").strip(),
            },
            "materials_aggregate": None,
            "metrics_semantics": {
                "money_scope": "material_reuse_aggregation",
                "reconcilable_to_account_summary": False,
                "notice": "当前素材表现金额为素材复用聚合口径，同一素材复用于多个计划或账户时会重复累计，不直接与账户总消耗核平。",
            },
            "materialTodayStatus": self._material_today_hot_status(
                all_customer_centers=all_customer_centers,
            ),
        }
        payload.update(
            self._history_backfill_status_for_window(
                start_dt,
                end_dt,
                tz_name=tz_name,
                kind="material",
                all_customer_centers=all_customer_centers,
            )
        )
        payload.update(
            self._history_correction_status_for_window(
                start_dt,
                end_dt,
                tz_name=tz_name,
                kind="material",
                all_customer_centers=all_customer_centers,
            )
        )
        return self._attach_freshness(
            payload,
            data_time="",
            synced_at="",
            source=source,
            partial=False,
        )

    def _material_performance_sort_sql(
        self,
        sort_key: str = "",
        sort_dir: str = "desc",
    ) -> tuple[str, str, str]:
        numeric_sort_map = {
            "overall_ctr": "overall_ctr",
            "stat_cost": "stat_cost",
            "pay_amount": "pay_amount",
            "total_pay_amount": "total_pay_amount",
            "settled_pay_amount": "settled_pay_amount",
            "roi": "roi",
            "settled_roi": "settled_roi",
            "pay_order_cost": "pay_order_cost",
            "settled_amount_rate": "settled_amount_rate",
            "refund_rate_1h": "refund_rate_1h",
            "order_count": "order_count",
            "settled_order_count": "settled_order_count",
            "plan_count": "plan_count",
            "advertiser_count": "advertiser_count",
        }
        text_sort_map = {
            "material_name": "LOWER(COALESCE(material_name, ''))",
            "create_time": "LOWER(COALESCE(create_time, ''))",
            "top_account_name": "LOWER(COALESCE(top_account_name, ''))",
            "top_plan_name": "LOWER(COALESCE(top_plan_name, ''))",
            "top_anchor_name": "LOWER(COALESCE(top_anchor_name, ''))",
        }
        normalized_key = str(sort_key or "").strip()
        if normalized_key not in numeric_sort_map and normalized_key not in text_sort_map:
            normalized_key = "stat_cost"
        normalized_dir = self._query_sort_dir(sort_dir)
        normalized_dir_sql = normalized_dir.upper()
        sort_expr = numeric_sort_map.get(normalized_key) or text_sort_map.get(normalized_key) or "stat_cost"
        return (
            f"{sort_expr} {normalized_dir_sql}, material_key {normalized_dir_sql}",
            normalized_key,
            normalized_dir,
        )

    def refresh_material_ranking_index_for_window(
        self,
        *,
        start_day: str,
        end_day: str,
        range_key: str = "day",
        all_customer_centers: bool = False,
        sort_keys: list[str] | tuple[str, ...] | None = None,
        sort_dirs: list[str] | tuple[str, ...] | None = None,
    ) -> dict[str, Any]:
        return material_ranking_index.refresh_window(
            self,
            start_day=start_day,
            end_day=end_day,
            range_key=range_key,
            all_customer_centers=all_customer_centers,
            sort_keys=sort_keys,
            sort_dirs=sort_dirs,
        )

    def _material_history_index_refresh_end_day(self, target_days: list[str]) -> str:
        normalized_days = sorted({str(day or "").strip()[:10] for day in target_days if str(day or "").strip()})
        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE).strip() or TIMEZONE
        yesterday_key = (datetime.now(ZoneInfo(tz_name)).date() - timedelta(days=1)).strftime("%Y-%m-%d")
        candidates = [yesterday_key, *normalized_days]
        try:
            with self.db() as conn:
                row = conn.execute(
                    "SELECT MAX(day_key) AS max_day FROM material_ranking_day_prefix"
                ).fetchone()
            max_prefix_day = str((row or {}).get("max_day") or "").strip()
            if max_prefix_day:
                candidates.append(max_prefix_day)
        except Exception:
            LOGGER.exception("failed to inspect material day prefix max day")
        return max(candidates) if candidates else yesterday_key

    def _refresh_material_ranking_indexes_after_history_days(
        self,
        target_days: list[str] | set[str] | tuple[str, ...],
    ) -> dict[str, Any]:
        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE).strip() or TIMEZONE
        yesterday_key = (datetime.now(ZoneInfo(tz_name)).date() - timedelta(days=1)).strftime("%Y-%m-%d")
        normalized_days = sorted(
            {
                str(day or "").strip()[:10]
                for day in target_days
                if str(day or "").strip() and str(day or "").strip()[:10] <= yesterday_key
            }
        )
        if not normalized_days:
            return {
                "ok": True,
                "skipped": True,
                "reason": "no_closed_history_days",
                "yesterday": yesterday_key,
            }

        day_index_results: list[dict[str, Any]] = []
        index_scope_flags = [False]
        try:
            current_scope = material_ranking_index.scope_key(self, all_customer_centers=False)
            all_scope = material_ranking_index.scope_key(self, all_customer_centers=True)
            if all_scope and all_scope != current_scope:
                index_scope_flags.append(True)
        except Exception:
            LOGGER.exception("failed to resolve material ranking index scopes")

        for day_key in normalized_days:
            for all_customer_centers in index_scope_flags:
                try:
                    day_index_results.append(
                        self.refresh_material_ranking_index_for_window(
                            start_day=day_key,
                            end_day=day_key,
                            range_key="day",
                            all_customer_centers=all_customer_centers,
                            sort_keys=material_ranking_index.SORT_KEYS,
                            sort_dirs=("desc", "asc"),
                        )
                    )
                except Exception as exc:  # noqa: BLE001
                    LOGGER.exception("failed to rebuild material day index for %s", day_key)
                    day_index_results.append(
                        {
                            "ok": False,
                            "day": day_key,
                            "all_customer_centers": bool(all_customer_centers),
                            "error": str(exc),
                        }
                    )

        start_day = normalized_days[0]
        end_day = self._material_history_index_refresh_end_day(normalized_days)
        prefix_results: list[dict[str, Any]] = []
        rolling_index_results: list[dict[str, Any]] = []
        try:
            prefix_results.append(
                material_ranking_index.rebuild_day_prefix_range(
                    self,
                    start_day=start_day,
                    end_day=end_day,
                    all_customer_centers=False,
                )
            )
        except Exception as exc:  # noqa: BLE001
            LOGGER.exception("failed to rebuild current material day prefix from %s to %s", start_day, end_day)
            prefix_results.append(
                {
                    "ok": False,
                    "scope": "current",
                    "start_day": start_day,
                    "end_day": end_day,
                    "error": str(exc),
                }
            )
        try:
            prefix_results.append(
                material_ranking_index.rebuild_day_prefix_range(
                    self,
                    start_day=start_day,
                    end_day=end_day,
                    all_customer_centers=True,
                    force_scope_key=material_ranking_index.SCOPE_ALL,
                )
            )
        except Exception as exc:  # noqa: BLE001
            LOGGER.exception("failed to rebuild all material day prefix from %s to %s", start_day, end_day)
            prefix_results.append(
                {
                    "ok": False,
                    "scope": material_ranking_index.SCOPE_ALL,
                    "start_day": start_day,
                    "end_day": end_day,
                    "error": str(exc),
                }
            )

        rolling_end_day = end_day
        rolling_window_specs = [
            (
                "week",
                (datetime.strptime(rolling_end_day, "%Y-%m-%d").date() - timedelta(days=6)).strftime("%Y-%m-%d"),
                rolling_end_day,
            ),
            (
                "month",
                (datetime.strptime(rolling_end_day, "%Y-%m-%d").date() - timedelta(days=29)).strftime("%Y-%m-%d"),
                rolling_end_day,
            ),
        ]
        for range_key_value, rolling_start_day, rolling_end_day_value in rolling_window_specs:
            for all_customer_centers in index_scope_flags:
                try:
                    rolling_index_results.append(
                        self.refresh_material_ranking_index_for_window(
                            start_day=rolling_start_day,
                            end_day=rolling_end_day_value,
                            range_key=range_key_value,
                            all_customer_centers=all_customer_centers,
                            sort_keys=material_ranking_index.SORT_KEYS,
                            sort_dirs=("desc", "asc"),
                        )
                    )
                except Exception as exc:  # noqa: BLE001
                    LOGGER.exception(
                        "failed to rebuild material %s index for %s-%s",
                        range_key_value,
                        rolling_start_day,
                        rolling_end_day_value,
                    )
                    rolling_index_results.append(
                        {
                            "ok": False,
                            "range_key": range_key_value,
                            "start_day": rolling_start_day,
                            "end_day": rolling_end_day_value,
                            "all_customer_centers": bool(all_customer_centers),
                            "error": str(exc),
                        }
                    )

        self.clear_material_runtime_caches(scope="all")
        ok = all(bool(item.get("ok")) for item in [*day_index_results, *prefix_results, *rolling_index_results])
        return {
            "ok": ok,
            "target_days": normalized_days,
            "start_day": start_day,
            "end_day": end_day,
            "day_index_result_count": len(day_index_results),
            "day_index_results": day_index_results[-10:],
            "prefix_results": prefix_results,
            "rolling_index_result_count": len(rolling_index_results),
            "rolling_index_results": rolling_index_results,
        }

    def _material_ranking_index_build_key(
        self,
        *,
        start_day: str,
        end_day: str,
        range_key: str,
        all_customer_centers: bool,
    ) -> str:
        return "|".join(
            [
                material_ranking_index.scope_key(self, all_customer_centers=all_customer_centers),
                str(range_key or "").strip(),
                str(start_day or "").strip(),
                str(end_day or "").strip(),
            ]
        )

    @staticmethod
    def _material_ranking_index_lock_name(build_key: str) -> str:
        lock_name = hashlib.sha1(str(build_key or "").encode("utf-8")).hexdigest()[:24]
        return f"material-ranking-index:{lock_name}"

    def _queue_material_ranking_index_for_request(
        self,
        *,
        start_day: str,
        end_day: str,
        range_key: str,
        all_customer_centers: bool,
        cache_namespace: str,
    ) -> bool:
        build_key = self._material_ranking_index_build_key(
            start_day=start_day,
            end_day=end_day,
            range_key=range_key,
            all_customer_centers=all_customer_centers,
        )
        now_value = time.time()
        with self._material_ranking_index_build_lock:
            previous = float(self._material_ranking_index_build_marks.get(build_key, 0.0) or 0.0)
            if now_value - previous < 300:
                return False
            self._material_ranking_index_build_marks[build_key] = now_value
            if len(self._material_ranking_index_build_marks) > 256:
                cutoff = now_value - 3600
                self._material_ranking_index_build_marks = {
                    key: value
                    for key, value in self._material_ranking_index_build_marks.items()
                    if float(value or 0.0) >= cutoff
                }

        def build_index() -> None:
            try:
                with self._distributed_runtime_lock(
                    self._material_ranking_index_lock_name(build_key),
                    timeout_seconds=900,
                    blocking_timeout_seconds=0,
                ) as acquired:
                    if not acquired:
                        return
                    result = self.refresh_material_ranking_index_for_window(
                        start_day=start_day,
                        end_day=end_day,
                        range_key=range_key,
                        all_customer_centers=all_customer_centers,
                        sort_keys=material_ranking_index.SORT_KEYS,
                        sort_dirs=("desc", "asc"),
                    )
                if result.get("ok"):
                    self._invalidate_cache_namespaces(cache_namespace)
            except Exception:
                LOGGER.exception(
                    "material ranking index build failed for %s %s-%s",
                    range_key,
                    start_day,
                    end_day,
                )

        threading.Thread(
            target=build_index,
            daemon=True,
            name=f"material-ranking-index-{range_key}",
        ).start()
        return True

    def rebuild_material_ranking_indexes(
        self,
        *,
        days: int = MATERIAL_RANKING_INDEX_RETENTION_DAYS,
        all_customer_centers: bool = False,
    ) -> dict[str, Any]:
        return material_ranking_index.rebuild_recent(
            self,
            days=days,
            all_customer_centers=all_customer_centers,
        )

    def _material_performance_page_payload(
        self,
        *,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
        material_name_keywords: list[str] | None = None,
        cache_key_suffix: str = "",
        require_nonzero_metrics: bool = False,
        rank_zero_metrics_last: bool = False,
    ) -> dict[str, Any]:
        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")

        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if normalized == "custom":
            start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
        elif normalized == "all":
            start_dt, end_dt, range_label = build_all_material_window(tz_name)
        else:
            start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)

        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, 20)
        sort_sql, normalized_sort_key, normalized_sort_dir = self._material_performance_sort_sql(sort_key, sort_dir)
        search_text = self._query_text(search)
        material_keywords = [
            str(item or "").strip()
            for item in list(material_name_keywords or [])
            if str(item or "").strip()
        ]
        material_name_patterns = [self._sql_like_pattern(item) for item in material_keywords]
        filter_nonzero_metrics = bool(require_nonzero_metrics and not rank_zero_metrics_last)
        cache_customer_center_id = "__all_customer_centers__" if all_customer_centers else self._current_customer_center_id()
        base_cache_key = build_material_cache_key(
            normalized,
            start_date,
            end_date,
            "",
            allowed_advertiser_ids,
            cache_customer_center_id,
            MATERIAL_VIEW_PERFORMANCE,
        )
        if cache_key_suffix:
            base_cache_key = f"{base_cache_key}:{cache_key_suffix}"
        cache_scope = material_cache_scope_for_range(normalized, snapshot_time="")
        cache_namespace = f"{build_material_cache_namespace(MATERIAL_VIEW_PERFORMANCE, scope=cache_scope)}:page"
        cache_version = self._shared_cache_version(cache_namespace)
        fresh_ttl, stale_ttl = material_cache_ttls_for_scope(cache_scope)
        if cache_scope == MATERIAL_CACHE_SCOPE_HISTORY:
            fresh_ttl = max(fresh_ttl, 3600)
            stale_ttl = max(stale_ttl, 21600)
        query_cache_key = (
            f"{base_cache_key}:sql-metric-page:"
            f"{normalized_page}:{normalized_page_size}:{normalized_sort_key}:{normalized_sort_dir}:"
            f"{'zero-tail' if rank_zero_metrics_last else ('nonzero-only' if filter_nonzero_metrics else 'default')}:"
            f"{hashlib.sha1(search_text.encode('utf-8')).hexdigest()[:16]}"
        )

        def build_payload() -> dict[str, Any]:
            tz = ZoneInfo(str(tz_name or TIMEZONE))
            today_key = datetime.now(tz).strftime("%Y-%m-%d")
            start_day = start_dt.astimezone(tz).strftime("%Y-%m-%d")
            end_day = end_dt.astimezone(tz).strftime("%Y-%m-%d")
            allowed = (
                None
                if allowed_advertiser_ids is None
                else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0) > 0)
            )

            def empty_payload() -> dict[str, Any]:
                payload = {
                    "snapshot_time": "",
                    "snapshot_count": 0,
                    "items": [],
                    "meta": {
                        "snapshot_time": "",
                        "status": "ok",
                        "plan_count": 0,
                        "detail_count": 0,
                        "product_count": 0,
                        "material_count": 0,
                        "video_count": 0,
                        "error_count": 0,
                        "snapshot_dates": [],
                        "snapshot_fallback_used": False,
                    },
                    "range_key": normalized,
                    "range_label": range_label,
                    "material_mode": MATERIAL_VIEW_PERFORMANCE,
                    "query_start_date": start_day,
                    "query_end_date": end_day,
                    "pagination": {
                        "page": 1,
                        "page_size": normalized_page_size,
                        "total_count": 0,
                        "total_pages": 1,
                        "start_index": 0,
                        "end_index": 0,
                        "sort_key": normalized_sort_key,
                        "sort_dir": normalized_sort_dir,
                        "search": str(search or "").strip(),
                    },
                    "materials_aggregate": None,
                    "metrics_semantics": {
                        "money_scope": "material_reuse_aggregation",
                        "reconcilable_to_account_summary": False,
                        "notice": "当前素材表现金额为素材复用聚合口径，同一素材复用于多个计划或账户时会重复累计，不直接与账户总消耗核平。",
                    },
                    "materialTodayStatus": self._material_today_hot_status(
                        all_customer_centers=all_customer_centers,
                    ),
                }
                payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material",
                        all_customer_centers=all_customer_centers,
                    )
                )
                payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material",
                        all_customer_centers=all_customer_centers,
                    )
                )
                return self._attach_freshness(
                    payload,
                    data_time="",
                    synced_at="",
                    source="material_current_daily",
                    partial=False,
                )

            if allowed_advertiser_ids is not None and not allowed:
                return empty_payload()

            source_queries: list[str] = []
            source_params: list[Any] = []
            daily_end_day = min(
                end_day,
                (datetime.strptime(today_key, "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d"),
            )
            if start_day <= daily_end_day:
                daily_where = ["md.biz_date >= ?", "md.biz_date <= ?"]
                source_params.extend([start_day, daily_end_day])
                daily_where.append(
                    self._material_history_stable_day_sql(
                        day_expr="md.biz_date",
                        customer_center_expr="md.customer_center_id",
                    )
                )
                if all_customer_centers:
                    daily_where.append("COALESCE(md.customer_center_id, '') <> ''")
                else:
                    daily_where.append("md.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    daily_where.append(
                        f"""
                        EXISTS (
                            SELECT 1
                            FROM jsonb_array_elements_text(COALESCE(NULLIF(md.advertiser_ids_json, ''), '[]')::jsonb) AS adv(value)
                            WHERE CAST(adv.value AS BIGINT) IN ({','.join('?' for _ in allowed)})
                        )
                        """
                    )
                    source_params.extend(allowed)
                if filter_nonzero_metrics:
                    daily_where.append(self._material_performance_nonzero_sql("md"))
                if material_name_patterns:
                    daily_where.append(
                        "(" + " OR ".join(["LOWER(COALESCE(md.material_name, '')) LIKE ? ESCAPE '\\'" for _ in material_name_patterns]) + ")"
                    )
                    source_params.extend(material_name_patterns)
                source_queries.append(
                    f"""
                    SELECT
                        md.customer_center_id,
                        md.snapshot_time,
                        md.biz_date AS source_day,
                        md.window_start,
                        md.window_end,
                        md.material_key,
                        md.material_id,
                        md.material_name,
                        md.backend_material_name,
                        md.create_time,
                        md.material_type,
                        md.video_id,
                        md.cover_url,
                        md.aweme_item_id,
                        md.video_url,
                        md.stat_cost,
                        md.pay_amount,
                        md.total_pay_amount,
                        md.settled_pay_amount,
                        md.order_count,
                        md.settled_order_count,
                        md.plan_count,
                        md.advertiser_count,
                        md.plan_ids_json,
                        md.advertiser_ids_json,
                        md.is_original,
                        md.top_plan_name,
                        md.top_account_name,
                        md.top_anchor_name,
                        md.product_info_text,
                        md.product_names_json,
                        md.overall_show_count,
                        md.overall_click_count,
                        md.overall_ctr,
                        md.roi,
                        md.settled_roi,
                        md.pay_order_cost,
                        md.settled_amount_rate,
                        md.refund_amount_1h,
                        md.refund_rate_1h
                    FROM material_daily md
                    WHERE {' AND '.join(daily_where)}
                    """
                )
            if end_day >= today_key:
                current_where: list[str] = []
                if all_customer_centers:
                    current_where.append("COALESCE(mc.customer_center_id, '') <> ''")
                else:
                    current_where.append("mc.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    current_where.append(
                        f"""
                        EXISTS (
                            SELECT 1
                            FROM jsonb_array_elements_text(COALESCE(NULLIF(mc.advertiser_ids_json, ''), '[]')::jsonb) AS adv(value)
                            WHERE CAST(adv.value AS BIGINT) IN ({','.join('?' for _ in allowed)})
                        )
                        """
                    )
                    source_params.extend(allowed)
                if filter_nonzero_metrics:
                    current_where.append(self._material_performance_nonzero_sql("mc"))
                if material_name_patterns:
                    current_where.append(
                        "(" + " OR ".join(["LOWER(COALESCE(mc.material_name, '')) LIKE ? ESCAPE '\\'" for _ in material_name_patterns]) + ")"
                    )
                    source_params.extend(material_name_patterns)
                source_queries.append(
                    f"""
                    SELECT
                        mc.customer_center_id,
                        mc.snapshot_time,
                        substr(mc.snapshot_time, 1, 10) AS source_day,
                        mc.window_start,
                        mc.window_end,
                        mc.material_key,
                        mc.material_id,
                        mc.material_name,
                        mc.backend_material_name,
                        mc.create_time,
                        mc.material_type,
                        mc.video_id,
                        mc.cover_url,
                        mc.aweme_item_id,
                        mc.video_url,
                        mc.stat_cost,
                        mc.pay_amount,
                        mc.total_pay_amount,
                        mc.settled_pay_amount,
                        mc.order_count,
                        mc.settled_order_count,
                        mc.plan_count,
                        mc.advertiser_count,
                        mc.plan_ids_json,
                        mc.advertiser_ids_json,
                        mc.is_original,
                        mc.top_plan_name,
                        mc.top_account_name,
                        mc.top_anchor_name,
                        mc.product_info_text,
                        mc.product_names_json,
                        mc.overall_show_count,
                        mc.overall_click_count,
                        mc.overall_ctr,
                        mc.roi,
                        mc.settled_roi,
                        mc.pay_order_cost,
                        mc.settled_amount_rate,
                        mc.refund_amount_1h,
                        mc.refund_rate_1h
                    FROM material_current mc
                    WHERE {' AND '.join(current_where) if current_where else '1 = 1'}
                    """
                )

            if not source_queries:
                return empty_payload()

            today_key_for_index = datetime.now(ZoneInfo(str(tz_name or TIMEZONE))).strftime("%Y-%m-%d")
            window_includes_today = start_day <= today_key_for_index <= end_day
            uses_day_rollup_index = (start_day != end_day or end_day < today_key_for_index) and not window_includes_today
            index_range_key = (
                ""
                if uses_day_rollup_index
                else material_ranking_index.index_range_key(normalized, start_day, end_day)
            )
            can_use_ranking_index = (
                not window_includes_today
                and
                (uses_day_rollup_index or bool(index_range_key))
                and allowed_advertiser_ids is None
                and not material_name_patterns
                and rank_zero_metrics_last
                and normalized_sort_key in material_ranking_index.SORT_KEYS
                and (not search_text or uses_day_rollup_index)
            )
            can_use_live_overlay_index = (
                window_includes_today
                and start_day < today_key_for_index
                and allowed_advertiser_ids is None
                and not material_name_patterns
                and rank_zero_metrics_last
                and normalized_sort_key in material_ranking_index.SORT_KEYS
            )
            can_use_current_live_index = (
                window_includes_today
                and start_day == today_key_for_index
                and end_day == today_key_for_index
                and allowed_advertiser_ids is None
                and not material_name_patterns
                and rank_zero_metrics_last
                and normalized_sort_key in material_ranking_index.SORT_KEYS
            )
            if can_use_current_live_index or can_use_live_overlay_index or can_use_ranking_index:
                scope_key_value = material_ranking_index.scope_key(
                    self,
                    all_customer_centers=all_customer_centers,
                )
                if can_use_current_live_index:
                    with self.db() as index_conn:
                        indexed_payload = material_ranking_index.payload_from_current_index(
                            self,
                            index_conn,
                            start_day=start_day,
                            end_day=end_day,
                            normalized=normalized,
                            range_label=range_label,
                            page=normalized_page,
                            page_size=normalized_page_size,
                            sort_key=normalized_sort_key,
                            sort_dir=normalized_sort_dir,
                            tz_name=tz_name,
                            all_customer_centers=all_customer_centers,
                            search_text=search_text,
                        )
                    if indexed_payload is not None:
                        return indexed_payload
                elif can_use_live_overlay_index:
                    with self.db() as index_conn:
                        indexed_payload = material_ranking_index.payload_from_live_overlay_index(
                            self,
                            index_conn,
                            scope_key_value=scope_key_value,
                            start_day=start_day,
                            end_day=end_day,
                            normalized=normalized,
                            range_label=range_label,
                            start_dt=start_dt,
                            end_dt=end_dt,
                            tz_name=tz_name,
                            page=normalized_page,
                            page_size=normalized_page_size,
                            sort_key=normalized_sort_key,
                            sort_dir=normalized_sort_dir,
                            all_customer_centers=all_customer_centers,
                            search_text=search_text,
                        )
                    if indexed_payload is not None:
                        return indexed_payload
                elif uses_day_rollup_index:
                    with self.db() as index_conn:
                        indexed_payload = material_ranking_index.payload_from_day_rollup_index(
                            self,
                            index_conn,
                            source_queries=source_queries,
                            source_params=source_params,
                            scope_key_value=scope_key_value,
                            start_day=start_day,
                            end_day=end_day,
                            normalized=normalized,
                            range_label=range_label,
                            start_dt=start_dt,
                            end_dt=end_dt,
                            tz_name=tz_name,
                            page=normalized_page,
                            page_size=normalized_page_size,
                            sort_key=normalized_sort_key,
                            sort_dir=normalized_sort_dir,
                            all_customer_centers=all_customer_centers,
                            search_text=search_text,
                        )
                    if indexed_payload is not None:
                        return indexed_payload
                    if search_text:
                        payload = empty_payload()
                        payload["materials_aggregate"] = {
                            "material_mode": MATERIAL_VIEW_PERFORMANCE,
                            "material_count": 0,
                            "stat_cost": 0.0,
                            "pay_amount": 0.0,
                            "total_pay_amount": 0.0,
                            "settled_pay_amount": 0.0,
                            "order_count": 0,
                            "settled_order_count": 0,
                            "overall_show_count": 0,
                            "overall_click_count": 0,
                            "overall_ctr": 0.0,
                            "roi": 0.0,
                            "settled_roi": 0.0,
                            "pay_order_cost": 0.0,
                            "settled_amount_rate": 0.0,
                            "refund_amount_1h": 0.0,
                            "refund_rate_1h": 0.0,
                            "plan_count": 0,
                            "advertiser_count": 0,
                            "summary_text": "total 0 materials",
                        }
                        payload["ranking_index_used"] = False
                        payload["ranking_index_range_key"] = "day_prefix"
                        payload["ranking_index_day_prefix_used"] = False
                        payload["ranking_index_day_rollup_used"] = False
                        payload["ranking_index_search_guard_used"] = True
                        payload["freshness"] = self._build_freshness_payload(
                            data_time="",
                            synced_at="",
                            source="material_ranking_search_guard",
                            partial=False,
                        )
                        return payload
                else:
                    with self.db() as index_conn:
                        indexed_payload = material_ranking_index.payload_from_index(
                            self,
                            index_conn,
                            source_queries=source_queries,
                            source_params=source_params,
                            scope_key_value=scope_key_value,
                            index_range_key_value=index_range_key,
                            start_day=start_day,
                            end_day=end_day,
                            normalized=normalized,
                            range_label=range_label,
                            start_dt=start_dt,
                            end_dt=end_dt,
                            tz_name=tz_name,
                            page=normalized_page,
                            page_size=normalized_page_size,
                            sort_key=normalized_sort_key,
                            sort_dir=normalized_sort_dir,
                            all_customer_centers=all_customer_centers,
                        )
                    if indexed_payload is not None:
                        return indexed_payload
                    self._queue_material_ranking_index_for_request(
                        start_day=start_day,
                        end_day=end_day,
                        range_key=index_range_key,
                        all_customer_centers=all_customer_centers,
                        cache_namespace=cache_namespace,
                    )

            escaped_search = search_text.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
            search_like = f"%{escaped_search}%"
            search_params = [search_like] * 10 if search_text else []
            search_source_filter = ""
            aggregated_source_filter = ""
            if search_text:
                search_source_filter = """
                WHERE (
                    LOWER(COALESCE(source.material_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.material_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.video_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.product_info_text, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.top_anchor_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.top_plan_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.top_account_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.material_key, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.aweme_item_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(source.material_type, '')) LIKE ? ESCAPE '\\'
                )
                """
                aggregated_source_filter = "WHERE source.material_key IN (SELECT material_key FROM matching_materials)"

            zero_bucket_sort_prefix = "prepared.zero_bucket ASC, " if rank_zero_metrics_last else ""
            page_sql = f"""
            WITH source AS (
                {' UNION ALL '.join(source_queries)}
            ),
            matching_materials AS (
                SELECT DISTINCT source.material_key
                FROM source
                {search_source_filter}
            ),
            material_plan_ids AS (
                SELECT DISTINCT source.material_key, CAST(plan_item.value AS BIGINT) AS plan_id
                FROM source
                {"INNER JOIN matching_materials mm ON mm.material_key = source.material_key" if search_text else ""}
                CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(NULLIF(source.plan_ids_json, ''), '[]')::jsonb) AS plan_item(value)
            ),
            material_advertiser_ids AS (
                SELECT DISTINCT source.material_key, CAST(adv_item.value AS BIGINT) AS advertiser_id
                FROM source
                {"INNER JOIN matching_materials mm ON mm.material_key = source.material_key" if search_text else ""}
                CROSS JOIN LATERAL jsonb_array_elements_text(COALESCE(NULLIF(source.advertiser_ids_json, ''), '[]')::jsonb) AS adv_item(value)
            ),
            aggregated AS (
                SELECT
                    source.material_key,
                    CASE
                        WHEN MAX(CASE WHEN source.material_type = 'UNATTRIBUTED_DELETED' THEN 1 ELSE 0 END) = 1
                        THEN '未归因关闭/暂停计划消耗'
                        ELSE COALESCE(MAX(NULLIF(source.backend_material_name, '')), MAX(NULLIF(source.material_name, '')), '')
                    END AS material_name,
                    COALESCE(MIN(NULLIF(source.create_time, '')), '') AS create_time,
                    COALESCE(MAX(NULLIF(source.top_account_name, '')), '') AS top_account_name,
                    COALESCE(MAX(NULLIF(source.top_plan_name, '')), '') AS top_plan_name,
                    COALESCE(MAX(NULLIF(source.top_anchor_name, '')), '') AS top_anchor_name,
                    MAX(source.snapshot_time) AS snapshot_time,
                    CAST(ROUND(COALESCE(SUM(source.stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                    CAST(ROUND(COALESCE(SUM(source.pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                    CAST(ROUND(COALESCE(SUM(source.total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(source.settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                    CAST(COALESCE(SUM(source.order_count), 0) AS INTEGER) AS order_count,
                    CAST(COALESCE(SUM(source.settled_order_count), 0) AS INTEGER) AS settled_order_count,
                    CAST(COALESCE(SUM(source.overall_show_count), 0) AS INTEGER) AS overall_show_count,
                    CAST(COALESCE(SUM(source.overall_click_count), 0) AS INTEGER) AS overall_click_count,
                    CAST(ROUND(COALESCE(SUM(source.refund_amount_1h), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS refund_amount_1h,
                    CAST(COALESCE((SELECT COUNT(DISTINCT mpi.plan_id) FROM material_plan_ids mpi WHERE mpi.material_key = source.material_key), 0) AS INTEGER) AS plan_count,
                    CAST(COALESCE((SELECT COUNT(DISTINCT mai.advertiser_id) FROM material_advertiser_ids mai WHERE mai.material_key = source.material_key), 0) AS INTEGER) AS advertiser_count,
                    CAST(ROUND(COALESCE(
                        (COALESCE(SUM(source.overall_click_count), 0)::numeric / NULLIF(COALESCE(SUM(source.overall_show_count), 0)::numeric, 0)) * 100,
                        0
                    ), 2) AS DOUBLE PRECISION) AS overall_ctr,
                    CAST(ROUND(COALESCE(
                        COALESCE(SUM(source.pay_amount), 0.0)::numeric / NULLIF(COALESCE(SUM(source.stat_cost), 0.0)::numeric, 0),
                        0
                    ), 2) AS DOUBLE PRECISION) AS roi,
                    CAST(ROUND(COALESCE(
                        COALESCE(SUM(source.settled_pay_amount), 0.0)::numeric / NULLIF(COALESCE(SUM(source.stat_cost), 0.0)::numeric, 0),
                        0
                    ), 2) AS DOUBLE PRECISION) AS settled_roi,
                    CAST(ROUND(COALESCE(
                        COALESCE(SUM(source.stat_cost), 0.0)::numeric / NULLIF(COALESCE(SUM(source.order_count), 0)::numeric, 0),
                        0
                    ), 2) AS DOUBLE PRECISION) AS pay_order_cost,
                    CAST(ROUND(COALESCE(
                        (COALESCE(SUM(source.settled_pay_amount), 0.0)::numeric / NULLIF(COALESCE(SUM(source.total_pay_amount), 0.0)::numeric, 0)) * 100,
                        0
                    ), 2) AS DOUBLE PRECISION) AS settled_amount_rate,
                    CAST(ROUND(COALESCE(
                        (COALESCE(SUM(source.refund_amount_1h), 0.0)::numeric / NULLIF(COALESCE(SUM(source.total_pay_amount), 0.0)::numeric, 0)) * 100,
                        0
                    ), 2) AS DOUBLE PRECISION) AS refund_rate_1h
                FROM source
                {aggregated_source_filter}
                GROUP BY source.material_key
            ),
            prepared AS (
                SELECT
                    aggregated.*,
                    {self._material_performance_zero_bucket_sql("aggregated")} AS zero_bucket
                FROM aggregated
            ),
            summary AS (
                SELECT
                    COUNT(*) AS total_count,
                    CAST(ROUND(COALESCE(SUM(stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_stat_cost,
                    CAST(ROUND(COALESCE(SUM(pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_pay_amount,
                    CAST(ROUND(COALESCE(SUM(total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_settled_pay_amount,
                    CAST(COALESCE(SUM(order_count), 0) AS INTEGER) AS aggregate_order_count,
                    CAST(COALESCE(SUM(settled_order_count), 0) AS INTEGER) AS aggregate_settled_order_count,
                    CAST(COALESCE(SUM(overall_show_count), 0) AS INTEGER) AS aggregate_overall_show_count,
                    CAST(COALESCE(SUM(overall_click_count), 0) AS INTEGER) AS aggregate_overall_click_count,
                    CAST(ROUND(COALESCE(SUM(refund_amount_1h), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_refund_amount_1h,
                    COALESCE((SELECT COUNT(DISTINCT plan_id) FROM material_plan_ids), 0) AS aggregate_plan_count,
                    COALESCE((SELECT COUNT(DISTINCT advertiser_id) FROM material_advertiser_ids), 0) AS aggregate_advertiser_count
                FROM prepared
            ),
            source_meta AS (
                SELECT
                    COALESCE(MAX(snapshot_time), '') AS latest_snapshot_time,
                    COUNT(DISTINCT snapshot_time) AS snapshot_count,
                    COUNT(DISTINCT customer_center_id) AS customer_center_count
                FROM source
            ),
            paged AS (
                SELECT *
                FROM (
                    SELECT prepared.material_key, ROW_NUMBER() OVER (ORDER BY {zero_bucket_sort_prefix}{sort_sql}) AS __page_order
                    FROM prepared
                ) ranked
                WHERE ranked.__page_order > ?
                  AND ranked.__page_order <= ?
            )
            SELECT source_meta.latest_snapshot_time, source_meta.snapshot_count, source_meta.customer_center_count,
                   summary.total_count, summary.aggregate_stat_cost, summary.aggregate_pay_amount,
                   summary.aggregate_total_pay_amount, summary.aggregate_settled_pay_amount,
                   summary.aggregate_order_count, summary.aggregate_settled_order_count,
                   summary.aggregate_overall_show_count, summary.aggregate_overall_click_count,
                   summary.aggregate_refund_amount_1h, summary.aggregate_plan_count, summary.aggregate_advertiser_count,
                   paged.material_key, paged.__page_order
            FROM summary
            LEFT JOIN source_meta ON TRUE
            LEFT JOIN paged ON TRUE
            ORDER BY paged.__page_order NULLS LAST
            """

            def run_performance_page(conn: Any, page_value: int) -> list[dict[str, Any]]:
                start_index = max(page_value - 1, 0) * normalized_page_size
                params = [
                    *source_params,
                    *search_params,
                    start_index,
                    start_index + normalized_page_size,
                ]
                return [dict(row) for row in conn.execute(page_sql, params).fetchall()]

            with self.db() as conn:
                query_rows = run_performance_page(conn, normalized_page)
                summary_row = dict(query_rows[0] or {}) if query_rows else {}
                total_count = int(summary_row.get("total_count", 0) or 0)
                total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
                current_page = min(max(1, normalized_page), total_pages)
                if current_page != normalized_page:
                    query_rows = run_performance_page(conn, current_page)
                    summary_row = dict(query_rows[0] or {}) if query_rows else summary_row
                page_material_keys = [
                    str(row.get("material_key") or "").strip()
                    for row in query_rows
                    if str(row.get("material_key") or "").strip()
                ]
                latest_snapshot_time = str(summary_row.get("latest_snapshot_time") or "").strip()
                if page_material_keys:
                    page_source_sql = f"""
                    WITH source AS (
                        {' UNION ALL '.join(source_queries)}
                    )
                    SELECT *
                    FROM source
                    WHERE material_key IN ({','.join('?' for _ in page_material_keys)})
                    """
                    page_source_rows = [
                        dict(row)
                        for row in conn.execute(page_source_sql, [*source_params, *page_material_keys]).fetchall()
                    ]
                    payload = self._build_material_payload_from_rows(
                        conn,
                        page_source_rows,
                        latest_snapshot_time=latest_snapshot_time,
                        all_customer_centers=all_customer_centers,
                        meta_rows=page_source_rows,
                        enrich_snapshot_context=True,
                        query_context_ready=True,
                    )
                    key_order = {key: index for index, key in enumerate(page_material_keys)}
                    items = self._sanitize_material_preview_fields_for_payload(
                        self._apply_latest_material_previews(
                            conn,
                            payload.get("items") or [],
                        )
                    )
                    items = [dict(item or {}) for item in items]
                    items.sort(
                        key=lambda item: key_order.get(
                            str(item.get("material_key") or "").strip(),
                            len(key_order),
                        )
                    )
                    payload["items"] = items
                else:
                    payload = empty_payload()

            total_stat_cost = round(float(summary_row.get("aggregate_stat_cost", 0.0) or 0.0), 2)
            total_pay_amount = round(float(summary_row.get("aggregate_pay_amount", 0.0) or 0.0), 2)
            total_total_pay_amount = round(float(summary_row.get("aggregate_total_pay_amount", 0.0) or 0.0), 2)
            total_settled_pay_amount = round(float(summary_row.get("aggregate_settled_pay_amount", 0.0) or 0.0), 2)
            total_order_count = int(summary_row.get("aggregate_order_count", 0) or 0)
            total_settled_order_count = int(summary_row.get("aggregate_settled_order_count", 0) or 0)
            total_show_count = int(summary_row.get("aggregate_overall_show_count", 0) or 0)
            total_click_count = int(summary_row.get("aggregate_overall_click_count", 0) or 0)
            total_refund_amount_1h = round(float(summary_row.get("aggregate_refund_amount_1h", 0.0) or 0.0), 2)
            total_count = int(summary_row.get("total_count", 0) or 0)
            total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
            current_page = min(max(1, normalized_page), total_pages)
            start_index = (current_page - 1) * normalized_page_size
            page_items = list(payload.get("items") or [])
            snapshot_count = int(summary_row.get("snapshot_count", 0) or 0)
            source_customer_center_count = int(summary_row.get("customer_center_count", 0) or 0)

            payload["snapshot_time"] = str(summary_row.get("latest_snapshot_time") or "").strip()
            payload["snapshot_count"] = snapshot_count
            payload["meta"] = self._material_meta_from_rows(
                list(page_items or []),
                payload.get("snapshot_time") or "",
                material_count=total_count,
            )
            if all_customer_centers:
                payload["customer_center_count"] = source_customer_center_count
            payload["range_key"] = normalized
            payload["range_label"] = range_label
            payload["material_mode"] = MATERIAL_VIEW_PERFORMANCE
            payload["query_start_date"] = start_day
            payload["query_end_date"] = end_day
            payload["pagination"] = {
                "page": current_page,
                "page_size": normalized_page_size,
                "total_count": total_count,
                "total_pages": total_pages,
                "start_index": start_index + 1 if total_count > 0 else 0,
                "end_index": start_index + len(page_items),
                "sort_key": normalized_sort_key,
                "sort_dir": normalized_sort_dir,
                "search": "",
            }
            payload["materials_aggregate"] = {
                "material_mode": MATERIAL_VIEW_PERFORMANCE,
                "material_count": total_count,
                "stat_cost": total_stat_cost,
                "pay_amount": total_pay_amount,
                "total_pay_amount": total_total_pay_amount,
                "settled_pay_amount": total_settled_pay_amount,
                "order_count": total_order_count,
                "settled_order_count": total_settled_order_count,
                "overall_show_count": total_show_count,
                "overall_click_count": total_click_count,
                "overall_ctr": round(total_click_count / total_show_count * 100.0, 2) if total_show_count > 0 else 0.0,
                "roi": round(total_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "settled_roi": round(total_settled_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "pay_order_cost": round(total_stat_cost / total_order_count, 2) if total_order_count > 0 else 0.0,
                "settled_amount_rate": round(total_settled_pay_amount / total_total_pay_amount * 100.0, 2) if total_total_pay_amount > 0 else 0.0,
                "refund_amount_1h": total_refund_amount_1h,
                "refund_rate_1h": round(total_refund_amount_1h / total_total_pay_amount * 100.0, 2) if total_total_pay_amount > 0 else 0.0,
                "plan_count": int(summary_row.get("aggregate_plan_count", 0) or 0),
                "advertiser_count": int(summary_row.get("aggregate_advertiser_count", 0) or 0),
                "summary_text": f"共{total_count}条素材",
            }
            payload["metrics_semantics"] = {
                "money_scope": "material_reuse_aggregation",
                "reconcilable_to_account_summary": False,
                "notice": "当前素材表现金额为素材复用聚合口径，同一素材复用于多个计划或账户时会重复累计，不直接与账户总消耗核平。",
            }
            payload["materialTodayStatus"] = self._material_today_hot_status(
                all_customer_centers=all_customer_centers,
            )
            payload.update(
                self._history_backfill_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material",
                    all_customer_centers=all_customer_centers,
                )
            )
            payload.update(
                self._history_correction_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material",
                    all_customer_centers=all_customer_centers,
                )
            )
            return self._attach_freshness(
                payload,
                data_time=payload.get("snapshot_time"),
                synced_at=payload.get("snapshot_time"),
                source="material_current_daily",
                partial=False,
            )

        return self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_query_cache,
            cache_key=self._versioned_cache_key(cache_version, query_cache_key),
            raw_cache_key=query_cache_key,
            cache_version=cache_version,
            force_refresh=force_refresh,
            builder=build_payload,
            fresh_ttl_seconds=max(fresh_ttl, 300),
            stale_ttl_seconds=max(stale_ttl, 900),
        )

    def _material_relation_sort_sql(
        self,
        sort_key: str = "",
        sort_dir: str = "desc",
    ) -> tuple[str, str, str]:
        numeric_sort_map = {
            "overall_ctr": "overall_ctr",
            "stat_cost": "stat_cost",
            "total_pay_amount": "total_pay_amount",
            "settled_pay_amount": "settled_pay_amount",
            "roi": "roi",
            "pay_amount": "pay_amount",
            "order_count": "order_count",
            "seen_count": "seen_count",
            "active_day_count": "active_day_count",
        }
        text_sort_map = {
            "material_name": "LOWER(COALESCE(material_name, ''))",
            "create_time": "LOWER(COALESCE(create_time, ''))",
            "advertiser_name": "LOWER(COALESCE(advertiser_name, ''))",
            "ad_name": "LOWER(COALESCE(ad_name, ''))",
            "top_anchor_name": "LOWER(COALESCE(top_anchor_name, ''))",
            "first_seen_at": "LOWER(COALESCE(first_seen_at, ''))",
            "last_seen_at": "LOWER(COALESCE(last_seen_at, ''))",
        }
        normalized_key = str(sort_key or "").strip()
        if normalized_key not in numeric_sort_map and normalized_key not in text_sort_map:
            normalized_key = "stat_cost"
        normalized_dir = self._query_sort_dir(sort_dir)
        normalized_dir_sql = normalized_dir.upper()
        sort_expr = numeric_sort_map.get(normalized_key) or text_sort_map.get(normalized_key) or "stat_cost"
        return (
            f"{sort_expr} {normalized_dir_sql}, material_row_key {normalized_dir_sql}",
            normalized_key,
            normalized_dir,
        )

    def _material_relation_page_payload(
        self,
        *,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = False,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        target_snapshot = str(snapshot_time or "").strip()
        if target_snapshot:
            payload = self._material_rankings_read_model_payload(
                range_key,
                start_date,
                end_date,
                target_snapshot,
                allowed_advertiser_ids,
                MATERIAL_VIEW_RELATION,
                all_customer_centers=all_customer_centers,
                force_refresh=force_refresh,
            )
            return self.paginate_material_payload(
                payload,
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
                allowed_advertiser_ids=allowed_advertiser_ids,
                force_refresh=force_refresh,
            )

        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")

        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if normalized == "custom":
            start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
        elif normalized == "all":
            start_dt, end_dt, range_label = build_all_material_window(tz_name)
        else:
            start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)

        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, 10)
        cache_customer_center_id = "__all_customer_centers__" if all_customer_centers else self._current_customer_center_id()
        base_cache_key = build_material_cache_key(
            normalized,
            start_date,
            end_date,
            "",
            allowed_advertiser_ids,
            cache_customer_center_id,
            MATERIAL_VIEW_RELATION,
        )
        search_text = self._query_text(search)
        sort_sql, normalized_sort_key, normalized_sort_dir = self._material_relation_sort_sql(sort_key, sort_dir)
        cache_scope = material_cache_scope_for_range(normalized, snapshot_time="")
        cache_namespace = f"{build_material_cache_namespace(MATERIAL_VIEW_RELATION, scope=cache_scope)}:page"
        cache_version = self._shared_cache_version(cache_namespace)
        fresh_ttl, stale_ttl = material_cache_ttls_for_scope(cache_scope)
        if cache_scope == MATERIAL_CACHE_SCOPE_HISTORY:
            fresh_ttl = max(fresh_ttl, 3600)
            stale_ttl = max(stale_ttl, 21600)
        query_cache_key = (
            f"{base_cache_key}:sql-page:"
            f"{normalized_page}:{normalized_page_size}:{normalized_sort_key}:{normalized_sort_dir}:"
            f"{hashlib.sha1(search_text.encode('utf-8')).hexdigest()[:16]}"
        )

        def build_payload() -> dict[str, Any]:
            tz = ZoneInfo(str(tz_name or TIMEZONE))
            today_key = datetime.now(tz).strftime("%Y-%m-%d")
            start_day = start_dt.astimezone(tz).strftime("%Y-%m-%d")
            end_day = end_dt.astimezone(tz).strftime("%Y-%m-%d")
            allowed = None if allowed_advertiser_ids is None else sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
            if allowed_advertiser_ids is not None and not allowed:
                empty_payload = {
                    "snapshot_time": "",
                    "snapshot_count": 0,
                    "items": [],
                    "meta": {
                        "snapshot_time": "",
                        "status": "ok",
                        "plan_count": 0,
                        "detail_count": 0,
                        "product_count": 0,
                        "material_count": 0,
                        "relation_count": 0,
                        "video_count": 0,
                        "error_count": 0,
                        "snapshot_dates": [],
                        "snapshot_fallback_used": False,
                    },
                    "range_key": normalized,
                    "range_label": range_label,
                    "material_mode": MATERIAL_VIEW_RELATION,
                    "query_start_date": start_day,
                    "query_end_date": end_day,
                    "pagination": {
                        "page": 1,
                        "page_size": normalized_page_size,
                        "total_count": 0,
                        "total_pages": 1,
                        "start_index": 0,
                        "end_index": 0,
                        "sort_key": normalized_sort_key,
                        "sort_dir": normalized_sort_dir,
                        "search": str(search or "").strip(),
                    },
                    "materials_aggregate": self._material_aggregate_row([], material_mode=MATERIAL_VIEW_RELATION),
                    "metrics_semantics": {
                        "money_scope": "material_relation_grain",
                        "reconcilable_to_account_summary": True,
                        "reconcile_requires_relation_grain": True,
                        "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
                    },
                    "materialTodayStatus": self._material_today_hot_status(
                        all_customer_centers=all_customer_centers,
                    ),
                }
                empty_payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                empty_payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                return self._attach_freshness(
                    empty_payload,
                    data_time="",
                    synced_at="",
                    source="material_relation_current_daily",
                    partial=False,
                )

            source_queries: list[str] = []
            source_params: list[Any] = []
            daily_end_day = min(
                end_day,
                (datetime.strptime(today_key, "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d"),
            )
            if start_day <= daily_end_day:
                daily_where = ["mrd.biz_date >= ?", "mrd.biz_date <= ?"]
                source_params.extend([start_day, daily_end_day])
                daily_where.append(
                    self._material_history_stable_day_sql(
                        day_expr="mrd.biz_date",
                        customer_center_expr="mrd.customer_center_id",
                    )
                )
                if all_customer_centers:
                    daily_where.append("COALESCE(mrd.customer_center_id, '') <> ''")
                else:
                    daily_where.append("mrd.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    daily_where.append(f"mrd.advertiser_id IN ({','.join('?' for _ in allowed)})")
                    source_params.extend(allowed)
                source_queries.append(
                    f"""
                    SELECT
                        mrd.customer_center_id,
                        mrd.snapshot_time,
                        mrd.biz_date AS source_day,
                        mrd.advertiser_id,
                        mrd.advertiser_name,
                        mrd.ad_id,
                        mrd.ad_name,
                        mrd.material_type,
                        mrd.material_key,
                        mrd.material_id,
                        mrd.material_name,
                        mrd.backend_material_name,
                        mrd.publish_title,
                        mrd.create_time,
                        mrd.video_id,
                        mrd.cover_url,
                        mrd.aweme_item_id,
                        mrd.video_url,
                        mrd.stat_cost,
                        mrd.pay_amount,
                        mrd.total_pay_amount,
                        mrd.settled_pay_amount,
                        mrd.order_count,
                        mrd.settled_order_count,
                        mrd.overall_show_count,
                        mrd.overall_click_count,
                        mrd.top_anchor_name,
                        mrd.product_info_text,
                        mrd.is_original
                    FROM material_relation_daily mrd
                    WHERE {' AND '.join(daily_where)}
                    """
                )
            if end_day >= today_key:
                current_where: list[str] = []
                if all_customer_centers:
                    current_where.append("COALESCE(mrc.customer_center_id, '') <> ''")
                else:
                    current_where.append("mrc.customer_center_id = ?")
                    source_params.append(self._current_customer_center_id())
                if allowed:
                    current_where.append(f"mrc.advertiser_id IN ({','.join('?' for _ in allowed)})")
                    source_params.extend(allowed)
                source_queries.append(
                    f"""
                    SELECT
                        mrc.customer_center_id,
                        mrc.snapshot_time,
                        substr(mrc.snapshot_time, 1, 10) AS source_day,
                        mrc.advertiser_id,
                        mrc.advertiser_name,
                        mrc.ad_id,
                        mrc.ad_name,
                        mrc.material_type,
                        mrc.material_key,
                        mrc.material_id,
                        mrc.material_name,
                        mrc.backend_material_name,
                        mrc.publish_title,
                        mrc.create_time,
                        mrc.video_id,
                        mrc.cover_url,
                        mrc.aweme_item_id,
                        mrc.video_url,
                        mrc.stat_cost,
                        mrc.pay_amount,
                        mrc.total_pay_amount,
                        mrc.settled_pay_amount,
                        mrc.order_count,
                        mrc.settled_order_count,
                        mrc.overall_show_count,
                        mrc.overall_click_count,
                        mrc.top_anchor_name,
                        mrc.product_info_text,
                        mrc.is_original
                    FROM material_relation_current mrc
                    WHERE {' AND '.join(current_where) if current_where else '1 = 1'}
                    """
                )

            if not source_queries:
                payload = {
                    "snapshot_time": "",
                    "snapshot_count": 0,
                    "items": [],
                    "meta": {
                        "snapshot_time": "",
                        "status": "ok",
                        "plan_count": 0,
                        "detail_count": 0,
                        "product_count": 0,
                        "material_count": 0,
                        "relation_count": 0,
                        "video_count": 0,
                        "error_count": 0,
                        "snapshot_dates": [],
                        "snapshot_fallback_used": False,
                    },
                    "range_key": normalized,
                    "range_label": range_label,
                    "material_mode": MATERIAL_VIEW_RELATION,
                    "query_start_date": start_day,
                    "query_end_date": end_day,
                    "pagination": {
                        "page": 1,
                        "page_size": normalized_page_size,
                        "total_count": 0,
                        "total_pages": 1,
                        "start_index": 0,
                        "end_index": 0,
                        "sort_key": normalized_sort_key,
                        "sort_dir": normalized_sort_dir,
                        "search": str(search or "").strip(),
                    },
                    "materials_aggregate": self._material_aggregate_row([], material_mode=MATERIAL_VIEW_RELATION),
                    "metrics_semantics": {
                        "money_scope": "material_relation_grain",
                        "reconcilable_to_account_summary": True,
                        "reconcile_requires_relation_grain": True,
                        "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
                    },
                    "materialTodayStatus": self._material_today_hot_status(
                        all_customer_centers=all_customer_centers,
                    ),
                }
                payload.update(
                    self._history_backfill_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                payload.update(
                    self._history_correction_status_for_window(
                        start_dt,
                        end_dt,
                        tz_name=tz_name,
                        kind="material_relation",
                        all_customer_centers=all_customer_centers,
                    )
                )
                return self._attach_freshness(
                    payload,
                    data_time="",
                    synced_at="",
                    source="material_relation_current_daily",
                    partial=False,
                )

            escaped_search = search_text.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
            search_like = f"%{escaped_search}%"
            search_params = (
                [search_like] * 13
                if search_text
                else []
            )
            search_clause = ""
            if search_text:
                search_clause = """
                WHERE (
                    LOWER(COALESCE(material_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(backend_material_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(publish_title, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(material_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(video_id, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(product_info_text, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(top_anchor_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(advertiser_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(ad_name, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(first_seen_at, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(last_seen_at, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(material_key, '')) LIKE ? ESCAPE '\\'
                    OR LOWER(COALESCE(aweme_item_id, '')) LIKE ? ESCAPE '\\'
                )
                """
            relation_sql = f"""
            WITH source AS (
                {' UNION ALL '.join(source_queries)}
            ),
            metrics AS (
                SELECT
                    customer_center_id,
                    advertiser_id,
                    ad_id,
                    material_type,
                    material_key,
                    MAX(snapshot_time) AS snapshot_time,
                    CAST(ROUND(SUM(COALESCE(stat_cost, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                    CAST(ROUND(SUM(COALESCE(pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                    CAST(ROUND(SUM(COALESCE(total_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                    CAST(ROUND(SUM(COALESCE(settled_pay_amount, 0.0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                    CAST(SUM(COALESCE(order_count, 0)) AS INTEGER) AS order_count,
                    CAST(SUM(COALESCE(settled_order_count, 0)) AS INTEGER) AS settled_order_count,
                    CAST(SUM(COALESCE(overall_show_count, 0)) AS INTEGER) AS overall_show_count,
                    CAST(SUM(COALESCE(overall_click_count, 0)) AS INTEGER) AS overall_click_count,
                    COUNT(*) AS active_day_count
                FROM source
                GROUP BY customer_center_id, advertiser_id, ad_id, material_type, material_key
            ),
            filtered AS MATERIALIZED (
                SELECT
                    metrics.customer_center_id,
                    metrics.snapshot_time,
                    latest_row.advertiser_id,
                    COALESCE(NULLIF(latest_row.advertiser_name, ''), '') AS advertiser_name,
                    latest_row.ad_id,
                    COALESCE(NULLIF(latest_row.ad_name, ''), '') AS ad_name,
                    latest_row.material_type,
                    latest_row.material_key,
                    CONCAT_WS(':', metrics.customer_center_id, latest_row.advertiser_id::text, latest_row.ad_id::text, latest_row.material_type, latest_row.material_key) AS material_row_key,
                    COALESCE(NULLIF(latest_row.material_id, ''), NULLIF(mp.material_id, ''), '') AS material_id,
                    CASE
                        WHEN latest_row.material_type = 'UNATTRIBUTED_DELETED' THEN '未归因关闭/暂停计划消耗'
                        ELSE COALESCE(NULLIF(latest_row.backend_material_name, ''), NULLIF(mp.backend_material_name, ''), NULLIF(latest_row.material_name, ''), NULLIF(mp.material_name, ''), '未命名素材')
                    END AS material_name,
                    COALESCE(NULLIF(latest_row.backend_material_name, ''), NULLIF(mp.backend_material_name, ''), '') AS backend_material_name,
                    COALESCE(NULLIF(latest_row.publish_title, ''), NULLIF(mp.publish_title, ''), '') AS publish_title,
                    COALESCE(NULLIF(mp.create_time, ''), NULLIF(latest_row.create_time, ''), '') AS create_time,
                    COALESCE(NULLIF(mp.video_id, ''), NULLIF(latest_row.video_id, ''), '') AS video_id,
                    COALESCE(NULLIF(mp.cover_url, ''), NULLIF(latest_row.cover_url, ''), '') AS cover_url,
                    COALESCE(NULLIF(mp.aweme_item_id, ''), NULLIF(latest_row.aweme_item_id, ''), '') AS aweme_item_id,
                    COALESCE(NULLIF(mp.video_url, ''), NULLIF(latest_row.video_url, ''), '') AS video_url,
                    metrics.stat_cost,
                    metrics.pay_amount,
                    metrics.total_pay_amount,
                    metrics.settled_pay_amount,
                    metrics.order_count,
                    metrics.settled_order_count,
                    metrics.overall_show_count,
                    metrics.overall_click_count,
                    COALESCE(NULLIF(latest_row.product_info_text, ''), NULLIF(mp.product_info_text, ''), '') AS product_info_text,
                    COALESCE(NULLIF(latest_row.top_anchor_name, ''), NULLIF(mp.top_anchor_name, ''), '') AS top_anchor_name,
                    COALESCE(mre.first_seen_at, '') AS first_seen_at,
                    COALESCE(mre.last_seen_at, '') AS last_seen_at,
                    COALESCE(mre.last_snapshot_time, '') AS last_snapshot_time,
                    CAST(COALESCE(mre.seen_count, 0) AS INTEGER) AS seen_count,
                    CAST(COALESCE(mp.is_original, latest_row.is_original, 0) AS INTEGER) AS is_original,
                    CAST(metrics.active_day_count AS INTEGER) AS active_day_count,
                    CAST(
                        CASE
                            WHEN metrics.overall_show_count > 0
                            THEN ROUND(
                                (metrics.overall_click_count::numeric * 100.0::numeric)
                                / NULLIF(metrics.overall_show_count::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS overall_ctr,
                    CAST(
                        CASE
                            WHEN metrics.stat_cost > 0
                            THEN ROUND(
                                metrics.pay_amount::numeric / NULLIF(metrics.stat_cost::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS roi,
                    CAST(
                        CASE
                            WHEN metrics.stat_cost > 0
                            THEN ROUND(
                                metrics.settled_pay_amount::numeric / NULLIF(metrics.stat_cost::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS settled_roi,
                    CAST(
                        CASE
                            WHEN metrics.order_count > 0
                            THEN ROUND(
                                metrics.stat_cost::numeric / NULLIF(metrics.order_count::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS pay_order_cost,
                    CAST(
                        CASE
                            WHEN metrics.total_pay_amount > 0
                            THEN ROUND(
                                (metrics.settled_pay_amount::numeric * 100.0::numeric)
                                / NULLIF(metrics.total_pay_amount::numeric, 0),
                                2
                            )
                            ELSE 0.0
                        END AS DOUBLE PRECISION
                    ) AS settled_amount_rate
                FROM metrics
                INNER JOIN source AS latest_row
                  ON latest_row.customer_center_id = metrics.customer_center_id
                 AND latest_row.advertiser_id = metrics.advertiser_id
                 AND latest_row.ad_id = metrics.ad_id
                 AND latest_row.material_type = metrics.material_type
                 AND latest_row.material_key = metrics.material_key
                 AND latest_row.snapshot_time = metrics.snapshot_time
                LEFT JOIN material_profile mp
                  ON mp.customer_center_id = metrics.customer_center_id
                 AND mp.material_key = metrics.material_key
                LEFT JOIN material_relation_edges mre
                  ON mre.customer_center_id = metrics.customer_center_id
                 AND mre.material_key = metrics.material_key
                 AND mre.advertiser_id = metrics.advertiser_id
                 AND mre.ad_id = metrics.ad_id
                {search_clause}
            ),
            summary AS (
                SELECT
                    COUNT(*) AS total_count,
                    CAST(ROUND(COALESCE(SUM(stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_stat_cost,
                    CAST(ROUND(COALESCE(SUM(pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_pay_amount,
                    CAST(ROUND(COALESCE(SUM(total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_settled_pay_amount,
                    CAST(COALESCE(SUM(order_count), 0) AS INTEGER) AS aggregate_order_count,
                    CAST(COALESCE(SUM(settled_order_count), 0) AS INTEGER) AS aggregate_settled_order_count,
                    CAST(COALESCE(SUM(overall_show_count), 0) AS INTEGER) AS aggregate_overall_show_count,
                    CAST(COALESCE(SUM(overall_click_count), 0) AS INTEGER) AS aggregate_overall_click_count,
                    COUNT(DISTINCT advertiser_id) AS aggregate_advertiser_count,
                    COUNT(DISTINCT ad_id) AS aggregate_plan_count,
                    COUNT(DISTINCT customer_center_id) AS aggregate_customer_center_count
                FROM filtered
            ),
            source_meta AS (
                SELECT
                    COALESCE(MAX(snapshot_time), '') AS latest_snapshot_time,
                    COUNT(DISTINCT source_day) AS snapshot_count,
                    COUNT(DISTINCT customer_center_id) AS customer_center_count
                FROM source
            ),
            paged AS (
                SELECT *
                FROM (
                    SELECT
                        filtered.*,
                        ROW_NUMBER() OVER (ORDER BY {sort_sql}) AS __page_order
                    FROM filtered
                ) ranked
                WHERE ranked.__page_order > ?
                  AND ranked.__page_order <= ?
            )
            SELECT
                source_meta.latest_snapshot_time,
                source_meta.snapshot_count,
                source_meta.customer_center_count,
                summary.total_count,
                summary.aggregate_stat_cost,
                summary.aggregate_pay_amount,
                summary.aggregate_total_pay_amount,
                summary.aggregate_settled_pay_amount,
                summary.aggregate_order_count,
                summary.aggregate_settled_order_count,
                summary.aggregate_overall_show_count,
                summary.aggregate_overall_click_count,
                summary.aggregate_advertiser_count,
                summary.aggregate_plan_count,
                summary.aggregate_customer_center_count,
                paged.*
            FROM summary
            LEFT JOIN source_meta ON TRUE
            LEFT JOIN paged ON TRUE
            ORDER BY paged.__page_order NULLS LAST
            """

            def run_relation_page(conn: Any, page_value: int) -> list[dict[str, Any]]:
                start_index = max(page_value - 1, 0) * normalized_page_size
                params = [
                    *source_params,
                    *search_params,
                    start_index,
                    start_index + normalized_page_size,
                ]
                return [dict(row) for row in conn.execute(relation_sql, params).fetchall()]

            with self.db() as conn:
                query_rows = run_relation_page(conn, normalized_page)
                summary_row = dict(query_rows[0] or {}) if query_rows else {}
                total_count = int(summary_row.get("total_count", 0) or 0)
                total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
                current_page = min(max(1, normalized_page), total_pages)
                if current_page != normalized_page:
                    query_rows = run_relation_page(conn, current_page)
                    summary_row = dict(query_rows[0] or {}) if query_rows else summary_row
                page_relation_rows = [
                    dict(row)
                    for row in query_rows
                    if str(row.get("material_key") or "").strip()
                ]
                latest_snapshot_time = str(summary_row.get("latest_snapshot_time") or "").strip()
                payload = self._build_material_relation_payload_from_rows(
                    conn,
                    page_relation_rows,
                    latest_snapshot_time=latest_snapshot_time,
                    all_customer_centers=all_customer_centers,
                )
                if page_relation_rows:
                    payload["items"] = self._sanitize_material_preview_fields_for_payload(
                        self._apply_latest_material_previews(
                            conn,
                            payload.get("items") or [],
                        )
                    )

            total_stat_cost = round(float(summary_row.get("aggregate_stat_cost", 0.0) or 0.0), 2)
            total_pay_amount = round(float(summary_row.get("aggregate_pay_amount", 0.0) or 0.0), 2)
            total_total_pay_amount = round(float(summary_row.get("aggregate_total_pay_amount", 0.0) or 0.0), 2)
            total_settled_pay_amount = round(float(summary_row.get("aggregate_settled_pay_amount", 0.0) or 0.0), 2)
            total_order_count = int(summary_row.get("aggregate_order_count", 0) or 0)
            total_settled_order_count = int(summary_row.get("aggregate_settled_order_count", 0) or 0)
            total_show_count = int(summary_row.get("aggregate_overall_show_count", 0) or 0)
            total_click_count = int(summary_row.get("aggregate_overall_click_count", 0) or 0)
            total_count = int(summary_row.get("total_count", 0) or 0)
            total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
            current_page = min(max(1, normalized_page), total_pages)
            start_index = (current_page - 1) * normalized_page_size
            page_items = list(payload.get("items") or [])
            snapshot_count = int(summary_row.get("snapshot_count", 0) or 0)
            source_customer_center_count = int(summary_row.get("customer_center_count", 0) or 0)

            payload["snapshot_time"] = str(summary_row.get("latest_snapshot_time") or "").strip()
            payload["snapshot_count"] = snapshot_count
            payload["meta"] = {
                "snapshot_time": payload.get("snapshot_time"),
                "status": "ok",
                "plan_count": 0,
                "detail_count": 0,
                "product_count": 0,
                "material_count": total_count,
                "relation_count": total_count,
                "video_count": 0,
                "error_count": 0,
                "snapshot_dates": [],
                "snapshot_fallback_used": False,
            }
            if all_customer_centers:
                payload["customer_center_count"] = source_customer_center_count
            payload["range_key"] = normalized
            payload["range_label"] = range_label
            payload["material_mode"] = MATERIAL_VIEW_RELATION
            payload["query_start_date"] = start_day
            payload["query_end_date"] = end_day
            payload["pagination"] = {
                "page": current_page,
                "page_size": normalized_page_size,
                "total_count": total_count,
                "total_pages": total_pages,
                "start_index": start_index + 1 if total_count > 0 else 0,
                "end_index": start_index + len(page_items),
                "sort_key": normalized_sort_key,
                "sort_dir": normalized_sort_dir,
                "search": str(search or "").strip(),
            }
            payload["materials_aggregate"] = {
                "material_mode": MATERIAL_VIEW_RELATION,
                "material_count": total_count,
                "stat_cost": total_stat_cost,
                "pay_amount": total_pay_amount,
                "total_pay_amount": total_total_pay_amount,
                "settled_pay_amount": total_settled_pay_amount,
                "order_count": total_order_count,
                "settled_order_count": total_settled_order_count,
                "overall_show_count": total_show_count,
                "overall_click_count": total_click_count,
                "overall_ctr": round(total_click_count / total_show_count * 100.0, 2) if total_show_count > 0 else 0.0,
                "roi": round(total_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "settled_roi": round(total_settled_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                "plan_count": int(summary_row.get("aggregate_plan_count", 0) or 0),
                "advertiser_count": int(summary_row.get("aggregate_advertiser_count", 0) or 0),
                "summary_text": f"共 {total_count} 条关系行",
            }
            payload["metrics_semantics"] = {
                "money_scope": "material_relation_grain",
                "reconcilable_to_account_summary": True,
                "reconcile_requires_relation_grain": True,
                "notice": "当前按素材 x 账户 x 计划关系逐行展示，可用于核对账户或计划总额；如果再按素材去重汇总，结果会与账户总表不一致。",
            }
            payload["materialTodayStatus"] = self._material_today_hot_status(
                all_customer_centers=all_customer_centers,
            )
            payload.update(
                self._history_backfill_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material_relation",
                    all_customer_centers=all_customer_centers,
                )
            )
            payload.update(
                self._history_correction_status_for_window(
                    start_dt,
                    end_dt,
                    tz_name=tz_name,
                    kind="material_relation",
                    all_customer_centers=all_customer_centers,
                )
            )
            return self._attach_freshness(
                payload,
                data_time=payload.get("snapshot_time"),
                synced_at=payload.get("snapshot_time"),
                source="material_relation_current_daily",
                partial=False,
            )

        return self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_query_cache,
            cache_key=self._versioned_cache_key(cache_version, query_cache_key),
            raw_cache_key=query_cache_key,
            cache_version=cache_version,
            force_refresh=force_refresh,
            builder=build_payload,
            fresh_ttl_seconds=max(fresh_ttl, 300),
            stale_ttl_seconds=max(stale_ttl, 900),
        )

    def material_relations_page_for_user(
        self,
        user: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        role = str((user or {}).get("role") or "")
        if role == ROLE_OPERATOR:
            payload = self.material_relations_for_user(
                user,
                range_key,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
                display_scope,
                force_refresh,
            )
            return self.paginate_material_payload(
                payload,
                page=page,
                page_size=page_size,
                sort_key=sort_key,
                sort_dir=sort_dir,
                search=search,
                allowed_advertiser_ids=allowed_advertiser_ids,
                force_refresh=force_refresh,
            )
        return self._material_relation_page_payload(
            range_key=range_key,
            start_date=start_date,
            end_date=end_date,
            snapshot_time=snapshot_time,
            allowed_advertiser_ids=allowed_advertiser_ids,
            all_customer_centers=self._display_scope_uses_all_customer_centers(display_scope),
            page=page,
            page_size=page_size,
            sort_key=sort_key,
            sort_dir=sort_dir,
            search=search,
            force_refresh=force_refresh,
        )

    def team_material_rankings_page_for_user(
        self,
        user: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        role = str((user or {}).get("role") or "")
        return self._material_performance_page_payload(
            range_key=range_key,
            start_date=start_date,
            end_date=end_date,
            allowed_advertiser_ids=allowed_advertiser_ids,
            all_customer_centers=(role == ROLE_OPERATOR or self._display_scope_uses_all_customer_centers(display_scope)),
            page=page,
            page_size=page_size,
            sort_key=sort_key,
            sort_dir=sort_dir,
            search=search,
            force_refresh=force_refresh,
            cache_key_suffix="team-materials:zero-tail",
            rank_zero_metrics_last=True,
        )

    def team_material_rankings_for_user(
        self,
        user: dict[str, Any] | None,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        display_scope: str = DISPLAY_SCOPE_CURRENT,
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        role = str((user or {}).get("role") or "")
        if role == ROLE_OPERATOR or self._display_scope_uses_all_customer_centers(display_scope):
            return self._cross_customer_center_material_payload(
                range_key,
                start_date,
                end_date,
                snapshot_time,
                allowed_advertiser_ids,
                MATERIAL_VIEW_PERFORMANCE,
                force_refresh=force_refresh,
            )
        return self.material_rankings(
            range_key,
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            MATERIAL_VIEW_PERFORMANCE,
            force_refresh=force_refresh,
        )

    def _apply_material_snapshot_context_for_pairs(
        self,
        conn: Any,
        items: list[dict[str, Any]],
        selected_pairs: set[tuple[str, str]],
        allowed_advertiser_ids: set[int] | None = None,
    ) -> list[dict[str, Any]]:
        if not items or not selected_pairs:
            return items
        snapshot_times = sorted(
            {
                str(snapshot_time or "").strip()
                for _customer_center_id, snapshot_time in selected_pairs
                if str(snapshot_time or "").strip()
            }
        )
        material_keys = sorted(
            {
                str(item.get("material_key") or "").strip()
                for item in items
                if str(item.get("material_key") or "").strip()
            }
        )
        if not snapshot_times or not material_keys:
            return items
        clauses = [
            f"snapshot_time IN ({','.join('?' for _ in snapshot_times)})",
            f"material_key IN ({','.join('?' for _ in material_keys)})",
        ]
        params: list[Any] = [*snapshot_times, *material_keys]
        if allowed_advertiser_ids is not None:
            allowed = sorted(int(item) for item in allowed_advertiser_ids if int(item or 0))
            if allowed:
                clauses.append(f"advertiser_id IN ({','.join('?' for _ in allowed)})")
                params.extend(allowed)
        rows = conn.execute(
            f"""
            SELECT snapshot_time, customer_center_id, material_key, product_show_count, product_click_count, raw_json
            FROM material_snapshots
            WHERE {" AND ".join(clauses)}
            """,
            params,
        ).fetchall()
        context_by_key: dict[str, dict[str, Any]] = {}
        for raw_row in rows:
            row = dict(raw_row)
            pair = (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            )
            if pair not in selected_pairs:
                continue
            material_key = str(row.get("material_key") or "").strip()
            if not material_key:
                continue
            group = context_by_key.setdefault(
                material_key,
                {
                    "product_show_count": 0,
                    "product_click_count": 0,
                    "product_names": [],
                },
            )
            group["product_show_count"] += int(row.get("product_show_count", 0) or 0)
            group["product_click_count"] += int(row.get("product_click_count", 0) or 0)
            for name in self._extract_material_product_names(row.get("raw_json")):
                if name not in group["product_names"]:
                    group["product_names"].append(name)
        for item in items:
            context = context_by_key.get(str(item.get("material_key") or "").strip())
            if not context:
                continue
            show_count = int(context.get("product_show_count", 0) or 0)
            click_count = int(context.get("product_click_count", 0) or 0)
            item["product_info_text"] = self._summarize_material_product_names(list(context.get("product_names") or []))
            item["overall_show_count"] = show_count
            item["overall_click_count"] = click_count
            item["overall_ctr"] = round(click_count / show_count * 100.0, 2) if show_count > 0 else 0.0
        return items

    def _apply_material_top_anchor_names_for_pairs(
        self,
        conn: Any,
        items: list[dict[str, Any]],
        selected_pairs: set[tuple[str, str]],
    ) -> list[dict[str, Any]]:
        if not items or not selected_pairs:
            return items
        unresolved_keys = {
            (
                str(item.get("top_account_name") or "").strip(),
                str(item.get("top_plan_name") or "").strip(),
            )
            for item in items
            if not str(item.get("top_anchor_name") or "").strip()
            and str(item.get("top_account_name") or "").strip()
            and str(item.get("top_plan_name") or "").strip()
        }
        if not unresolved_keys:
            return items
        snapshot_times = sorted(
            {
                str(snapshot_time or "").strip()
                for _customer_center_id, snapshot_time in selected_pairs
                if str(snapshot_time or "").strip()
            }
        )
        if not snapshot_times:
            return items
        placeholders = ",".join("?" for _ in snapshot_times)
        rows = conn.execute(
            f"""
            SELECT snapshot_time, customer_center_id, advertiser_name, ad_name, anchor_name, ad_id
            FROM plan_snapshots
            WHERE snapshot_time IN ({placeholders})
              AND COALESCE(anchor_name, '') <> ''
            ORDER BY snapshot_time DESC, ad_id DESC
            """,
            snapshot_times,
        ).fetchall()
        anchor_map: dict[tuple[str, str], str] = {}
        for raw_row in rows:
            row = dict(raw_row)
            pair = (
                str(row.get("customer_center_id") or "").strip(),
                str(row.get("snapshot_time") or "").strip(),
            )
            if pair not in selected_pairs:
                continue
            key = (
                str(row.get("advertiser_name") or "").strip(),
                str(row.get("ad_name") or "").strip(),
            )
            if key not in unresolved_keys or key in anchor_map:
                continue
            anchor_name = str(row.get("anchor_name") or "").strip()
            if anchor_name:
                anchor_map[key] = anchor_name
        remaining_keys = {key for key in unresolved_keys if key not in anchor_map}
        if remaining_keys:
            customer_center_ids = sorted(
                {
                    str(customer_center_id or "").strip()
                    for customer_center_id, _snapshot_time in selected_pairs
                    if str(customer_center_id or "").strip()
                }
            )
            if customer_center_ids:
                customer_placeholders = ",".join("?" for _ in customer_center_ids)
                current_rows = conn.execute(
                    f"""
                    SELECT customer_center_id, advertiser_name, ad_name, anchor_name, ad_id
                    FROM plan_current
                    WHERE customer_center_id IN ({customer_placeholders})
                      AND COALESCE(anchor_name, '') <> ''
                    ORDER BY snapshot_time DESC, ad_id DESC
                    """,
                    customer_center_ids,
                ).fetchall()
                for raw_row in current_rows:
                    row = dict(raw_row)
                    key = (
                        str(row.get("advertiser_name") or "").strip(),
                        str(row.get("ad_name") or "").strip(),
                    )
                    if key not in remaining_keys or key in anchor_map:
                        continue
                    anchor_name = str(row.get("anchor_name") or "").strip()
                    if anchor_name:
                        anchor_map[key] = anchor_name
        if not anchor_map:
            return items
        enriched_items: list[dict[str, Any]] = []
        for item in items:
            enriched = dict(item)
            if not str(enriched.get("top_anchor_name") or "").strip():
                enriched["top_anchor_name"] = anchor_map.get(
                    (
                        str(enriched.get("top_account_name") or "").strip(),
                        str(enriched.get("top_plan_name") or "").strip(),
                    ),
                    "",
                )
            enriched_items.append(enriched)
        return enriched_items

    def _cross_customer_center_material_payload(
        self,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        mode: str = MATERIAL_VIEW_PERFORMANCE,
        force_refresh: bool = False,
    ) -> dict[str, Any]:
        return self._material_rankings_read_model_payload(
            range_key,
            start_date,
            end_date,
            snapshot_time,
            allowed_advertiser_ids,
            mode,
            all_customer_centers=True,
            force_refresh=force_refresh,
        )

    @staticmethod
    def _sql_like_pattern(value: Any) -> str:
        text = str(value or "").strip().lower()
        escaped = text.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
        return f"%{escaped}%"

    @staticmethod
    def _material_profile_search_expr(alias: str = "p") -> str:
        prefix = str(alias or "").strip()
        if prefix and not prefix.endswith("."):
            prefix = f"{prefix}."
        return f"""
            LOWER(
                COALESCE({prefix}material_key, '') || ' ' ||
                COALESCE({prefix}material_id, '') || ' ' ||
                COALESCE({prefix}backend_material_name, '') || ' ' ||
                COALESCE({prefix}material_name, '') || ' ' ||
                COALESCE({prefix}publish_title, '') || ' ' ||
                COALESCE({prefix}video_id, '') || ' ' ||
                COALESCE({prefix}product_info_text, '') || ' ' ||
                COALESCE({prefix}top_anchor_name, '') || ' ' ||
                COALESCE({prefix}top_plan_name, '') || ' ' ||
                COALESCE({prefix}top_account_name, '') || ' ' ||
                COALESCE({prefix}aweme_item_id, '') || ' ' ||
                COALESCE({prefix}material_type, '') || ' ' ||
                COALESCE({prefix}product_names_json, '')
            )
        """

    def _material_index_window_context(
        self,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
    ) -> dict[str, Any]:
        normalized = str(range_key or "day").strip().lower()
        if normalized not in MATERIAL_RANGES and normalized not in PERFORMANCE_RANGES:
            raise ValueError("range must be one of day/yesterday/week/month/all/custom")
        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        if normalized == "custom":
            start_dt, end_dt, range_label = build_material_custom_window(start_date, end_date, tz_name)
        elif normalized == "all":
            start_dt, end_dt, range_label = build_all_material_window(tz_name)
        else:
            start_dt, end_dt, range_label = build_performance_window(normalized, tz_name)
        tz = ZoneInfo(str(tz_name or TIMEZONE))
        return {
            "range_key": normalized,
            "range_label": range_label,
            "start_dt": start_dt,
            "end_dt": end_dt,
            "start_day": start_dt.astimezone(tz).strftime("%Y-%m-%d"),
            "end_day": end_dt.astimezone(tz).strftime("%Y-%m-%d"),
            "tz_name": tz_name,
        }

    @staticmethod
    def _material_prefix_start_day(start_day: str) -> str:
        return (datetime.strptime(str(start_day or "")[:10], "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d")

    def _material_prefix_window_ready(
        self,
        conn: Any,
        *,
        scope_key_value: str,
        start_day: str,
        end_day: str,
    ) -> tuple[bool, str, int]:
        prefix_start_day = self._material_prefix_start_day(start_day)
        day_count = (
            datetime.strptime(end_day, "%Y-%m-%d").date()
            - datetime.strptime(start_day, "%Y-%m-%d").date()
        ).days + 1
        prefix_table = conn.execute("SELECT to_regclass('public.material_ranking_day_prefix') AS name").fetchone()
        if not (prefix_table or {}).get("name"):
            return False, prefix_start_day, day_count
        state = conn.execute(
            """
            SELECT
                EXISTS(
                    SELECT 1
                    FROM material_ranking_day_prefix
                    WHERE scope_key = ? AND day_key = ?
                    LIMIT 1
                ) AS has_end_day,
                EXISTS(
                    SELECT 1
                    FROM material_ranking_day_prefix
                    WHERE scope_key = ? AND day_key = ?
                    LIMIT 1
                ) AS has_start_day,
                (SELECT MIN(day_key) FROM material_ranking_day_prefix WHERE scope_key = ?) AS min_day
            """,
            [scope_key_value, end_day, scope_key_value, prefix_start_day, scope_key_value],
        ).fetchone()
        min_day = str((state or {}).get("min_day") or "").strip()
        ready = bool((state or {}).get("has_end_day")) and (
            bool((state or {}).get("has_start_day")) or (bool(min_day) and prefix_start_day < min_day)
        )
        return ready, prefix_start_day, day_count

    def _operator_keyword_metrics_plan(
        self,
        conn: Any,
        *,
        scope_key_value: str,
        start_day: str,
        end_day: str,
        all_customer_centers: bool,
    ) -> dict[str, Any] | None:
        tz_name = str(self.read_config().get("timezone") or TIMEZONE)
        today_key = datetime.now(ZoneInfo(tz_name)).strftime("%Y-%m-%d")
        window_includes_today = start_day <= today_key <= end_day
        current_scope_sql = "COALESCE(mc.customer_center_id, '') <> ''" if all_customer_centers else "mc.customer_center_id = ?"
        current_scope_params: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        current_metrics_sql = f"""
            current_metrics AS (
                SELECT
                    mc.material_key,
                    MAX(mc.snapshot_time) AS snapshot_time,
                    CAST(1 AS INTEGER) AS active_day_count,
                    CAST(ROUND(COALESCE(SUM(mc.stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                    CAST(ROUND(COALESCE(SUM(mc.pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                    CAST(ROUND(COALESCE(SUM(mc.total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                    CAST(ROUND(COALESCE(SUM(mc.settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                    CAST(COALESCE(SUM(mc.order_count), 0) AS INTEGER) AS order_count,
                    CAST(COALESCE(SUM(mc.settled_order_count), 0) AS INTEGER) AS settled_order_count,
                    CAST(COALESCE(SUM(mc.overall_show_count), 0) AS INTEGER) AS overall_show_count,
                    CAST(COALESCE(SUM(mc.overall_click_count), 0) AS INTEGER) AS overall_click_count,
                    CAST(ROUND(COALESCE(SUM(mc.refund_amount_1h), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS refund_amount_1h,
                    CAST(COALESCE(SUM(mc.plan_count), 0) AS INTEGER) AS plan_count,
                    CAST(COALESCE(SUM(mc.advertiser_count), 0) AS INTEGER) AS advertiser_count
                FROM material_current mc
                WHERE {current_scope_sql}
                GROUP BY mc.material_key
            )
        """
        if window_includes_today and start_day == today_key and end_day == today_key:
            return {
                "cte_sql": f"""
                    {current_metrics_sql},
                    metrics AS (
                        SELECT *
                        FROM current_metrics
                    )
                """,
                "params": [*current_scope_params],
                "ranking_index_range_key": "current_live",
                "ranking_source": "material_current_live",
                "day_prefix_used": False,
                "day_rollup_used": False,
                "live_overlay_used": True,
                "indexed_day_count": 1,
            }

        if window_includes_today and start_day < today_key:
            history_end_day = min(
                end_day,
                (datetime.strptime(today_key, "%Y-%m-%d").date() - timedelta(days=1)).strftime("%Y-%m-%d"),
            )
            ready, prefix_start_day, indexed_day_count = self._material_prefix_window_ready(
                conn,
                scope_key_value=scope_key_value,
                start_day=start_day,
                end_day=history_end_day,
            )
            if not ready:
                return None
            return {
                "cte_sql": f"""
                    end_rows AS (
                        SELECT *
                        FROM material_ranking_day_prefix
                        WHERE scope_key = ? AND day_key = ?
                    ),
                    start_rows AS (
                        SELECT *
                        FROM material_ranking_day_prefix
                        WHERE scope_key = ? AND day_key = ?
                    ),
                    history_metrics AS (
                        SELECT
                            e.material_key,
                            e.snapshot_time,
                            CAST(e.active_day_count - COALESCE(s.active_day_count, 0) AS INTEGER) AS active_day_count,
                            CAST(ROUND((e.stat_cost - COALESCE(s.stat_cost, 0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                            CAST(ROUND((e.pay_amount - COALESCE(s.pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                            CAST(ROUND((e.total_pay_amount - COALESCE(s.total_pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                            CAST(ROUND((e.settled_pay_amount - COALESCE(s.settled_pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                            CAST(e.order_count - COALESCE(s.order_count, 0) AS INTEGER) AS order_count,
                            CAST(e.settled_order_count - COALESCE(s.settled_order_count, 0) AS INTEGER) AS settled_order_count,
                            CAST(e.overall_show_count - COALESCE(s.overall_show_count, 0) AS INTEGER) AS overall_show_count,
                            CAST(e.overall_click_count - COALESCE(s.overall_click_count, 0) AS INTEGER) AS overall_click_count,
                            CAST(ROUND((e.refund_amount_1h - COALESCE(s.refund_amount_1h, 0))::numeric, 2) AS DOUBLE PRECISION) AS refund_amount_1h,
                            CAST(e.plan_count - COALESCE(s.plan_count, 0) AS INTEGER) AS plan_count,
                            CAST(e.advertiser_count - COALESCE(s.advertiser_count, 0) AS INTEGER) AS advertiser_count
                        FROM end_rows e
                        LEFT JOIN start_rows s
                          ON s.scope_key = e.scope_key
                         AND s.material_key = e.material_key
                    ),
                    {current_metrics_sql},
                    metrics AS (
                        SELECT
                            COALESCE(c.material_key, h.material_key) AS material_key,
                            COALESCE(NULLIF(c.snapshot_time, ''), NULLIF(h.snapshot_time, ''), '') AS snapshot_time,
                            CAST(COALESCE(h.active_day_count, 0) + CASE WHEN c.material_key IS NULL THEN 0 ELSE 1 END AS INTEGER) AS active_day_count,
                            CAST(ROUND((COALESCE(h.stat_cost, 0) + COALESCE(c.stat_cost, 0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                            CAST(ROUND((COALESCE(h.pay_amount, 0) + COALESCE(c.pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                            CAST(ROUND((COALESCE(h.total_pay_amount, 0) + COALESCE(c.total_pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                            CAST(ROUND((COALESCE(h.settled_pay_amount, 0) + COALESCE(c.settled_pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                            CAST(COALESCE(h.order_count, 0) + COALESCE(c.order_count, 0) AS INTEGER) AS order_count,
                            CAST(COALESCE(h.settled_order_count, 0) + COALESCE(c.settled_order_count, 0) AS INTEGER) AS settled_order_count,
                            CAST(COALESCE(h.overall_show_count, 0) + COALESCE(c.overall_show_count, 0) AS INTEGER) AS overall_show_count,
                            CAST(COALESCE(h.overall_click_count, 0) + COALESCE(c.overall_click_count, 0) AS INTEGER) AS overall_click_count,
                            CAST(ROUND((COALESCE(h.refund_amount_1h, 0) + COALESCE(c.refund_amount_1h, 0))::numeric, 2) AS DOUBLE PRECISION) AS refund_amount_1h,
                            CAST(COALESCE(h.plan_count, 0) + COALESCE(c.plan_count, 0) AS INTEGER) AS plan_count,
                            CAST(COALESCE(h.advertiser_count, 0) + COALESCE(c.advertiser_count, 0) AS INTEGER) AS advertiser_count
                        FROM history_metrics h
                        FULL OUTER JOIN current_metrics c
                          ON c.material_key = h.material_key
                    )
                """,
                "params": [scope_key_value, history_end_day, scope_key_value, prefix_start_day, *current_scope_params],
                "ranking_index_range_key": "day_prefix_live",
                "ranking_source": "material_ranking_day_prefix_live",
                "day_prefix_used": True,
                "day_rollup_used": True,
                "live_overlay_used": True,
                "indexed_day_count": indexed_day_count + 1,
            }

        ready, prefix_start_day, indexed_day_count = self._material_prefix_window_ready(
            conn,
            scope_key_value=scope_key_value,
            start_day=start_day,
            end_day=end_day,
        )
        if not ready:
            return None
        return {
            "cte_sql": """
                end_rows AS (
                    SELECT *
                    FROM material_ranking_day_prefix
                    WHERE scope_key = ? AND day_key = ?
                ),
                start_rows AS (
                    SELECT *
                    FROM material_ranking_day_prefix
                    WHERE scope_key = ? AND day_key = ?
                ),
                metrics AS (
                    SELECT
                        e.material_key,
                        e.snapshot_time,
                        CAST(e.active_day_count - COALESCE(s.active_day_count, 0) AS INTEGER) AS active_day_count,
                        CAST(ROUND((e.stat_cost - COALESCE(s.stat_cost, 0))::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                        CAST(ROUND((e.pay_amount - COALESCE(s.pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                        CAST(ROUND((e.total_pay_amount - COALESCE(s.total_pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                        CAST(ROUND((e.settled_pay_amount - COALESCE(s.settled_pay_amount, 0))::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                        CAST(e.order_count - COALESCE(s.order_count, 0) AS INTEGER) AS order_count,
                        CAST(e.settled_order_count - COALESCE(s.settled_order_count, 0) AS INTEGER) AS settled_order_count,
                        CAST(e.overall_show_count - COALESCE(s.overall_show_count, 0) AS INTEGER) AS overall_show_count,
                        CAST(e.overall_click_count - COALESCE(s.overall_click_count, 0) AS INTEGER) AS overall_click_count,
                        CAST(ROUND((e.refund_amount_1h - COALESCE(s.refund_amount_1h, 0))::numeric, 2) AS DOUBLE PRECISION) AS refund_amount_1h,
                        CAST(e.plan_count - COALESCE(s.plan_count, 0) AS INTEGER) AS plan_count,
                        CAST(e.advertiser_count - COALESCE(s.advertiser_count, 0) AS INTEGER) AS advertiser_count
                    FROM end_rows e
                    LEFT JOIN start_rows s
                      ON s.scope_key = e.scope_key
                     AND s.material_key = e.material_key
                )
            """,
            "params": [scope_key_value, end_day, scope_key_value, prefix_start_day],
            "ranking_index_range_key": "day_prefix",
            "ranking_source": "material_ranking_day_prefix",
            "day_prefix_used": True,
            "day_rollup_used": True,
            "live_overlay_used": False,
            "indexed_day_count": indexed_day_count,
        }

    def _operator_keyword_index_config(
        self,
        *,
        include_disabled: bool = False,
        only_user_id: int | None = None,
    ) -> tuple[dict[int, dict[str, Any]], list[tuple[int, str, str]], dict[int, set[str]]]:
        operators, keywords = self._operator_config(include_disabled=include_disabled, only_user_id=only_user_id)
        configured_keywords: dict[int, set[str]] = {}
        values: list[tuple[int, str, str]] = []
        seen: set[tuple[int, str]] = set()
        for row in keywords:
            operator_id = int(row.get("user_id", 0) or 0)
            if operator_id not in operators:
                continue
            keyword = str(row.get("keyword") or "").strip()
            if not keyword:
                continue
            dedupe_key = (operator_id, keyword.casefold())
            if dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            configured_keywords.setdefault(operator_id, set()).add(keyword)
            values.append((operator_id, keyword, self._sql_like_pattern(keyword)))
        operators = {
            operator_id: operator
            for operator_id, operator in operators.items()
            if configured_keywords.get(operator_id)
        }
        values = [item for item in values if item[0] in operators]
        configured_keywords = {
            operator_id: configured_keywords[operator_id]
            for operator_id in operators
            if configured_keywords.get(operator_id)
        }
        return operators, values, configured_keywords

    @staticmethod
    def _values_sql(rows: list[tuple[Any, ...]]) -> str:
        if not rows:
            return ""
        width = len(rows[0])
        return ", ".join("(" + ", ".join("?" for _ in range(width)) + ")" for _ in rows)

    @staticmethod
    def _flatten_values(rows: list[tuple[Any, ...]]) -> list[Any]:
        return [value for row in rows for value in row]

    def _material_operator_rankings_from_index(
        self,
        *,
        range_key: str = "",
        start_date: str = "",
        end_date: str = "",
        all_customer_centers: bool = True,
    ) -> list[dict[str, Any]] | None:
        operators, keyword_values, configured_keywords = self._operator_keyword_index_config()
        if not operators:
            return []
        context = self._material_index_window_context(range_key, start_date, end_date)
        scope_key_value = material_ranking_index.scope_key(self, all_customer_centers=all_customer_centers)
        operator_rows = [
            (
                int(operator_id),
                str(operator.get("username") or "").strip(),
                str(operator.get("display_name") or operator.get("username") or "").strip(),
                len(configured_keywords.get(operator_id) or []),
            )
            for operator_id, operator in sorted(operators.items())
        ]
        operator_values_sql = self._values_sql(operator_rows)
        keyword_values_sql = self._values_sql(keyword_values)
        if not operator_values_sql or not keyword_values_sql:
            return []
        profile_scope_sql = "COALESCE(p.customer_center_id, '') <> ''" if all_customer_centers else "p.customer_center_id = ?"
        profile_scope_params: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        profile_expr = self._material_profile_search_expr("p")
        with self.db() as conn:
            metrics_plan = self._operator_keyword_metrics_plan(
                conn,
                scope_key_value=scope_key_value,
                start_day=context["start_day"],
                end_day=context["end_day"],
                all_customer_centers=all_customer_centers,
            )
            if not metrics_plan:
                return None
            rows = [
                dict(row)
                for row in conn.execute(
                    f"""
                    WITH operator_rows(user_id, username, display_name, keyword_count) AS (
                        VALUES {operator_values_sql}
                    ),
                    operator_keywords(user_id, keyword, pattern) AS (
                        VALUES {keyword_values_sql}
                    ),
                    {metrics_plan["cte_sql"]},
                    matched_material_keywords AS (
                        SELECT DISTINCT ok.user_id, ok.keyword, p.material_key
                        FROM operator_keywords ok
                        JOIN material_profile p
                          ON {profile_scope_sql}
                         AND {profile_expr} LIKE ok.pattern ESCAPE '\\'
                        JOIN metrics m
                          ON m.material_key = p.material_key
                         AND m.active_day_count > 0
                    ),
                    matched_materials AS (
                        SELECT user_id, material_key, COUNT(DISTINCT keyword) AS matched_keyword_count
                        FROM matched_material_keywords
                        GROUP BY user_id, material_key
                    ),
                    profile_one AS (
                        SELECT DISTINCT ON (p.material_key)
                            p.material_key,
                            p.material_name,
                            p.top_account_name
                        FROM material_profile p
                        JOIN matched_materials mm ON mm.material_key = p.material_key
                        WHERE {profile_scope_sql}
                        ORDER BY p.material_key, p.updated_at DESC
                    ),
                    operator_materials AS (
                        SELECT
                            mm.user_id,
                            mm.matched_keyword_count,
                            m.*,
                            COALESCE(po.material_name, '') AS material_name,
                            COALESCE(po.top_account_name, '') AS top_account_name
                        FROM matched_materials mm
                        JOIN metrics m ON m.material_key = mm.material_key
                        LEFT JOIN profile_one po ON po.material_key = mm.material_key
                    ),
                    rollup AS (
                        SELECT
                            user_id,
                            CAST(ROUND(COALESCE(SUM(stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                            CAST(ROUND(COALESCE(SUM(pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                            CAST(ROUND(COALESCE(SUM(total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                            CAST(ROUND(COALESCE(SUM(settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                            CAST(COALESCE(SUM(order_count), 0) AS INTEGER) AS order_count,
                            CAST(COALESCE(SUM(settled_order_count), 0) AS INTEGER) AS settled_order_count,
                            CAST(COALESCE(SUM(plan_count), 0) AS INTEGER) AS plan_count,
                            CAST(COALESCE(SUM(advertiser_count), 0) AS INTEGER) AS advertiser_count,
                            CAST(COUNT(DISTINCT material_key) AS INTEGER) AS material_count,
                            CAST(COALESCE(SUM(matched_keyword_count), 0) AS INTEGER) AS matched_keyword_count
                        FROM operator_materials
                        GROUP BY user_id
                    ),
                    top_material AS (
                        SELECT *
                        FROM (
                            SELECT
                                user_id,
                                material_name,
                                top_account_name,
                                stat_cost,
                                ROW_NUMBER() OVER (
                                    PARTITION BY user_id
                                    ORDER BY stat_cost DESC, material_key ASC
                                ) AS rn
                            FROM operator_materials
                        ) ranked
                        WHERE rn = 1
                    )
                    SELECT
                        o.user_id AS operator_id,
                        o.display_name AS operator_name,
                        o.username AS operator_username,
                        CAST(ROUND(COALESCE(r.stat_cost, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS stat_cost,
                        CAST(ROUND(COALESCE(r.pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS pay_amount,
                        CAST(ROUND(COALESCE(r.total_pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS total_pay_amount,
                        CAST(ROUND(COALESCE(r.settled_pay_amount, 0.0)::numeric, 2) AS DOUBLE PRECISION) AS settled_pay_amount,
                        CAST(COALESCE(r.order_count, 0) AS INTEGER) AS order_count,
                        CAST(COALESCE(r.settled_order_count, 0) AS INTEGER) AS settled_order_count,
                        CAST(COALESCE(r.plan_count, 0) AS INTEGER) AS plan_count,
                        CAST(COALESCE(r.advertiser_count, 0) AS INTEGER) AS advertiser_count,
                        CAST(COALESCE(r.material_count, 0) AS INTEGER) AS material_count,
                        o.keyword_count,
                        CAST(COALESCE(r.matched_keyword_count, 0) AS INTEGER) AS matched_keyword_count,
                        COALESCE(t.material_name, '') AS top_material_name,
                        COALESCE(t.top_account_name, '') AS top_account_name
                    FROM operator_rows o
                    LEFT JOIN rollup r ON r.user_id = o.user_id
                    LEFT JOIN top_material t ON t.user_id = o.user_id
                    ORDER BY stat_cost DESC, pay_amount DESC, order_count DESC, operator_name ASC, operator_id ASC
                    """,
                    [
                        *self._flatten_values(operator_rows),
                        *self._flatten_values(keyword_values),
                        *list(metrics_plan.get("params") or []),
                        *profile_scope_params,
                        *profile_scope_params,
                    ],
                ).fetchall()
            ]
        for row in rows:
            stat_cost = round(float(row.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(row.get("pay_amount", 0.0) or 0.0), 2)
            total_pay_amount = round(float(row.get("total_pay_amount", 0.0) or 0.0), 2)
            settled_pay_amount = round(float(row.get("settled_pay_amount", 0.0) or 0.0), 2)
            order_count = int(row.get("order_count", 0) or 0)
            settled_order_count = int(row.get("settled_order_count", 0) or 0)
            refund_amount_1h = 0.0
            row["stat_cost"] = stat_cost
            row["pay_amount"] = pay_amount
            row["total_pay_amount"] = total_pay_amount
            row["settled_pay_amount"] = settled_pay_amount
            row["roi"] = round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0
            row["settled_roi"] = round(settled_pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0
            row["pay_order_cost"] = round(stat_cost / order_count, 2) if order_count > 0 else 0.0
            row["settled_amount_rate"] = round(settled_pay_amount / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else 0.0
            row["refund_amount_1h"] = refund_amount_1h
            row["refund_rate_1h"] = 0.0
            row["refund_rate_1h_available"] = False
            row["order_count"] = order_count
            row["settled_order_count"] = settled_order_count
            row["ranking_source"] = str(metrics_plan.get("ranking_source") or "material_ranking_day_prefix")
        return rows

    def _operator_material_index_page_payload(
        self,
        user_id: int,
        *,
        range_key: str = "day",
        start_date: str = "",
        end_date: str = "",
        page: int = 1,
        page_size: int = 0,
        sort_key: str = "",
        sort_dir: str = "desc",
        search: str = "",
        include_disabled_user: bool = False,
        force_refresh: bool = False,
    ) -> dict[str, Any] | None:
        operators, keyword_values, configured_keywords = self._operator_keyword_index_config(
            include_disabled=include_disabled_user,
            only_user_id=int(user_id or 0),
        )
        context = self._material_index_window_context(range_key, start_date, end_date)
        _sort_sql, normalized_sort_key, normalized_sort_dir = self._material_performance_sort_sql(sort_key, sort_dir)
        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, 20, max_size=500)
        if not operators or not keyword_values:
            return self._empty_material_performance_page_payload(
                range_key=context["range_key"],
                range_label=context["range_label"],
                start_dt=context["start_dt"],
                end_dt=context["end_dt"],
                page_size=normalized_page_size,
                sort_key=normalized_sort_key,
                sort_dir=normalized_sort_dir,
                search=search,
                tz_name=context["tz_name"],
                all_customer_centers=True,
                source="material_ranking_operator_keywords",
            )
        cache_scope = material_cache_scope_for_range(context["range_key"], snapshot_time="")
        cache_namespace = f"{build_material_cache_namespace(MATERIAL_VIEW_PERFORMANCE, scope=cache_scope)}:operator-page"
        material_cache_namespace = f"{build_material_cache_namespace(MATERIAL_VIEW_PERFORMANCE, scope=cache_scope)}:page"
        cache_version = f"{self._shared_cache_version(cache_namespace)}:{self._shared_cache_version(material_cache_namespace)}"
        keyword_signature = hashlib.sha1(
            self._json_text(
                sorted(
                    [
                        (int(operator_id), sorted(values))
                        for operator_id, values in configured_keywords.items()
                    ]
                )
            ).encode("utf-8")
        ).hexdigest()[:16]
        raw_cache_key = (
            f"operator-material-index-page:{user_id}:{context['range_key']}:{start_date}:{end_date}:"
            f"{normalized_page}:{normalized_page_size}:{normalized_sort_key}:{normalized_sort_dir}:"
            f"{hashlib.sha1(str(search or '').strip().lower().encode('utf-8')).hexdigest()[:16]}:{keyword_signature}"
        )

        def build_payload() -> dict[str, Any]:
            scope_key_value = material_ranking_index.scope_key(self, all_customer_centers=True)
            keyword_values_sql = self._values_sql(keyword_values)
            if not keyword_values_sql:
                return self._empty_material_performance_page_payload(
                    range_key=context["range_key"],
                    range_label=context["range_label"],
                    start_dt=context["start_dt"],
                    end_dt=context["end_dt"],
                    page_size=normalized_page_size,
                    sort_key=normalized_sort_key,
                    sort_dir=normalized_sort_dir,
                    search=search,
                    tz_name=context["tz_name"],
                    all_customer_centers=True,
                    source="material_ranking_operator_keywords",
                )
            metric_column = {
                "overall_ctr": "(CASE WHEN overall_show_count > 0 THEN overall_click_count::DOUBLE PRECISION / overall_show_count ELSE 0 END)",
                "stat_cost": "stat_cost",
                "total_pay_amount": "total_pay_amount",
                "settled_pay_amount": "settled_pay_amount",
                "pay_amount": "pay_amount",
                "roi": "(CASE WHEN stat_cost > 0 THEN pay_amount::DOUBLE PRECISION / stat_cost ELSE 0 END)",
                "settled_roi": "(CASE WHEN stat_cost > 0 THEN settled_pay_amount::DOUBLE PRECISION / stat_cost ELSE 0 END)",
                "pay_order_cost": "(CASE WHEN order_count > 0 THEN stat_cost::DOUBLE PRECISION / order_count ELSE 0 END)",
                "settled_amount_rate": "(CASE WHEN total_pay_amount > 0 THEN settled_pay_amount::DOUBLE PRECISION / total_pay_amount ELSE 0 END)",
                "refund_rate_1h": "(CASE WHEN total_pay_amount > 0 THEN refund_amount_1h::DOUBLE PRECISION / total_pay_amount ELSE 0 END)",
                "order_count": "order_count",
                "settled_order_count": "settled_order_count",
                "plan_count": "plan_count",
                "advertiser_count": "advertiser_count",
            }.get(normalized_sort_key, "stat_cost")
            metric_order = "DESC" if normalized_sort_dir == "desc" else "ASC"
            profile_expr = self._material_profile_search_expr("p")
            search_text = self._query_text(search)
            search_sql = ""
            search_params: list[Any] = []
            if search_text:
                search_sql = f"AND {profile_expr} LIKE ? ESCAPE '\\'"
                search_params.append(self._sql_like_pattern(search_text))
            with self.db() as conn:
                metrics_plan = self._operator_keyword_metrics_plan(
                    conn,
                    scope_key_value=scope_key_value,
                    start_day=context["start_day"],
                    end_day=context["end_day"],
                    all_customer_centers=True,
                )
                if not metrics_plan:
                    return None
                indexed_day_count = int(metrics_plan.get("indexed_day_count", 0) or 0)
                ranking_index_range_key = str(metrics_plan.get("ranking_index_range_key") or "day_prefix")
                page_start = (normalized_page - 1) * normalized_page_size
                rows = [
                    dict(row)
                    for row in conn.execute(
                        f"""
                        WITH operator_keywords(user_id, keyword, pattern) AS (
                            VALUES {keyword_values_sql}
                        ),
                        {metrics_plan["cte_sql"]},
                        matched_materials AS (
                            SELECT p.material_key, COUNT(DISTINCT ok.keyword) AS matched_keyword_count
                            FROM operator_keywords ok
                            JOIN material_profile p
                              ON COALESCE(p.customer_center_id, '') <> ''
                             AND {profile_expr} LIKE ok.pattern ESCAPE '\\'
                             {search_sql}
                            JOIN metrics m
                              ON m.material_key = p.material_key
                             AND m.active_day_count > 0
                            GROUP BY p.material_key
                        ),
                        filtered AS (
                            SELECT m.*, mm.matched_keyword_count
                            FROM metrics m
                            JOIN matched_materials mm ON mm.material_key = m.material_key
                            WHERE m.active_day_count > 0
                        ),
                        summary AS (
                            SELECT
                                COUNT(*) AS total_count,
                                CAST(ROUND(COALESCE(SUM(stat_cost), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_stat_cost,
                                CAST(ROUND(COALESCE(SUM(pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_pay_amount,
                                CAST(ROUND(COALESCE(SUM(total_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_total_pay_amount,
                                CAST(ROUND(COALESCE(SUM(settled_pay_amount), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_settled_pay_amount,
                                CAST(COALESCE(SUM(order_count), 0) AS INTEGER) AS aggregate_order_count,
                                CAST(COALESCE(SUM(settled_order_count), 0) AS INTEGER) AS aggregate_settled_order_count,
                                CAST(COALESCE(SUM(overall_show_count), 0) AS INTEGER) AS aggregate_overall_show_count,
                                CAST(COALESCE(SUM(overall_click_count), 0) AS INTEGER) AS aggregate_overall_click_count,
                                CAST(ROUND(COALESCE(SUM(refund_amount_1h), 0.0)::numeric, 2) AS DOUBLE PRECISION) AS aggregate_refund_amount_1h,
                                CAST(COALESCE(SUM(plan_count), 0) AS INTEGER) AS aggregate_plan_count,
                                CAST(COALESCE(SUM(advertiser_count), 0) AS INTEGER) AS aggregate_advertiser_count
                            FROM filtered
                        ),
                        ranked AS (
                            SELECT
                                filtered.*,
                                ROW_NUMBER() OVER (
                                    ORDER BY {metric_column} {metric_order}, material_key ASC
                                ) AS rank_no
                            FROM filtered
                        ),
                        paged AS (
                            SELECT *
                            FROM ranked
                            WHERE rank_no > ? AND rank_no <= ?
                        )
                        SELECT
                            COALESCE((SELECT MAX(snapshot_time) FROM filtered), '') AS latest_snapshot_time,
                            ? AS indexed_day_count,
                            summary.*,
                            paged.material_key,
                            paged.rank_no,
                            paged.snapshot_time AS page_snapshot_time,
                            paged.active_day_count AS page_active_day_count,
                            paged.stat_cost AS page_stat_cost,
                            paged.pay_amount AS page_pay_amount,
                            paged.total_pay_amount AS page_total_pay_amount,
                            paged.settled_pay_amount AS page_settled_pay_amount,
                            paged.order_count AS page_order_count,
                            paged.settled_order_count AS page_settled_order_count,
                            paged.overall_show_count AS page_overall_show_count,
                            paged.overall_click_count AS page_overall_click_count,
                            paged.refund_amount_1h AS page_refund_amount_1h,
                            paged.plan_count AS page_plan_count,
                            paged.advertiser_count AS page_advertiser_count,
                            paged.matched_keyword_count AS page_matched_keyword_count
                        FROM summary
                        LEFT JOIN paged ON TRUE
                        ORDER BY paged.rank_no NULLS LAST
                        """,
                        [
                            *self._flatten_values(keyword_values),
                            *list(metrics_plan.get("params") or []),
                            *search_params,
                            page_start,
                            page_start + normalized_page_size,
                            indexed_day_count,
                        ],
                    ).fetchall()
                ]
                summary = dict(rows[0] or {}) if rows else {}
                total_count = int(summary.get("total_count", 0) or 0)
                if total_count <= 0:
                    empty = self._empty_material_performance_page_payload(
                        range_key=context["range_key"],
                        range_label=context["range_label"],
                        start_dt=context["start_dt"],
                        end_dt=context["end_dt"],
                        page_size=normalized_page_size,
                        sort_key=normalized_sort_key,
                        sort_dir=normalized_sort_dir,
                        search=search,
                        tz_name=context["tz_name"],
                        all_customer_centers=True,
                        source="material_ranking_operator_keywords",
                    )
                    empty["ranking_index_used"] = True
                    empty["ranking_index_range_key"] = ranking_index_range_key
                    empty["operator_keyword_count"] = len(keyword_values)
                    return empty
                total_pages = max(1, (total_count + normalized_page_size - 1) // normalized_page_size)
                current_page = min(normalized_page, total_pages)
                if current_page != normalized_page:
                    return self._operator_material_index_page_payload(
                        user_id,
                        range_key=range_key,
                        start_date=start_date,
                        end_date=end_date,
                        page=current_page,
                        page_size=normalized_page_size,
                        sort_key=sort_key,
                        sort_dir=sort_dir,
                        search=search,
                        include_disabled_user=include_disabled_user,
                        force_refresh=force_refresh,
                    )
                page_material_keys = [
                    str(row.get("material_key") or "").strip()
                    for row in rows
                    if str(row.get("material_key") or "").strip()
                ]
                profile_by_key: dict[str, dict[str, Any]] = {}
                if page_material_keys:
                    placeholders = ",".join("?" for _ in page_material_keys)
                    profile_by_key = {
                        str(row.get("material_key") or "").strip(): dict(row)
                        for row in conn.execute(
                            f"""
                            SELECT DISTINCT ON (material_key) *
                            FROM material_profile
                            WHERE COALESCE(customer_center_id, '') <> ''
                              AND material_key IN ({placeholders})
                            ORDER BY material_key, updated_at DESC
                            """,
                            page_material_keys,
                        ).fetchall()
                        if str(row.get("material_key") or "").strip()
                    }
                latest_snapshot_time = str(summary.get("latest_snapshot_time") or "").strip()
                page_source_rows: list[dict[str, Any]] = []
                metric_by_key = {
                    str(row.get("material_key") or "").strip(): dict(row)
                    for row in rows
                    if str(row.get("material_key") or "").strip()
                }
                for material_key in page_material_keys:
                    metric = metric_by_key.get(material_key) or {}
                    profile = profile_by_key.get(material_key) or {}
                    stat_cost = round(float(metric.get("page_stat_cost", 0.0) or 0.0), 2)
                    pay_amount = round(float(metric.get("page_pay_amount", 0.0) or 0.0), 2)
                    total_pay_amount = round(float(metric.get("page_total_pay_amount", 0.0) or 0.0), 2)
                    settled_pay_amount = round(float(metric.get("page_settled_pay_amount", 0.0) or 0.0), 2)
                    order_count = int(metric.get("page_order_count", 0) or 0)
                    settled_order_count = int(metric.get("page_settled_order_count", 0) or 0)
                    overall_show_count = int(metric.get("page_overall_show_count", 0) or 0)
                    overall_click_count = int(metric.get("page_overall_click_count", 0) or 0)
                    refund_amount_1h = round(float(metric.get("page_refund_amount_1h", 0.0) or 0.0), 2)
                    page_source_rows.append(
                        {
                            "customer_center_id": str(profile.get("customer_center_id") or self._current_customer_center_id()),
                            "snapshot_time": str(metric.get("page_snapshot_time") or latest_snapshot_time),
                            "source_day": context["end_day"],
                            "window_start": f"{context['start_day']} 00:00:00",
                            "window_end": f"{context['end_day']} 23:59:59",
                            "material_key": material_key,
                            "material_id": str(profile.get("material_id") or ""),
                            "material_name": str(profile.get("material_name") or "") or "unnamed material",
                            "create_time": str(profile.get("create_time") or ""),
                            "material_type": str(profile.get("material_type") or "") or "OTHER",
                            "video_id": str(profile.get("video_id") or ""),
                            "cover_url": str(profile.get("cover_url") or ""),
                            "aweme_item_id": str(profile.get("aweme_item_id") or ""),
                            "video_url": str(profile.get("video_url") or ""),
                            "stat_cost": stat_cost,
                            "pay_amount": pay_amount,
                            "total_pay_amount": total_pay_amount,
                            "settled_pay_amount": settled_pay_amount,
                            "order_count": order_count,
                            "settled_order_count": settled_order_count,
                            "plan_count": int(metric.get("page_plan_count", 0) or 0),
                            "advertiser_count": int(metric.get("page_advertiser_count", 0) or 0),
                            "plan_ids_json": str(profile.get("plan_ids_json") or "[]"),
                            "advertiser_ids_json": str(profile.get("advertiser_ids_json") or "[]"),
                            "is_original": int(profile.get("is_original", 0) or 0),
                            "top_plan_name": str(profile.get("top_plan_name") or ""),
                            "top_account_name": str(profile.get("top_account_name") or ""),
                            "top_anchor_name": str(profile.get("top_anchor_name") or ""),
                            "product_info_text": str(profile.get("product_info_text") or ""),
                            "product_names_json": str(profile.get("product_names_json") or "[]"),
                            "overall_show_count": overall_show_count,
                            "overall_click_count": overall_click_count,
                            "overall_ctr": round(overall_click_count / overall_show_count * 100.0, 2) if overall_show_count > 0 else 0.0,
                            "roi": round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                            "settled_roi": round(settled_pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                            "pay_order_cost": round(stat_cost / order_count, 2) if order_count > 0 else 0.0,
                            "settled_amount_rate": round(settled_pay_amount / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else 0.0,
                            "refund_amount_1h": refund_amount_1h,
                            "refund_rate_1h": round(refund_amount_1h / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else None,
                            "matched_keyword_count": int(metric.get("page_matched_keyword_count", 0) or 0),
                        }
                    )
                payload = self._build_material_payload_from_rows(
                    conn,
                    page_source_rows,
                    latest_snapshot_time=latest_snapshot_time,
                    all_customer_centers=True,
                    meta_rows=page_source_rows,
                    enrich_snapshot_context=False,
                    query_context_ready=True,
                )
                key_order = {key: index for index, key in enumerate(page_material_keys)}
                items = self._sanitize_material_preview_fields_for_payload(
                    self._apply_latest_material_previews(conn, payload.get("items") or [])
                )
                items = [dict(item or {}) for item in items]
                for item in items:
                    metric = metric_by_key.get(str(item.get("material_key") or "").strip()) or {}
                    item["matched_keyword_count"] = int(metric.get("page_matched_keyword_count", 0) or 0)
                items.sort(key=lambda item: key_order.get(str(item.get("material_key") or "").strip(), len(key_order)))
                start_index = (current_page - 1) * normalized_page_size
                total_stat_cost = round(float(summary.get("aggregate_stat_cost", 0.0) or 0.0), 2)
                total_pay_amount = round(float(summary.get("aggregate_pay_amount", 0.0) or 0.0), 2)
                total_total_pay_amount = round(float(summary.get("aggregate_total_pay_amount", 0.0) or 0.0), 2)
                total_settled_pay_amount = round(float(summary.get("aggregate_settled_pay_amount", 0.0) or 0.0), 2)
                total_order_count = int(summary.get("aggregate_order_count", 0) or 0)
                total_settled_order_count = int(summary.get("aggregate_settled_order_count", 0) or 0)
                total_show_count = int(summary.get("aggregate_overall_show_count", 0) or 0)
                total_click_count = int(summary.get("aggregate_overall_click_count", 0) or 0)
                total_refund_amount_1h = round(float(summary.get("aggregate_refund_amount_1h", 0.0) or 0.0), 2)
                payload["items"] = items
                payload["snapshot_time"] = latest_snapshot_time
                payload["snapshot_count"] = int(summary.get("indexed_day_count", 0) or 0)
                payload["range_key"] = context["range_key"]
                payload["range_label"] = context["range_label"]
                payload["material_mode"] = MATERIAL_VIEW_PERFORMANCE
                payload["query_start_date"] = context["start_day"]
                payload["query_end_date"] = context["end_day"]
                payload["pagination"] = {
                    "page": current_page,
                    "page_size": normalized_page_size,
                    "total_count": total_count,
                    "total_pages": total_pages,
                    "start_index": start_index + 1 if total_count > 0 else 0,
                    "end_index": start_index + len(items),
                    "sort_key": normalized_sort_key,
                    "sort_dir": normalized_sort_dir,
                    "search": str(search or "").strip(),
                }
                payload["materials_aggregate"] = {
                    "material_mode": MATERIAL_VIEW_PERFORMANCE,
                    "material_count": total_count,
                    "stat_cost": total_stat_cost,
                    "pay_amount": total_pay_amount,
                    "total_pay_amount": total_total_pay_amount,
                    "settled_pay_amount": total_settled_pay_amount,
                    "order_count": total_order_count,
                    "settled_order_count": total_settled_order_count,
                    "overall_show_count": total_show_count,
                    "overall_click_count": total_click_count,
                    "overall_ctr": round(total_click_count / total_show_count * 100.0, 2) if total_show_count > 0 else 0.0,
                    "roi": round(total_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                    "settled_roi": round(total_settled_pay_amount / total_stat_cost, 2) if total_stat_cost > 0 else 0.0,
                    "pay_order_cost": round(total_stat_cost / total_order_count, 2) if total_order_count > 0 else 0.0,
                    "settled_amount_rate": round(total_settled_pay_amount / total_total_pay_amount * 100.0, 2) if total_total_pay_amount > 0 else 0.0,
                    "refund_amount_1h": total_refund_amount_1h,
                    "refund_rate_1h": round(total_refund_amount_1h / total_total_pay_amount * 100.0, 2) if total_total_pay_amount > 0 else 0.0,
                    "plan_count": int(summary.get("aggregate_plan_count", 0) or 0),
                    "advertiser_count": int(summary.get("aggregate_advertiser_count", 0) or 0),
                    "summary_text": f"total {total_count} materials",
                }
                payload["ranking_index_used"] = True
                payload["ranking_index_range_key"] = ranking_index_range_key
                payload["ranking_index_day_prefix_used"] = bool(metrics_plan.get("day_prefix_used"))
                payload["ranking_index_day_rollup_used"] = bool(metrics_plan.get("day_rollup_used"))
                payload["ranking_index_live_overlay_used"] = bool(metrics_plan.get("live_overlay_used"))
                payload["ranking_index_day_rollup_days"] = indexed_day_count
                payload["operator_keyword_count"] = len(keyword_values)
                payload["operator_keywords"] = sorted(next(iter(configured_keywords.values()), set()))
                return self._attach_freshness(
                    payload,
                    data_time=payload.get("snapshot_time"),
                    synced_at=payload.get("snapshot_time"),
                    source="material_ranking_operator_keywords",
                    partial=False,
                )

        fresh_ttl, stale_ttl = material_cache_ttls_for_scope(cache_scope)
        return self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_query_cache,
            cache_key=self._versioned_cache_key(cache_version, raw_cache_key),
            raw_cache_key=raw_cache_key,
            cache_version=cache_version,
            force_refresh=force_refresh,
            builder=build_payload,
            fresh_ttl_seconds=max(fresh_ttl, 300),
            stale_ttl_seconds=max(stale_ttl, 900),
        )

    def _material_operator_matching_rows(
        self,
        *,
        range_key: str = "",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = True,
    ) -> list[dict[str, Any]]:
        operators, keywords = self._active_operator_config()
        keyword_texts = sorted(
            {
                str(row.get("keyword") or "").strip()
                for row in keywords
                if int(row.get("user_id", 0) or 0) in operators and str(row.get("keyword") or "").strip()
            },
            key=lambda item: (-len(item), item.casefold()),
        )
        if not keyword_texts:
            return []

        config = self.read_config()
        tz_name = str(config.get("timezone") or TIMEZONE)
        target_snapshot = str(snapshot_time or "").strip()
        normalized_range = str(range_key or "day").strip().lower()
        if target_snapshot:
            snapshot_day = _parse_date_input(target_snapshot[:10], "snapshot_time")
            tz = ZoneInfo(tz_name)
            start_dt = datetime(snapshot_day.year, snapshot_day.month, snapshot_day.day, 0, 0, 0, tzinfo=tz)
            end_dt = datetime(snapshot_day.year, snapshot_day.month, snapshot_day.day, 23, 59, 59, tzinfo=tz)
        else:
            if normalized_range not in PERFORMANCE_RANGES:
                raise ValueError("range must be one of day/yesterday/week/month/custom")
            if normalized_range == "custom":
                start_dt, end_dt, _range_label = build_custom_performance_window(start_date, end_date, tz_name)
            else:
                start_dt, end_dt, _range_label = build_performance_window(normalized_range, tz_name)

        where_prefix = "COALESCE(customer_center_id, '') <> ''" if all_customer_centers else "customer_center_id = ?"
        params_prefix: list[Any] = [] if all_customer_centers else [self._current_customer_center_id()]
        keyword_sql = " OR ".join(["LOWER(COALESCE(material_name, '')) LIKE ? ESCAPE '\\'" for _ in keyword_texts])
        keyword_params = [self._sql_like_pattern(item) for item in keyword_texts]
        stable_daily_sql = self._material_history_stable_day_sql(
            day_expr="md.biz_date",
            customer_center_expr="md.customer_center_id",
        )

        with self.db() as conn:
            source_rows: list[dict[str, Any]] = []
            if target_snapshot:
                source_rows = [
                    dict(row)
                    for row in conn.execute(
                        f"""
                        SELECT *
                        FROM material_current
                        WHERE {where_prefix}
                          AND snapshot_time = ?
                          AND ({keyword_sql})
                        ORDER BY snapshot_time DESC, stat_cost DESC, material_key ASC
                        """,
                        [*params_prefix, target_snapshot, *keyword_params],
                    ).fetchall()
                ]
                if not source_rows:
                    source_rows = [
                        dict(row)
                        for row in conn.execute(
                            f"""
                            SELECT *
                            FROM material_daily md
                            WHERE {where_prefix}
                              AND {stable_daily_sql}
                              AND biz_date = ?
                              AND ({keyword_sql})
                            ORDER BY snapshot_time DESC, stat_cost DESC, material_key ASC
                            """,
                            [*params_prefix, target_snapshot[:10], *keyword_params],
                        ).fetchall()
                    ]
            else:
                today_key = datetime.now(ZoneInfo(tz_name)).strftime("%Y-%m-%d")
                start_day = start_dt.strftime("%Y-%m-%d")
                end_day = end_dt.strftime("%Y-%m-%d")
                if end_day < today_key:
                    source_rows.extend(
                        [
                            dict(row)
                            for row in conn.execute(
                                f"""
                                SELECT *
                                FROM material_daily md
                                WHERE {where_prefix}
                                  AND {stable_daily_sql}
                                  AND biz_date >= ?
                                  AND biz_date <= ?
                                  AND ({keyword_sql})
                                ORDER BY biz_date DESC, stat_cost DESC, material_key ASC
                                """,
                                [*params_prefix, start_day, end_day, *keyword_params],
                            ).fetchall()
                        ]
                    )
                else:
                    if start_day < today_key:
                        source_rows.extend(
                            [
                                dict(row)
                                for row in conn.execute(
                                    f"""
                                    SELECT *
                                    FROM material_daily md
                                    WHERE {where_prefix}
                                      AND {stable_daily_sql}
                                      AND biz_date >= ?
                                      AND biz_date < ?
                                      AND ({keyword_sql})
                                    ORDER BY biz_date DESC, stat_cost DESC, material_key ASC
                                    """,
                                    [*params_prefix, start_day, today_key, *keyword_params],
                                ).fetchall()
                            ]
                        )
                    source_rows.extend(
                        [
                            dict(row)
                            for row in conn.execute(
                                f"""
                                SELECT *
                                FROM material_current
                                WHERE {where_prefix}
                                  AND ({keyword_sql})
                                ORDER BY snapshot_time DESC, stat_cost DESC, material_key ASC
                                """,
                                [*params_prefix, *keyword_params],
                            ).fetchall()
                        ]
                    )

        return self._filter_material_current_or_daily_rows(
            source_rows,
            start_dt,
            end_dt,
            tz_name,
            allowed_advertiser_ids,
        )

    def _material_operator_rankings_from_read_model(
        self,
        *,
        range_key: str = "",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
        allowed_advertiser_ids: set[int] | None = None,
        all_customer_centers: bool = True,
    ) -> list[dict[str, Any]]:
        operators, keywords = self._active_operator_config()
        keyword_signature = hashlib.sha1(
            self._json_text(
                sorted(
                    [
                        (
                            int(row.get("user_id", 0) or 0),
                            str(operators.get(int(row.get("user_id", 0) or 0), {}).get("username") or "").strip(),
                            str(operators.get(int(row.get("user_id", 0) or 0), {}).get("display_name") or "").strip(),
                            str(row.get("keyword") or "").strip(),
                        )
                        for row in keywords
                        if int(row.get("user_id", 0) or 0) in operators and str(row.get("keyword") or "").strip()
                    ]
                )
            ).encode("utf-8")
        ).hexdigest()[:16]
        cache_customer_center_id = "__all_customer_centers__" if all_customer_centers else self._current_customer_center_id()
        raw_cache_key = (
            f"material-operator-rankings:{cache_customer_center_id}:"
            f"{str(range_key or '').strip()}:{str(start_date or '').strip()}:{str(end_date or '').strip()}:"
            f"{str(snapshot_time or '').strip()}:{build_scope_cache_key(allowed_advertiser_ids)}:{keyword_signature}"
        )
        cache_namespace = "material-operator-rankings"
        cache_version = self._shared_cache_version(cache_namespace)
        cache_key = self._versioned_cache_key(cache_version, raw_cache_key)
        cache_scope = material_cache_scope_for_range(range_key, snapshot_time=str(snapshot_time or "").strip())
        fresh_ttl = 180 if cache_scope == MATERIAL_CACHE_SCOPE_LIVE else 1800
        stale_ttl = 900 if cache_scope == MATERIAL_CACHE_SCOPE_LIVE else 7200

        def build_payload() -> dict[str, Any]:
            if not snapshot_time and allowed_advertiser_ids is None:
                indexed_rows = self._material_operator_rankings_from_index(
                    range_key=range_key,
                    start_date=start_date,
                    end_date=end_date,
                    all_customer_centers=all_customer_centers,
                )
                if indexed_rows is not None:
                    return {"items": indexed_rows}
            rows = self._material_operator_matching_rows(
                range_key=range_key,
                start_date=start_date,
                end_date=end_date,
                snapshot_time=snapshot_time,
                allowed_advertiser_ids=allowed_advertiser_ids,
                all_customer_centers=all_customer_centers,
            )
            if not rows:
                return {"items": []}
            return {"items": self._build_operator_rankings_from_materials(self._aggregate_material_rollups(rows))}

        payload = self._read_payload_cache_swr(
            namespace=cache_namespace,
            cache_store=self._material_query_cache,
            cache_key=cache_key,
            raw_cache_key=raw_cache_key,
            cache_version=cache_version,
            force_refresh=False,
            builder=build_payload,
            fresh_ttl_seconds=fresh_ttl,
            stale_ttl_seconds=stale_ttl,
        )
        return [dict(item or {}) for item in list(payload.get("items") or [])]

    def _apply_material_operator_rankings(
        self,
        payload: dict[str, Any],
        *,
        allowed_advertiser_ids: set[int] | None = None,
        range_key: str = "",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
    ) -> dict[str, Any]:
        if not payload:
            return payload
        normalized_range = str(range_key or payload.get("range_key") or "").strip().lower()
        query_start_date = str(start_date or payload.get("query_start_date") or "").strip()
        query_end_date = str(end_date or payload.get("query_end_date") or "").strip()
        target_snapshot = str(snapshot_time or "").strip()
        if not normalized_range:
            target_snapshot = target_snapshot or str(payload.get("snapshot_time") or "").strip()
            if not target_snapshot:
                return payload
        operators = self._material_operator_rankings_from_read_model(
            range_key=normalized_range,
            start_date=query_start_date,
            end_date=query_end_date,
            snapshot_time=target_snapshot,
            allowed_advertiser_ids=allowed_advertiser_ids,
            all_customer_centers=True,
        )
        next_payload = dict(payload)
        next_payload["operators"] = operators
        summary = dict(next_payload.get("summary") or {})
        summary["operator_count"] = len(operators)
        summary["active_operator_count"] = sum(1 for item in operators if float(item.get("stat_cost", 0.0) or 0.0) > 0)
        next_payload["summary"] = summary
        return next_payload

    def _safe_apply_material_operator_rankings(
        self,
        payload: dict[str, Any],
        *,
        allowed_advertiser_ids: set[int] | None = None,
        range_key: str = "",
        start_date: str = "",
        end_date: str = "",
        snapshot_time: str = "",
    ) -> dict[str, Any]:
        try:
            return self._apply_material_operator_rankings(
                payload,
                allowed_advertiser_ids=allowed_advertiser_ids,
                range_key=range_key,
                start_date=start_date,
                end_date=end_date,
                snapshot_time=snapshot_time,
            )
        except Exception:  # noqa: BLE001
            degraded_payload = dict(payload or {})
            degraded_payload["material_operator_rankings_skipped"] = True
            return degraded_payload

    @staticmethod
    def _query_page_value(page: int, default: int = 1) -> int:
        try:
            normalized = int(page or default)
        except (TypeError, ValueError):
            normalized = default
        return max(1, normalized)

    @staticmethod
    def _query_page_size_value(page_size: int, default: int, max_size: int = 200) -> int:
        try:
            normalized = int(page_size or default)
        except (TypeError, ValueError):
            normalized = default
        return max(1, min(max_size, normalized))

    @staticmethod
    def _query_sort_dir(sort_dir: str, default: str = "desc") -> str:
        normalized = str(sort_dir or default).strip().lower()
        return normalized if normalized in {"asc", "desc"} else default

    @staticmethod
    def _query_text(value: Any) -> str:
        return str(value or "").strip().lower()

    @staticmethod
    def _query_float(value: Any) -> float:
        try:
            return float(value or 0.0)
        except (TypeError, ValueError):
            return 0.0

    @staticmethod
    def _query_int(value: Any) -> int:
        try:
            return int(float(value or 0))
        except (TypeError, ValueError):
            return 0

    def _rows_already_sorted_for_query(
        self,
        rows: list[dict[str, Any]],
        *,
        sort_key: str,
        sort_dir: str,
        default_key: str,
        numeric_keys: set[str] | None = None,
        text_keys: set[str] | None = None,
        tie_breaker: str = "",
    ) -> tuple[bool, str, str]:
        numeric = set(numeric_keys or set())
        text = set(text_keys or set())
        allowed = numeric | text
        normalized_key = str(sort_key or "").strip()
        if normalized_key not in allowed:
            normalized_key = default_key
        normalized_dir = self._query_sort_dir(sort_dir)
        if len(rows) < 2:
            return True, normalized_key, normalized_dir

        if normalized_key in numeric:
            def key_builder(item: dict[str, Any]) -> tuple[Any, ...]:
                return (
                    self._query_float(item.get(normalized_key)),
                    self._query_text(item.get(tie_breaker or "")),
                )
        else:
            def key_builder(item: dict[str, Any]) -> tuple[Any, ...]:
                return (
                    self._query_text(item.get(normalized_key)),
                    self._query_float(item.get(tie_breaker or "")),
                )

        previous_key = key_builder(dict(rows[0] or {}))
        for raw_row in rows[1:]:
            current_key = key_builder(dict(raw_row or {}))
            if normalized_dir == "desc":
                if previous_key < current_key:
                    return False, normalized_key, normalized_dir
            elif previous_key > current_key:
                return False, normalized_key, normalized_dir
            previous_key = current_key
        return True, normalized_key, normalized_dir

    def _sort_rows_for_query(
        self,
        rows: list[dict[str, Any]],
        *,
        sort_key: str,
        sort_dir: str,
        default_key: str,
        numeric_keys: set[str] | None = None,
        text_keys: set[str] | None = None,
        tie_breaker: str = "",
    ) -> tuple[list[dict[str, Any]], str, str]:
        numeric = set(numeric_keys or set())
        text = set(text_keys or set())
        allowed = numeric | text
        normalized_key = str(sort_key or "").strip()
        if normalized_key not in allowed:
            normalized_key = default_key
        normalized_dir = self._query_sort_dir(sort_dir)
        reverse = normalized_dir == "desc"
        if normalized_key in numeric:
            sorted_rows = sorted(
                rows,
                key=lambda item: (
                    self._query_float(item.get(normalized_key)),
                    self._query_text(item.get(tie_breaker or "")),
                ),
                reverse=reverse,
            )
        else:
            sorted_rows = sorted(
                rows,
                key=lambda item: (
                    self._query_text(item.get(normalized_key)),
                    self._query_float(item.get(tie_breaker or "")),
                ),
                reverse=reverse,
            )
        return sorted_rows, normalized_key, normalized_dir

    def _paginate_query_rows(
        self,
        rows: list[dict[str, Any]],
        *,
        page: int,
        page_size: int,
    ) -> tuple[list[dict[str, Any]], dict[str, Any]]:
        total_count = len(rows)
        total_pages = max(1, (total_count + page_size - 1) // page_size)
        current_page = min(max(1, page), total_pages)
        start_index = (current_page - 1) * page_size
        page_rows = rows[start_index:start_index + page_size]
        return page_rows, {
            "page": current_page,
            "page_size": page_size,
            "total_count": total_count,
            "total_pages": total_pages,
            "start_index": start_index + 1 if total_count > 0 else 0,
            "end_index": start_index + len(page_rows),
        }

    def _paginate_query_rows_if_requested(
        self,
        rows: list[dict[str, Any]],
        *,
        page: int,
        page_size: int,
        default_page_size: int,
    ) -> tuple[list[dict[str, Any]], dict[str, Any]]:
        requested_page_size = int(page_size or 0)
        if requested_page_size <= 0:
            total_count = len(rows)
            return list(rows), {
                "page": 1,
                "page_size": total_count,
                "total_count": total_count,
                "total_pages": 1,
                "start_index": 1 if total_count > 0 else 0,
                "end_index": total_count,
            }
        normalized_page = self._query_page_value(page)
        normalized_page_size = self._query_page_size_value(page_size, default_page_size)
        return self._paginate_query_rows(
            rows,
            page=normalized_page,
            page_size=normalized_page_size,
        )

    def _account_metric_profile_payload(
        self,
        *,
        has_global: bool,
        has_cubic_official: bool,
        has_settled_only: bool,
    ) -> dict[str, Any]:
        if (has_global or has_cubic_official) and has_settled_only:
            return self._metric_profile_payload(PLAN_SOURCE_UNI_PROMOTION, PLAN_DELIVERY_TYPE_GLOBAL, mixed=True)
        if has_settled_only:
            return self._metric_profile_payload(PLAN_SOURCE_UNI_REPORT, PLAN_DELIVERY_TYPE_CUBIC)
        if has_global and has_cubic_official:
            return {
                "metric_profile": "FULL",
                "metric_profile_text": "全域+乘方",
                "metric_source_text": "全域主链 + 乘方官方链",
                "metric_source_title": "账户行同时包含全域主链与乘方官方链计划，字段已按同口径汇总",
                "supports_pay_amount": True,
                "supports_total_pay_amount": True,
                "supports_pay_roi": True,
                "supports_order_count": True,
                "supports_pay_order_cost": True,
                "supports_settled_amount_rate": True,
                "supports_refund_rate_1h": True,
            }
        if has_cubic_official:
            return self._metric_profile_payload(PLAN_SOURCE_UNI_CUBIC, PLAN_DELIVERY_TYPE_CUBIC)
        return self._metric_profile_payload(PLAN_SOURCE_UNI_PROMOTION, PLAN_DELIVERY_TYPE_GLOBAL)

    def _account_query_context_from_plans(self, plans: list[dict[str, Any]]) -> dict[int, dict[str, Any]]:
        groups: dict[int, dict[str, Any]] = {}
        for raw in plans or []:
            row = dict(raw or {})
            advertiser_id = int(row.get("advertiser_id", 0) or 0)
            if advertiser_id <= 0:
                continue
            group = groups.setdefault(
                advertiser_id,
                {
                    "top_plan_name": "",
                    "_top_plan_orders": -1,
                    "_top_plan_pay_amount": -1.0,
                    "_has_global_metric_profile": False,
                    "_has_cubic_official_metric_profile": False,
                    "_has_settled_only_metric_profile": False,
                    "stat_cost": 0.0,
                    "pay_amount": 0.0,
                    "total_pay_amount": 0.0,
                    "settled_pay_amount": 0.0,
                    "order_count": 0,
                    "settled_order_count": 0,
                    "refund_amount_1h": 0.0,
                    "plan_count": 0,
                    "active_plan_count": 0,
                },
            )
            source = str(row.get("plan_source") or PLAN_SOURCE_UNI_PROMOTION).strip().upper()
            delivery_type = str(row.get("plan_delivery_type") or PLAN_DELIVERY_TYPE_GLOBAL).strip().upper()
            metric_profile = str(row.get("metric_profile") or "").strip().upper()
            if not metric_profile:
                metric_profile = str(self._metric_profile_payload(source, delivery_type).get("metric_profile") or "FULL").upper()
            if metric_profile == "SETTLED_ONLY":
                group["_has_settled_only_metric_profile"] = True
            elif metric_profile == "MIXED":
                group["_has_global_metric_profile"] = True
                group["_has_cubic_official_metric_profile"] = True
                group["_has_settled_only_metric_profile"] = True
            elif delivery_type == PLAN_DELIVERY_TYPE_CUBIC and source == PLAN_SOURCE_UNI_CUBIC:
                group["_has_cubic_official_metric_profile"] = True
            else:
                group["_has_global_metric_profile"] = True
            order_count = self._query_int(row.get("order_count"))
            pay_amount = self._query_float(row.get("pay_amount"))
            stat_cost = self._query_float(row.get("stat_cost"))
            total_pay_amount = self._query_float(row.get("total_pay_amount"))
            settled_pay_amount = self._query_float(row.get("settled_pay_amount"))
            settled_order_count = self._query_int(row.get("settled_order_count"))
            refund_amount_1h = self._query_float(row.get("refund_amount_1h"))
            group["stat_cost"] = round(float(group.get("stat_cost", 0.0) or 0.0) + stat_cost, 2)
            group["pay_amount"] = round(float(group.get("pay_amount", 0.0) or 0.0) + pay_amount, 2)
            group["total_pay_amount"] = round(float(group.get("total_pay_amount", 0.0) or 0.0) + total_pay_amount, 2)
            group["settled_pay_amount"] = round(float(group.get("settled_pay_amount", 0.0) or 0.0) + settled_pay_amount, 2)
            group["order_count"] = int(group.get("order_count", 0) or 0) + order_count
            group["settled_order_count"] = int(group.get("settled_order_count", 0) or 0) + settled_order_count
            group["refund_amount_1h"] = round(float(group.get("refund_amount_1h", 0.0) or 0.0) + refund_amount_1h, 2)
            group["plan_count"] = int(group.get("plan_count", 0) or 0) + 1
            if stat_cost > 0 or pay_amount > 0 or order_count > 0:
                group["active_plan_count"] = int(group.get("active_plan_count", 0) or 0) + 1
            if (
                order_count > int(group.get("_top_plan_orders", -1))
                or (
                    order_count == int(group.get("_top_plan_orders", -1))
                    and pay_amount > float(group.get("_top_plan_pay_amount", -1.0))
                )
            ):
                group["top_plan_name"] = str(row.get("ad_name") or "").strip()
                group["_top_plan_orders"] = order_count
                group["_top_plan_pay_amount"] = pay_amount
        result: dict[int, dict[str, Any]] = {}
        for advertiser_id, group in groups.items():
            stat_cost = round(float(group.get("stat_cost", 0.0) or 0.0), 2)
            pay_amount = round(float(group.get("pay_amount", 0.0) or 0.0), 2)
            total_pay_amount = round(float(group.get("total_pay_amount", 0.0) or 0.0), 2)
            settled_pay_amount = round(float(group.get("settled_pay_amount", 0.0) or 0.0), 2)
            order_count = int(group.get("order_count", 0) or 0)
            settled_order_count = int(group.get("settled_order_count", 0) or 0)
            refund_amount_1h = round(float(group.get("refund_amount_1h", 0.0) or 0.0), 2)
            result[advertiser_id] = {
                "top_plan_name": str(group.get("top_plan_name") or "").strip(),
                "stat_cost": stat_cost,
                "pay_amount": pay_amount,
                "total_pay_amount": total_pay_amount,
                "settled_pay_amount": settled_pay_amount,
                "order_count": order_count,
                "settled_order_count": settled_order_count,
                "refund_amount_1h": refund_amount_1h,
                "plan_count": int(group.get("plan_count", 0) or 0),
                "active_plan_count": int(group.get("active_plan_count", 0) or 0),
                "roi": round(pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                "settled_roi": round(settled_pay_amount / stat_cost, 2) if stat_cost > 0 else 0.0,
                "pay_order_cost": round(stat_cost / order_count, 2) if order_count > 0 else 0.0,
                "settled_amount_rate": round(settled_pay_amount / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else 0.0,
                "refund_rate_1h": round(refund_amount_1h / total_pay_amount * 100.0, 2) if total_pay_amount > 0 else 0.0,
                **self._account_metric_profile_payload(
                    has_global=bool(group.get("_has_global_metric_profile")),
                    has_cubic_official=bool(group.get("_has_cubic_official_metric_profile")),
                    has_settled_only=bool(group.get("_has_settled_only_metric_profile")),
                ),
            }
        return result

    def _enrich_account_rows_for_query(
        self,
        accounts: list[dict[str, Any]],
        plans: list[dict[str, Any]],
    ) -> list[dict[str, Any]]:
        context_by_id = self._account_query_context_from_plans(plans)
        rows: list[dict[str, Any]] = []
        for raw in accounts or []:
            row = dict(raw or {})
            advertiser_id = int(row.get("advertiser_id", 0) or 0)
            context = context_by_id.get(
                advertiser_id,
                self._account_metric_profile_payload(
                    has_global=True,
                    has_cubic_official=False,
                    has_settled_only=False,
                ),
            )
            row["top_plan_name"] = str(row.get("top_plan_name") or context.get("top_plan_name") or "").strip()
            for key, value in context.items():
                if key == "top_plan_name" and row["top_plan_name"]:
                    continue
                if key in {"stat_cost", "pay_amount", "order_count"} and row.get(key) not in {None, ""}:
                    continue
                row[key] = value
            error_text = str(row.get("error") or "").strip()
            row["status_text"] = "查询失败" if not bool(row.get("ok", True)) else ("计划聚合" if error_text.startswith("fallback:") else "正常")
            rows.append(row)
        return rows

    @staticmethod
    def _plan_account_options(accounts: list[dict[str, Any]], plans: list[dict[str, Any]]) -> list[dict[str, Any]]:
        options: dict[int, dict[str, Any]] = {}
        for raw in plans or []:
            row = dict(raw or {})
            advertiser_id = int(row.get("advertiser_id", 0) or 0)
            if advertiser_id <= 0:
                continue
            options.setdefault(
                advertiser_id,
                {
                    "advertiser_id": advertiser_id,
                    "advertiser_name": str(row.get("advertiser_name") or "").strip() or str(advertiser_id),
                },
            )
        if not options:
            for raw in accounts or []:
                row = dict(raw or {})
                advertiser_id = int(row.get("advertiser_id", 0) or 0)
                if advertiser_id <= 0:
                    continue
                options.setdefault(
                    advertiser_id,
                    {
                        "advertiser_id": advertiser_id,
                        "advertiser_name": str(row.get("advertiser_name") or "").strip() or str(advertiser_id),
                    },
                )
        return sorted(options.values(), key=lambda item: (str(item.get("advertiser_name") or ""), int(item.get("advertiser_id", 0) or 0)))

    @staticmethod
    def _compact_account_rows_for_payload(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        allowed_keys = {
            "advertiser_id",
            "advertiser_name",
            "ok",
            "error",
            "snapshot_time",
            "stat_cost",
            "pay_amount",
            "total_pay_amount",
            "settled_pay_amount",
            "roi",
            "settled_roi",
            "order_count",
            "settled_order_count",
            "pay_order_cost",
            "settled_amount_rate",
            "refund_amount_1h",
            "refund_rate_1h",
            "plan_count",
            "top_plan_name",
            "status_text",
        }
        compact_rows: list[dict[str, Any]] = []
        for raw in rows or []:
            row = dict(raw or {})
            compact_rows.append({key: row.get(key) for key in allowed_keys if key in row})
        return compact_rows

